import { GoogleGenAI } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Optimize this delivery route. Starting from ${startLocation}, sequence these deliveries logically to minimize travel time. Return the optimized order of IDs.
    Deliveries: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: "OBJECT",
        properties: {
          optimizedOrder: {
            type: "ARRAY",
            items: { type: "STRING" },
            description: "List of delivery IDs in optimized order"
          },
          reasoning: {
            type: "STRING",
            description: "Brief explanation of the optimization"
          }
        } as any,
        required: ["optimizedOrder"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse AI response", e);
    return { optimizedOrder: deliveries.map(d => d.id), reasoning: "Fallback to original order" };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }) => {
  // Usamos gemini-2.5-flash porque soporta googleMaps tool
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Find the precise location and delivery details for: "${input}". 
    You MUST provide the information in this exact format:
    RECIPIENT: [Name]
    ADDRESS: [Full Address]
    LAT: [Latitude]
    LNG: [Longitude]
    NOTES: [Notes]`,
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: userLocation ? {
        retrievalConfig: {
          latLng: {
            latitude: userLocation.latitude,
            longitude: userLocation.longitude
          }
        }
      } : undefined
    },
  });

  const text = response.text;
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  // Extraemos los datos del texto con regex ya que no podemos usar JSON schema con herramientas de grounding
  const recipientMatch = text.match(/RECIPIENT:\s*(.*)/i);
  const addressMatch = text.match(/ADDRESS:\s*(.*)/i);
  const latMatch = text.match(/LAT:\s*(-?\d+\.\d+)/i);
  const lngMatch = text.match(/LNG:\s*(-?\d+\.\d+)/i);
  const notesMatch = text.match(/NOTES:\s*(.*)/i);

  // Extraer el link de maps si existe en el grounding
  let sourceUrl = "";
  if (groundingChunks) {
    const mapChunk = groundingChunks.find((chunk: any) => chunk.maps?.uri);
    if (mapChunk) sourceUrl = mapChunk.maps.uri;
  }

  return {
    recipient: recipientMatch ? recipientMatch[1].trim() : "Destinatario Desconocido",
    address: addressMatch ? addressMatch[1].trim() : input,
    lat: latMatch ? parseFloat(latMatch[1]) : (userLocation?.latitude || 40.4168),
    lng: lngMatch ? parseFloat(lngMatch[1]) : (userLocation?.longitude || -3.7038),
    notes: notesMatch ? notesMatch[1].trim() : "",
    sourceUrl
  };
};

