                delivery={delivery}
                isSelected={selectedId === delivery.id}
                onClick={() => {
                  setSelectedId(delivery.id);
                  if (viewMode === 'list') setViewMode('split');
                }}
                onStatusChange={handleStatusChange}
              />
            ))}
          </div>
        </aside>

        <section className={`${viewMode === 'list' ? 'hidden' : 'flex-1'} relative`}>
          <MapView deliveries={deliveries} selectedId={selectedId} onMarkerClick={(id) => setSelectedId(id)} />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Localización Precisa</h3>
                <p className="text-sm text-slate-500">Google Maps validará tu dirección.</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6">
              <textarea 
                value={newAddressInput}
                onChange={(e) => setNewAddressInput(e.target.value)}
                className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none"
                placeholder="Ej: Entrega para Maria en Calle Serrano 40, Madrid..."
                required
              />
              <div className="mt-2 flex items-center gap-2 text-[11px] text-blue-600 font-medium">
                <MapIcon size={12} />
                <span>Usando Google Maps para coordenadas exactas</span>
              </div>

              <div className="flex gap-3 mt-8">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-3 px-4 rounded-xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className="flex-1 py-3 px-4 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50">
                  {isParsing ? <><Loader2 size={20} className="animate-spin" /> Buscando...</> : <><Search size={20} /> Validar Dirección</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

