import React, { useState, useEffect, useCallback } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, ChevronRight, X, Navigation, LayoutGrid } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([
    {
      id: '1',
      recipient: 'Juan Pérez',
      address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
      coordinates: [40.4241, -3.7126],
      status: DeliveryStatus.PENDING,
      estimatedTime: '09:30 AM'
    }
  ]);

  const [selectedId, setSelectedId] = useState<string | null>(null);
  // Por defecto 'split' en desktop, 'list' en mobile se maneja en el render
  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>('split');
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  // Detectar si es móvil para ajustar la vista inicial
  useEffect(() => {
    if (window.innerWidth < 768) {
      setViewMode('list');
    }

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
      // Al añadir, vamos al mapa para ver dónde está
      setViewMode(window.innerWidth < 768 ? 'map' : 'split');
    } catch (error) {
      console.error(error);
      alert("Hubo un error al localizar la dirección. Por favor, intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleOptimize = async () => {
    if (deliveries.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(deliveries, startLoc);
      const orderMap = new Map();
      result.optimizedOrder.forEach((id: string, index: number) => orderMap.set(id, index));

      const sorted = [...deliveries].sort((a, b) => {
        const indexA = orderMap.get(a.id) ?? 999;
        const indexB = orderMap.get(b.id) ?? 999;
        return indexA - indexB;
      });

      setDeliveries(sorted);
    } catch (error) {
      console.error(error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
  };

  const stats = {
    total: deliveries.length,
    completed: deliveries.filter(d => d.status === DeliveryStatus.COMPLETED).length,
    pending: deliveries.filter(d => d.status === DeliveryStatus.PENDING).length
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      {/* Header mejorado con Tabs visibles en móvil */}
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md shadow-blue-100">
            <Navigation size={20} className="md:w-6 md:h-6" />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-lg md:text-xl font-bold text-slate-900 tracking-tight leading-none">LogiRoute <span className="text-blue-600">AI</span></h1>
            <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wider mt-1">Smart Delivery</p>
          </div>
        </div>

        {/* Tabs de vista integrados en el header para acceso rápido */}
        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button 
            onClick={() => setViewMode('list')} 
            className={`p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            title="Ver Lista"
          >
            <List size={16} />
            <span className="hidden md:inline">Lista</span>
          </button>
          <button 
            onClick={() => setViewMode('map')} 
            className={`p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            title="Ver Mapa"
          >
            <MapIcon size={16} />
            <span className="hidden md:inline">Mapa</span>
          </button>
          <button 
            onClick={() => setViewMode('split')} 
            className={`hidden md:flex p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            title="Vista Dividida"
          >
            <LayoutGrid size={16} />
            <span className="hidden md:inline">Dividida</span>
          </button>
        </div>

        <button 
          onClick={() => setIsAdding(true)} 
          className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold transition-all shadow-lg shadow-blue-100 active:scale-95"
        >
          <Plus size={20} />
          <span className="hidden lg:inline text-sm">Nueva Entrega</span>
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        {/* Sidebar de entregas */}
        <aside 
          className={`
            absolute inset-0 z-20 md:relative md:inset-auto
            ${viewMode === 'map' ? 'hidden' : 'flex'} 
            ${viewMode === 'split' ? 'md:w-[380px] lg:w-[420px]' : 'w-full'}
            flex flex-col bg-white border-r border-slate-200 overflow-hidden transition-all duration-300
          `}
        >
          <div className="p-4 bg-slate-50/50 border-b border-slate-100">
            <div className="flex items-center justify-between mb-4">
              <h2 className="font-bold text-slate-800 flex items-center gap-2">
                <List size={18} className="text-blue-600" />
                Ruta de Hoy
              </h2>
              <button 
                onClick={handleOptimize} 
                disabled={isOptimizing || deliveries.length < 2} 
                className="text-[11px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100"
              >
                {isOptimizing ? <Loader2 size={14} className="animate-spin" /> : <BrainCircuit size={14} />}
                OPTIMIZAR AI
              </button>
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Total</p>
                <p className="text-lg font-black text-slate-800">{stats.total}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-green-400 font-bold uppercase tracking-widest">Éxito</p>
                <p className="text-lg font-black text-green-600">{stats.completed}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-blue-400 font-bold uppercase tracking-widest">Pend.</p>
                <p className="text-lg font-black text-blue-600">{stats.pending}</p>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-slate-50/30">
            {deliveries.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 text-slate-400">
                <div className="bg-white p-4 rounded-full shadow-sm mb-4 border border-slate-100">
                  <Navigation size={40} className="text-slate-200" />
                </div>
                <p className="font-bold text-slate-500">Sin entregas</p>
                <p className="text-xs mt-1">Tu lista de hoy está vacía.</p>
              </div>
            ) : (
              deliveries.map((delivery, index) => (
                <DeliveryCard 
                  key={delivery.id}
                  index={index}
                  delivery={delivery}
                  isSelected={selectedId === delivery.id}
                  onClick={() => {
                    setSelectedId(delivery.id);
                    // Si estamos en móvil y pulsamos una entrega, vamos al mapa
                    if (window.innerWidth < 768) {
                      setViewMode('map');
                    }
                  }}
                  onStatusChange={handleStatusChange}
                />
              ))
            )}
          </div>
        </aside>

        {/* Sección de Mapa */}
        <section 
          className={`
            flex-1 h-full relative z-10
            ${viewMode === 'list' ? 'hidden' : 'block'}
          `}
        >
          <MapView 
            deliveries={deliveries} 
            selectedId={selectedId} 
            onMarkerClick={(id) => {
              setSelectedId(id);
              // En pantallas muy grandes, al pulsar un marcador quizás queremos ver el detalle en la lista
            }} 
          />

          {/* Botón flotante para volver a la lista en móvil si estamos en mapa */}
          {viewMode === 'map' && (
            <button 
              onClick={() => setViewMode('list')}
              className="md:hidden absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-800 px-6 py-3 rounded-full shadow-2xl z-[400] font-bold flex items-center gap-2 border border-slate-200 active:scale-95"
            >
              <List size={18} className="text-blue-600" />
              Ver Lista de Entregas
            </button>
          )}
        </section>
      </main>

      {/* Modal de añadir dirección */}
      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4 transition-all duration-300">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Nueva Entrega</h3>
                <p className="text-sm text-slate-500">Google Maps validará la ubicación.</p>
              </div>
              <button 
                onClick={() => setIsAdding(false)} 
                className="p-2 hover:bg-white hover:shadow-sm rounded-full text-slate-400 transition-all"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6">
              <div className="relative">
                <textarea 
                  value={newAddressInput}
                  onChange={(e) => setNewAddressInput(e.target.value)}
                  className="w-full h-40 p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all resize-none text-slate-700 placeholder:text-slate-400 font-medium"
                  placeholder="Ej: Entrega para Maria en Calle Serrano 40, Madrid. Dejar en conserjería..."
                  required
                />
                <div className="absolute bottom-4 right-4 text-blue-600 opacity-20">
                  <BrainCircuit size={32} />
                </div>
              </div>

              <div className="mt-3 flex items-center gap-2 text-[11px] text-blue-600 font-bold uppercase tracking-wider bg-blue-50 px-3 py-2 rounded-lg inline-flex">
                <Search size={12} />
                <span>Validación con IA de Google Maps</span>
              </div>

              <div className="flex gap-3 mt-8">
                <button 
                  type="button" 
                  onClick={() => setIsAdding(false)} 
                  className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold hover:bg-slate-50 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  disabled={isParsing || !newAddressInput.trim()} 
                  className="flex-1 py-4 px-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-blue-200 active:scale-95"
                >
                  {isParsing ? (
                    <><Loader2 size={20} className="animate-spin" /> Buscando...</>
                  ) : (
                    <><MapIcon size={20} /> Localizar</>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

