            <span className="w-6 h-6 flex items-center justify-center bg-slate-900 text-white text-[10px] font-bold rounded-full">
              {index + 1}
            </span>
            <h3 className="font-semibold text-slate-800 truncate max-w-[140px]">{delivery.recipient}</h3>
          </div>
          <div className="flex items-center gap-2">
            <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${statusColors[delivery.status]}`}>
              {delivery.status.replace('_', ' ')}
            </span>
            <button 
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors"
              title="Eliminar entrega"
            >
              <Trash2 size={16} />
            </button>
          </div>
        </div>

        <div className="flex items-start gap-2 text-slate-500 text-sm mb-1">
          <MapPin size={16} className="mt-0.5 shrink-0" />
          <p className="line-clamp-2">{delivery.address}</p>
