                <div className="bg-white p-4 rounded-full shadow-sm mb-4 border border-slate-100">
                  <Navigation size={40} className="text-slate-200" />
                </div>
                <p className="font-bold text-slate-500">Sin entregas</p>
                <p className="text-xs mt-1">Pulsa "+" para añadir tu primera parada.</p>
              </div>
            ) : (
              deliveries.map((delivery, index) => (
                <DeliveryCard 
                  key={delivery.id}
                  index={index}
                  delivery={delivery}
                  isSelected={selectedId === delivery.id}
                  onClick={() => {
                    setSelectedId(delivery.id);
                    if (window.innerWidth < 768) setViewMode('map');
                  }}
                  onStatusChange={handleStatusChange}
                  onDelete={handleDeleteDelivery}
                  onDragStart={onDragStart}
                  onDragOver={onDragOver}
                  onDragEnd={(e) => onDragEnd(e)}
                />
              ))
            )}
          </div>
        </aside>

        <section className={`${viewMode === 'list' ? 'hidden' : 'block'} flex-1 h-full relative z-10`}>
          <MapView deliveries={deliveries} selectedId={selectedId} onMarkerClick={(id) => setSelectedId(id)} />
          {viewMode === 'map' && (
            <button 
              onClick={() => setViewMode('list')}
              className="md:hidden absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-800 px-6 py-3 rounded-full shadow-2xl z-[400] font-bold flex items-center gap-2 border border-slate-200"
            >
              <List size={18} className="text-blue-600" />
              Lista de Paradas
            </button>
          )}
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Nueva Entrega</h3>
                <p className="text-sm text-slate-500">Google Maps validará la ubicación.</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white hover:shadow-sm rounded-full text-slate-400"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6">
              <textarea 
                value={newAddressInput}
                onChange={(e) => setNewAddressInput(e.target.value)}
                className="w-full h-40 p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all resize-none text-slate-700"
                placeholder="Ej: Entrega para Maria en Calle Serrano 40, Madrid..."
                required
              />
              <div className="mt-3 flex items-center gap-2 text-[11px] text-blue-600 font-bold uppercase tracking-wider bg-blue-50 px-3 py-2 rounded-lg inline-flex">
                <Search size={12} />
                <span>Geolocalización por Inteligencia Artificial</span>
              </div>
              <div className="flex gap-3 mt-8">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className="flex-1 py-4 px-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-200">
                  {isParsing ? <><Loader2 size={20} className="animate-spin" /> Buscando...</> : <><MapIcon size={20} /> Localizar</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Delivery, DeliveryStatus } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const statusColors = {
    [DeliveryStatus.PENDING]: 'bg-slate-100 text-slate-600',
    [DeliveryStatus.IN_PROGRESS]: 'bg-blue-100 text-blue-600',
    [DeliveryStatus.COMPLETED]: 'bg-green-100 text-green-600',
    [DeliveryStatus.CANCELLED]: 'bg-red-100 text-red-600',
  };

  return (
    <div 
      draggable
      onDragStart={(e) => onDragStart(e, index)}
      onDragOver={(e) => onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative p-4 mb-3 rounded-xl border-2 transition-all cursor-pointer group hover:shadow-md ${
        isSelected ? 'border-blue-500 bg-blue-50' : 'border-transparent bg-white shadow-sm hover:border-slate-200'
      } active:scale-[0.98] transition-transform`}
    >
      {/* Drag Handle Overlay for Mobile & Visual Indicator */}
      <div className="absolute left-1 top-1/2 -translate-y-1/2 text-slate-300 group-hover:text-slate-400 p-1">
        <GripVertical size={16} />
      </div>

      <div className="pl-4">
        <div className="flex justify-between items-start mb-2">
          <div className="flex items-center gap-2">
            <span className="w-6 h-6 flex items-center justify-center bg-slate-900 text-white text-[10px] font-bold rounded-full">
              {index + 1}
            </span>
            <h3 className="font-semibold text-slate-800 truncate max-w-[140px]">{delivery.recipient}</h3>
          </div>
          <div className="flex items-center gap-2">
            <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${statusColors[delivery.status]}`}>
              {delivery.status.replace('_', ' ')}
            </span>
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()} // Evita que empiece el Drag al pulsar el botón
              onClick={(e) => { 
                e.stopPropagation(); 
                onDelete(delivery.id); 
              }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors"
              title="Eliminar entrega"
            >
              <Trash2 size={16} />
            </button>
          </div>
        </div>

        <div className="flex items-start gap-2 text-slate-500 text-sm mb-1">
          <MapPin size={16} className="mt-0.5 shrink-0" />
          <p className="line-clamp-2">{delivery.address}</p>
        </div>

        {delivery.sourceUrl && (
          <a 
            href={delivery.sourceUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            className="text-[10px] text-blue-500 hover:underline flex items-center gap-1 mb-3 ml-6"
          >
            <ExternalLink size={10} /> Ver en Maps
          </a>
        )}

        <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-100 ml-6">
          <div className="flex gap-1">
            {delivery.status !== DeliveryStatus.COMPLETED && (
              <button 
                type="button"
                onMouseDown={(e) => e.stopPropagation()}
                onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                className="p-1.5 rounded-lg bg-green-50 text-green-600 hover:bg-green-100 transition-colors"
                title="Marcar como entregado"
              >
                <CheckCircle size={18} />
              </button>
            )}
            {delivery.status === DeliveryStatus.PENDING && (
              <button 
                type="button"
                onMouseDown={(e) => e.stopPropagation()}
                onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                className="p-1.5 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 transition-colors"
                title="Iniciar ruta"
              >
                <Navigation size={18} />
              </button>
            )}
          </div>
          <div className="text-[11px] text-slate-400 flex items-center gap-1">
            <Clock size={12} />
            {delivery.estimatedTime || '---'}
          </div>
        </div>
      </div>
    </div>
  );
};

