import React, { useState } from 'react';
import { Delivery, DeliveryStatus } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const statusColors = {
    [DeliveryStatus.PENDING]: 'bg-slate-100 text-slate-600',
    [DeliveryStatus.IN_PROGRESS]: 'bg-blue-100 text-blue-600',
    [DeliveryStatus.COMPLETED]: 'bg-green-100 text-green-600',
    [DeliveryStatus.CANCELLED]: 'bg-red-100 text-red-600',
  };

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  return (
    <div 
      draggable
      onDragStart={(e) => onDragStart(e, index)}
      onDragOver={(e) => onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 transition-all cursor-pointer group hover:shadow-md ${
        isSelected ? 'border-blue-500 bg-blue-50' : 'border-transparent bg-white shadow-sm hover:border-slate-200'
      } active:scale-[0.99] transition-transform overflow-hidden`}
    >
      {/* Drag Handle Indicator */}
      <div className="absolute left-1 top-4 text-slate-300 group-hover:text-slate-400 p-1">
        <GripVertical size={16} />
      </div>

      <div className="pl-8 pr-4 py-3">
        {/* Main Row: Always Visible */}
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3 overflow-hidden">
            <span className="shrink-0 w-6 h-6 flex items-center justify-center bg-slate-900 text-white text-[10px] font-bold rounded-full">
              {index + 1}
            </span>
            <h3 className="font-bold text-slate-800 truncate text-sm md:text-base">{delivery.recipient}</h3>
          </div>

          <div className="flex items-center gap-1 shrink-0">
             <span className={`text-[8px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider hidden sm:inline-block ${statusColors[delivery.status]}`}>
              {delivery.status.replace('_', ' ')}
            </span>

            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { 
                e.stopPropagation(); 
                onDelete(delivery.id); 
              }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors"
              title="Eliminar"
            >
              <Trash2 size={16} />
            </button>

            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-slate-100 transition-colors"
            >
              {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </button>
          </div>
        </div>

        {/* Expandable Details Area */}
        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-slate-100 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-3">
              <div className="flex items-start gap-2 text-slate-600 text-xs">
                <MapPin size={14} className="mt-0.5 shrink-0 text-slate-400" />
                <p className="leading-relaxed">{delivery.address}</p>
              </div>

              {delivery.notes && (
                <div className="bg-slate-100/50 p-2 rounded-lg text-[11px] text-slate-500 italic">
                  Nota: {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-2">
                <div className="flex gap-2">
                  {delivery.status !== DeliveryStatus.COMPLETED && (
                    <button 
                      type="button"
                      onMouseDown={(e) => e.stopPropagation()}
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                      className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-green-50 text-green-600 hover:bg-green-100 text-[11px] font-bold transition-colors"
                    >
                      <CheckCircle size={14} /> Entregado
                    </button>
                  )}
                  {delivery.status === DeliveryStatus.PENDING && (
                    <button 
                      type="button"
                      onMouseDown={(e) => e.stopPropagation()}
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                      className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 text-[11px] font-bold transition-colors"
                    >
                      <Navigation size={14} /> En Ruta
                    </button>
                  )}
                </div>

                <div className="flex items-center gap-3">
                  {delivery.sourceUrl && (
                    <a 
                      href={delivery.sourceUrl} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      onClick={(e) => e.stopPropagation()}
                      className="text-[10px] text-blue-500 hover:underline flex items-center gap-1"
                    >
                      <ExternalLink size={12} /> Ver Mapa
                    </a>
                  )}
                  <div className="text-[10px] text-slate-400 flex items-center gap-1 font-medium">
                    <Clock size={12} />
                    {delivery.estimatedTime || 'N/A'}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  selectedId: string | null;
  onMarkerClick: (id: string) => void;
  viewMode: string; // Añadido para detectar cambios de visibilidad
}

const MapView: React.FC<MapViewProps> = ({ deliveries, selectedId, onMarkerClick, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});

  // Inicialización única del mapa
  useEffect(() => {
    if (!mapRef.current) {
      mapRef.current = L.map('map-container', {
        zoomControl: false, // Lo moveremos para que no estorbe
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }
  }, []);

  // Recalibrar tamaño cuando cambia la vista
  useEffect(() => {
    if (mapRef.current && viewMode !== 'list') {
      // Un pequeño timeout asegura que el contenedor ya tiene sus dimensiones finales en el DOM
      setTimeout(() => {
        mapRef.current?.invalidateSize({ animate: true });
      }, 100);
    }
  }, [viewMode]);

  // Gestión de marcadores y límites
  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Limpiar marcadores previos
    (Object.values(markersRef.current) as L.Marker[]).forEach(m => m.remove());
    markersRef.current = {};

    deliveries.forEach((delivery, idx) => {
      const color = delivery.status === DeliveryStatus.COMPLETED ? '#10b981' : 
                   delivery.status === DeliveryStatus.IN_PROGRESS ? '#3b82f6' : '#64748b';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div style="background-color: ${color}; width: 28px; height: 28px; border-radius: 50%; border: 3px solid white; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); display: flex; align-items: center; justify-content: center; color: white; font-weight: 800; font-size: 11px;">${idx + 1}</div>`,
        iconSize: [28, 28],
        iconAnchor: [14, 14]
      });

      const marker = L.marker(delivery.coordinates, { icon })
        .addTo(map)
        .on('click', () => onMarkerClick(delivery.id));

      markersRef.current[delivery.id] = marker;
    });

    if (deliveries.length > 0 && viewMode !== 'list') {
      const bounds = L.latLngBounds(deliveries.map(d => d.coordinates));
      map.fitBounds(bounds, { padding: [60, 60], maxZoom: 16 });
    }
  }, [deliveries, onMarkerClick, viewMode]);

  // Centrar en elemento seleccionado con animación suave
  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      const marker = markersRef.current[selectedId];
      mapRef.current.flyTo(marker.getLatLng(), 16, {
        duration: 0.8
      });
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
    ></div>
  );
};

export default MapView;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v1';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'list' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
      if (window.innerWidth < 768) setViewMode('map');
    } catch (error) {
      console.error(error);
      alert("Error localizando dirección. Intenta añadir calle y ciudad.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleLogout = () => {
    if (window.confirm("¿Deseas cerrar la sesión? Se borrarán todas las entregas de la ruta actual.")) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(VIEW_MODE_KEY);
      window.location.reload();
    }
  };

  const handleOptimize = async () => {
    if (deliveries.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(deliveries, startLoc);
      const orderMap = new Map();
      result.optimizedOrder.forEach((id: string, index: number) => orderMap.set(id, index));

      const sorted = [...deliveries].sort((a, b) => {
        const indexA = orderMap.get(a.id) ?? 999;
        const indexB = orderMap.get(b.id) ?? 999;
        return indexA - indexB;
      });

      setDeliveries(sorted);
    } catch (error) {
      console.error(error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
    const ghost = e.currentTarget as HTMLElement;
    ghost.style.opacity = "0.5";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    const ghost = e.currentTarget as HTMLElement;
    ghost.style.opacity = "1";

    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const newList = [...deliveries];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      dragItem.current = null;
      dragOverItem.current = null;
      setDeliveries(newList);
    }
  };

  const stats = {
    total: deliveries.length,
    completed: deliveries.filter(d => d.status === DeliveryStatus.COMPLETED).length,
    pending: deliveries.filter(d => d.status === DeliveryStatus.PENDING).length
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md shadow-blue-100">
            <Navigation size={20} className="md:w-6 md:h-6" />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-lg md:text-xl font-bold text-slate-900 tracking-tight leading-none">LogiRoute <span className="text-blue-600">AI</span></h1>
            <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wider mt-1">Smart Delivery</p>
          </div>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button 
            onClick={() => setViewMode('list')} 
            className={`p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            <List size={16} />
            <span className="hidden md:inline">Lista</span>
          </button>
          <button 
            onClick={() => setViewMode('map')} 
            className={`p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            <MapIcon size={16} />
            <span className="hidden md:inline">Mapa</span>
          </button>
          <button 
            onClick={() => setViewMode('split')} 
            className={`hidden md:flex p-2 md:px-4 md:py-1.5 rounded-lg text-xs md:text-sm font-bold transition-all items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            <LayoutGrid size={16} />
            <span className="hidden md:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={handleLogout}
            className="p-2 md:px-3 md:py-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
            title="Cerrar Sesión / Limpiar Datos"
          >
            <LogOut size={20} />
          </button>
          <button 
            onClick={() => setIsAdding(true)} 
            className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold transition-all shadow-lg shadow-blue-100 active:scale-95"
          >
            <Plus size={20} />
            <span className="hidden lg:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside 
          className={`
            absolute inset-0 z-20 md:relative md:inset-auto
            ${viewMode === 'map' ? 'hidden' : 'flex'} 
            ${viewMode === 'split' ? 'md:w-[380px] lg:w-[420px]' : 'w-full'}
            flex flex-col bg-white border-r border-slate-200 overflow-hidden transition-all duration-300
          `}
        >
          <div className="p-4 bg-slate-50/50 border-b border-slate-100">
            <div className="flex items-center justify-between mb-4">
              <h2 className="font-bold text-slate-800 flex items-center gap-2">
                <List size={18} className="text-blue-600" />
                Ruta Actual
              </h2>
              <button 
                onClick={handleOptimize} 
                disabled={isOptimizing || deliveries.length < 2} 
                className="text-[11px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100 shadow-sm"
              >
                {isOptimizing ? <Loader2 size={14} className="animate-spin" /> : <BrainCircuit size={14} />}
                OPTIMIZAR AI
              </button>
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest text-center">T</p>
                <p className="text-lg font-black text-slate-800">{stats.total}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-green-400 font-bold uppercase tracking-widest text-center">C</p>
                <p className="text-lg font-black text-green-600">{stats.completed}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-blue-400 font-bold uppercase tracking-widest text-center">P</p>
                <p className="text-lg font-black text-blue-600">{stats.pending}</p>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-1 bg-slate-50/30">
            {deliveries.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 text-slate-400">
                <Navigation size={40} className="text-slate-200 mb-4" />
                <p className="font-bold text-slate-500">Sin entregas</p>
                <p className="text-xs mt-1">Pulsa "+" para añadir paradas.</p>
              </div>
            ) : (
              deliveries.map((delivery, index) => (
                <DeliveryCard 
                  key={delivery.id}
                  index={index}
                  delivery={delivery}
                  isSelected={selectedId === delivery.id}
                  onClick={() => {
                    setSelectedId(delivery.id);
                    if (window.innerWidth < 768) setViewMode('map');
                  }}
                  onStatusChange={handleStatusChange}
                  onDelete={handleDeleteDelivery}
                  onDragStart={onDragStart}
                  onDragOver={onDragOver}
                  onDragEnd={(e) => onDragEnd(e)}
                />
              ))
            )}
          </div>
        </aside>

        <section className={`${viewMode === 'list' ? 'hidden' : 'block'} flex-1 h-full relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            selectedId={selectedId} 
            onMarkerClick={(id) => setSelectedId(id)} 
            viewMode={viewMode}
          />
          {viewMode === 'map' && (
            <button 
              onClick={() => setViewMode('list')}
              className="md:hidden absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-800 px-6 py-3 rounded-full shadow-2xl z-[400] font-bold flex items-center gap-2 border border-slate-200"
            >
              <List size={18} className="text-blue-600" />
              Lista de Paradas
            </button>
          )}
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Nueva Entrega</h3>
                <p className="text-sm text-slate-500">Añade una dirección para localizarla.</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white hover:shadow-sm rounded-full text-slate-400 transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6">
              <textarea 
                value={newAddressInput}
                onChange={(e) => setNewAddressInput(e.target.value)}
                className="w-full h-40 p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all resize-none text-slate-700"
                placeholder="Ej: Entrega para Maria en Calle Serrano 40, Madrid..."
                required
              />
              <div className="mt-3 flex items-center gap-2 text-[11px] text-blue-600 font-bold uppercase tracking-wider bg-blue-50 px-3 py-2 rounded-lg inline-flex">
                <Search size={12} />
                <span>Geolocalización por Inteligencia Artificial</span>
              </div>
              <div className="flex gap-3 mt-8">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className="flex-1 py-4 px-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-200">
                  {isParsing ? <><Loader2 size={20} className="animate-spin" /> Buscando...</> : <><MapIcon size={20} /> Localizar</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Optimize this delivery route. Starting from ${startLocation}, sequence these deliveries logically to minimize travel time. Return the optimized order of IDs.
