import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  selectedId: string | null;
  onMarkerClick: (id: string) => void;
  viewMode: string;
}

const MapView: React.FC<MapViewProps> = ({ deliveries, selectedId, onMarkerClick, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});

  // Inicialización única del mapa
  useEffect(() => {
    if (!mapRef.current) {
      const mapContainer = document.getElementById('map-container');
      if (!mapContainer) return;

      mapRef.current = L.map('map-container', {
        zoomControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }

    return () => {
      // Cleanup is handled by ref, but we could destroy here if needed
    };
  }, []);

  // Recalibrar tamaño cuando cambia la vista
  useEffect(() => {
    if (mapRef.current) {
      const timer = setTimeout(() => {
        try {
          mapRef.current?.invalidateSize({ animate: true });
        } catch (e) {
          console.warn("Invalidate size failed", e);
        }
      }, 250); // Increased timeout to ensure container is visible
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  // Gestión de marcadores y límites
  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Limpiar marcadores previos de forma segura
    Object.values(markersRef.current).forEach(m => {
      try {
        m.remove();
      } catch (e) {
        console.warn("Error removing marker", e);
      }
    });
    markersRef.current = {};

    const validDeliveries = deliveries.filter(d => 
      Array.isArray(d.coordinates) && 
      d.coordinates.length === 2 && 
      !isNaN(d.coordinates[0]) && 
      !isNaN(d.coordinates[1])
    );

    validDeliveries.forEach((delivery, idx) => {
      const color = delivery.status === DeliveryStatus.COMPLETED ? '#10b981' : 
                   delivery.status === DeliveryStatus.IN_PROGRESS ? '#3b82f6' : '#64748b';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div style="background-color: ${color}; width: 28px; height: 28px; border-radius: 50%; border: 3px solid white; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); display: flex; align-items: center; justify-content: center; color: white; font-weight: 800; font-size: 11px;">${idx + 1}</div>`,
        iconSize: [28, 28],
        iconAnchor: [14, 14]
      });

      try {
        const marker = L.marker(delivery.coordinates, { icon })
          .addTo(map)
          .on('click', () => onMarkerClick(delivery.id));

        markersRef.current[delivery.id] = marker;
      } catch (e) {
        console.error("Error creating marker for delivery", delivery.id, e);
      }
    });

    if (validDeliveries.length > 0 && viewMode !== 'list') {
      try {
        const bounds = L.latLngBounds(validDeliveries.map(d => d.coordinates));
        map.fitBounds(bounds, { padding: [60, 60], maxZoom: 16 });
      } catch (e) {
        console.warn("Could not fit bounds", e);
      }
    }
  }, [deliveries, onMarkerClick, viewMode]);

  // Centrar en elemento seleccionado
  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      try {
        const marker = markersRef.current[selectedId];
        mapRef.current.flyTo(marker.getLatLng(), 16, {
          duration: 0.8
        });
      } catch (e) {
        console.warn("FlyTo failed", e);
      }
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
      style={{ minHeight: '300px' }}
    ></div>
  );
};

export default MapView;

