import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, Package, truck, ArrowDownLeft, ArrowUpRight } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;

  // Lógica de colores por tipo y estado
  const getColors = () => {
    if (isCompleted) return 'border-green-200 bg-green-50 hover:border-green-300 text-green-700';
    if (delivery.type === DeliveryType.PICKUP) return 'border-red-100 bg-red-50/50 hover:border-red-200 text-red-700';
    return 'border-blue-100 bg-blue-50/50 hover:border-blue-200 text-blue-700';
  };

  const getBadgeColors = () => {
    if (isCompleted) return 'bg-green-100 text-green-600';
    if (delivery.type === DeliveryType.PICKUP) return 'bg-red-100 text-red-600';
    return 'bg-blue-100 text-blue-600';
  };

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  return (
    <div 
      draggable={!isCompleted}
      onDragStart={(e) => !isCompleted && onDragStart(e, index)}
      onDragOver={(e) => !isCompleted && onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 transition-all cursor-pointer group shadow-sm active:scale-[0.99] transition-transform overflow-hidden ${
        isSelected ? 'ring-2 ring-offset-1 ring-blue-500' : ''
      } ${getColors()}`}
    >
      {/* Drag Handle (Solo si no está completado) */}
      {!isCompleted && (
        <div className="absolute left-1 top-4 text-slate-300 group-hover:text-slate-400 p-1">
          <GripVertical size={16} />
        </div>
      )}

      <div className={`${!isCompleted ? 'pl-8' : 'pl-4'} pr-4 py-3`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3 overflow-hidden">
            {!isCompleted && (
              <span className="shrink-0 w-6 h-6 flex items-center justify-center bg-slate-900 text-white text-[10px] font-bold rounded-full">
                {index + 1}
              </span>
            )}
            <div className="flex flex-col">
              <div className="flex items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${getBadgeColors()}`}>
                  {delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />}
                  {delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0">
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors"
            >
              <Trash2 size={16} />
            </button>

            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white/50 transition-colors"
            >
              {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-black/5 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-3">
              <div className="flex items-start gap-2 text-slate-600 text-xs">
                <MapPin size={14} className="mt-0.5 shrink-0 text-slate-400" />
                <p className="leading-relaxed">{delivery.address}</p>
              </div>

              {delivery.notes && (
                <div className="bg-black/5 p-2 rounded-lg text-[11px] text-slate-500 italic">
                  Nota: {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-2">
                <div className="flex gap-2">
                  {!isCompleted && (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-green-600 text-white hover:bg-green-700 text-[11px] font-bold transition-all shadow-sm"
                      >
                        <CheckCircle size={14} /> Finalizar
                      </button>
                      {delivery.status === DeliveryStatus.PENDING && (
                        <button 
                          type="button"
                          onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-[11px] font-bold transition-colors"
                        >
                          <Navigation size={14} /> En Ruta
                        </button>
                      )}
                    </>
                  )}
                  {isCompleted && (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-[10px] text-slate-500 hover:underline"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="flex items-center gap-3">
                  {delivery.sourceUrl && (
                    <a href={delivery.sourceUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="text-[10px] text-blue-500 hover:underline flex items-center gap-1">
                      <ExternalLink size={12} /> Mapa
                    </a>
                  )}
                  <div className="text-[10px] text-slate-400 flex items-center gap-1 font-medium">
                    <Clock size={12} /> {delivery.estimatedTime || 'N/A'}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

