                {isOptimizing ? <Loader2 size={14} className="animate-spin" /> : <BrainCircuit size={14} />}
                OPTIMIZAR AI
              </button>
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">T</p>
                <p className="text-lg font-black text-slate-800">{stats.total}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-green-400 font-bold uppercase tracking-widest">C</p>
                <p className="text-lg font-black text-green-600">{stats.completed}</p>
              </div>
              <div className="bg-white p-2 rounded-xl border border-slate-200 shadow-sm text-center">
                <p className="text-[9px] text-blue-400 font-bold uppercase tracking-widest">P</p>
                <p className="text-lg font-black text-blue-600">{stats.pending}</p>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-slate-50/30">
            {/* Sección Pendientes */}
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={14} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-8 border-2 border-dashed border-slate-200 rounded-2xl bg-white/50">
                  <p className="text-xs text-slate-400">No hay tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => (
                  <DeliveryCard key={delivery.id} index={index} delivery={delivery} isSelected={selectedId === delivery.id} onClick={() => { setSelectedId(delivery.id); if (window.innerWidth < 768) setViewMode('map'); }} onStatusChange={handleStatusChange} onDelete={handleDeleteDelivery} onDragStart={onDragStart} onDragOver={onDragOver} onDragEnd={onDragEnd} />
                ))
              )}
            </div>

            {/* Sección Realizadas */}
            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-xs font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={14} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery, index) => (
                  <DeliveryCard key={delivery.id} index={index} delivery={delivery} isSelected={selectedId === delivery.id} onClick={() => { setSelectedId(delivery.id); if (window.innerWidth < 768) setViewMode('map'); }} onStatusChange={handleStatusChange} onDelete={handleDeleteDelivery} onDragStart={() => {}} onDragOver={() => {}} onDragEnd={() => {}} />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${viewMode === 'list' ? 'hidden' : 'block'} flex-1 h-full relative z-10 overflow-hidden`}>
          <MapView deliveries={deliveries} selectedId={selectedId} onMarkerClick={(id) => setSelectedId(id)} viewMode={viewMode} />
          {viewMode === 'map' && (
            <button onClick={() => setViewMode('list')} className="md:hidden absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-800 px-6 py-3 rounded-full shadow-2xl z-[400] font-bold flex items-center gap-2 border border-slate-200">
              <List size={18} className="text-blue-600" />
              Lista de Paradas
            </button>
          )}
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
                <p className="text-sm text-slate-500">Configura los detalles del destino.</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white hover:shadow-sm rounded-full text-slate-400"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-6">
              {/* Selector de Tipo */}
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button 
                  type="button" 
                  onClick={() => setNewType(DeliveryType.DELIVERY)}
                  className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-200'}`}
                >
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button 
                  type="button" 
                  onClick={() => setNewType(DeliveryType.PICKUP)}
                  className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-200'}`}
                >
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Dirección o Datos del Cliente</label>
                <textarea 
                  value={newAddressInput}
                  onChange={(e) => setNewAddressInput(e.target.value)}
                  className="w-full h-32 p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all resize-none text-slate-700"
                  placeholder="Ej: Recogida de paquete en C/ Serrano 10, Madrid..."
                  required
                />
              </div>

              <div className="flex gap-3">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <><Loader2 size={20} className="animate-spin" /> Procesando...</> : <><Plus size={20} /> Añadir</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, ArrowDownLeft, ArrowUpRight } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;

  const getColors = () => {
    if (isCompleted) return 'border-green-200 bg-green-50 hover:border-green-300 text-green-700';
    if (delivery.type === DeliveryType.PICKUP) return 'border-red-100 bg-red-50/50 hover:border-red-200 text-red-700';
    return 'border-blue-100 bg-blue-50/50 hover:border-blue-200 text-blue-700';
  };

  const getBadgeColors = () => {
    if (isCompleted) return 'bg-green-100 text-green-600';
    if (delivery.type === DeliveryType.PICKUP) return 'bg-red-100 text-red-600';
    return 'bg-blue-100 text-blue-600';
  };

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  return (
    <div 
      draggable={!isCompleted}
      onDragStart={(e) => !isCompleted && onDragStart(e, index)}
      onDragOver={(e) => !isCompleted && onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 transition-all cursor-pointer group shadow-sm active:scale-[0.99] transition-transform overflow-hidden ${
        isSelected ? 'ring-2 ring-offset-1 ring-blue-500' : ''
      } ${getColors()}`}
    >
      {!isCompleted && (
        <div className="absolute left-1 top-4 text-slate-300 group-hover:text-slate-400 p-1">
          <GripVertical size={16} />
        </div>
      )}

      <div className={`${!isCompleted ? 'pl-8' : 'pl-4'} pr-4 py-3`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3 overflow-hidden">
            {!isCompleted && (
              <span className="shrink-0 w-6 h-6 flex items-center justify-center bg-slate-900 text-white text-[10px] font-bold rounded-full">
                {index + 1}
              </span>
            )}
            <div className="flex flex-col">
              <div className="flex items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${getBadgeColors()}`}>
                  {delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />}
                  {delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0">
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors"
            >
              <Trash2 size={16} />
            </button>

            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white/50 transition-colors"
            >
              {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-black/5 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-3">
              <div className="flex items-start gap-2 text-slate-600 text-xs">
                <MapPin size={14} className="mt-0.5 shrink-0 text-slate-400" />
                <p className="leading-relaxed">{delivery.address}</p>
              </div>

              {delivery.notes && (
                <div className="bg-black/5 p-2 rounded-lg text-[11px] text-slate-500 italic">
                  Nota: {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-2">
                <div className="flex gap-2">
                  {!isCompleted && (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-green-600 text-white hover:bg-green-700 text-[11px] font-bold transition-all shadow-sm"
                      >
                        <CheckCircle size={14} /> Finalizar
                      </button>
                      {delivery.status === DeliveryStatus.PENDING && (
                        <button 
                          type="button"
                          onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-[11px] font-bold transition-colors"
                        >
                          <Navigation size={14} /> En Ruta
                        </button>
                      )}
                    </>
                  )}
                  {isCompleted && (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-[10px] text-slate-500 hover:underline"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="flex items-center gap-3">
                  {delivery.sourceUrl && (
                    <a href={delivery.sourceUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="text-[10px] text-blue-500 hover:underline flex items-center gap-1">
                      <ExternalLink size={12} /> Mapa
                    </a>
                  )}
                  <div className="text-[10px] text-slate-400 flex items-center gap-1 font-medium">
                    <Clock size={12} /> {delivery.estimatedTime || 'N/A'}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'list' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
      if (window.innerWidth < 768) setViewMode('map');
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      window.location.reload();
    }
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status !== DeliveryStatus.COMPLETED);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        const orderMap = new Map();
        result.optimizedOrder.forEach((id: string, index: number) => orderMap.set(id, index));

        const sortedPending = [...pending].sort((a, b) => {
          const indexA = orderMap.get(a.id) ?? 999;
          const indexB = orderMap.get(b.id) ?? 999;
          return indexA - indexB;
        });

        const completed = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);
        setDeliveries([...sortedPending, ...completed]);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pending = deliveries.filter(d => d.status !== DeliveryStatus.COMPLETED);
      const completed = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

      const newList = [...pending];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setDeliveries([...newList, ...completed]);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const pendingDeliveries = deliveries.filter(d => d.status !== DeliveryStatus.COMPLETED);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Navigation size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden md:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs md:text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden md:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`hidden md:flex p-2 md:px-4 rounded-lg text-xs md:text-sm font-bold transition-all items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden md:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden lg:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <aside className={`absolute inset-0 z-20 md:relative md:inset-auto ${viewMode === 'map' ? 'hidden' : 'flex'} ${viewMode === 'split' ? 'md:w-[380px] lg:w-[420px]' : 'w-full'} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2">
              <Navigation size={18} className="text-blue-600" />
              Ruta Actual
            </h2>
            <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[11px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
              {isOptimizing ? <Loader2 size={14} className="animate-spin" /> : <BrainCircuit size={14} />}
              OPTIMIZAR
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={14} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-8 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-xs text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => (
                  <DeliveryCard key={delivery.id} index={index} delivery={delivery} isSelected={selectedId === delivery.id} onClick={() => { setSelectedId(delivery.id); if (window.innerWidth < 768) setViewMode('map'); }} onStatusChange={handleStatusChange} onDelete={handleDeleteDelivery} onDragStart={onDragStart} onDragOver={onDragOver} onDragEnd={onDragEnd} />
                ))
              )}
            </div>

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
