            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-6">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white' : 'text-slate-500'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <textarea value={newAddressInput} onChange={(e) => setNewAddressInput(e.target.value)} className="w-full h-32 p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 outline-none transition-all resize-none" placeholder="Dirección o datos del paquete..." required />

              <div className="flex gap-3">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600' : 'bg-red-600'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} Añadir
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

