            <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
              {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
              OPTIMIZAR
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
