                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Phone size={18} />
                  </div>
                  <input 
                    type="tel"
                    value={newPhoneInput}
                    onChange={(e) => setNewPhoneInput(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                    placeholder="Teléfono de contacto (opcional)"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
