              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      window.location.reload();
    }
  };

  const handleMoveToTop = (id: string) => {
    const target = deliveries.find(d => d.id === id);
    if (!target) return;

    // Solo permitimos priorizar si no está completado
    if (target.status === DeliveryStatus.COMPLETED) return;

    const others = deliveries.filter(d => d.id !== id);
    setDeliveries([target, ...others]);
    setSelectedId(id);
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        const orderMap = new Map();
        result.optimizedOrder.forEach((id: string, index: number) => orderMap.set(id, index));

        const sortedPending = [...pending].sort((a, b) => {
          const indexA = orderMap.get(a.id) ?? 999;
          const indexB = orderMap.get(b.id) ?? 999;
          return indexA - indexB;
        });

        const rest = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED || d.status === DeliveryStatus.ISSUE);
        setDeliveries([...sortedPending, ...rest]);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
      const rest = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED || d.status === DeliveryStatus.ISSUE);

      const newList = [...pending];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setDeliveries([...newList, ...rest]);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const pendingDeliveries = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const asideClasses = viewMode === 'map' ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = viewMode === 'list' ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
              {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
              OPTIMIZAR
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onMoveToTop={handleMoveToTop}
                    onDragStart={onDragStart} 
                    onDragOver={onDragOver} 
                    onDragEnd={onDragEnd} 
                  />
                ))
              )}
            </div>

            {issueDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-yellow-600 uppercase tracking-widest px-1">
                  <AlertTriangle size={12} />
                  <span>Incidencias ({issueDeliveries.length})</span>
                </div>
                {issueDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onMoveToTop={handleMoveToTop}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={12} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onMoveToTop={handleMoveToTop}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${sectionClasses} relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            selectedId={selectedId} 
            onMarkerClick={(id) => setSelectedId(id)} 
            onMoveToTop={handleMoveToTop}
            viewMode={viewMode} 
          />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-28 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all resize-none text-sm" 
                    placeholder="Dirección o datos del paquete (Ej: Calle Mayor 1, Madrid)..." 
                    required 
                  />
                </div>

                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Phone size={18} />
                  </div>
                  <input 
                    type="tel"
                    value={newPhoneInput}
                    onChange={(e) => setNewPhoneInput(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                    placeholder="Teléfono de contacto (opcional)"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
                  <span className="text-sm">Añadir Parada</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, ArrowDownLeft, ArrowUpRight, AlertTriangle, Phone, ArrowUpToLine } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onMoveToTop: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onMoveToTop,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;
  const isIssue = delivery.status === DeliveryStatus.ISSUE;

  const getStyles = () => {
    if (isCompleted) {
      return {
        border: 'border-green-200',
        bg: 'bg-green-50/30',
        accent: 'bg-green-600',
        text: 'text-green-700',
        side: 'border-l-green-500'
      };
    }
    if (isIssue) {
      return {
        border: 'border-yellow-200',
        bg: 'bg-yellow-50/40',
        accent: 'bg-yellow-600',
        text: 'text-yellow-700',
        side: 'border-l-yellow-500'
      };
    }
    if (delivery.type === DeliveryType.PICKUP) {
      return {
        border: 'border-red-100',
        bg: 'bg-red-50/40',
        accent: 'bg-red-600',
        text: 'text-red-700',
        side: 'border-l-red-500'
      };
    }
    return {
      border: 'border-blue-100',
      bg: 'bg-blue-50/40',
      accent: 'bg-blue-600',
      text: 'text-blue-700',
      side: 'border-l-blue-500'
    };
  };

  const styles = getStyles();

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  return (
    <div 
      draggable={!isCompleted && !isIssue}
      onDragStart={(e) => !isCompleted && !isIssue && onDragStart(e, index)}
      onDragOver={(e) => !isCompleted && !isIssue && onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 border-l-[6px] transition-all cursor-pointer group shadow-sm hover:shadow-md ${
        isSelected ? 'ring-2 ring-blue-500 ring-offset-1' : ''
      } ${styles.border} ${styles.bg} ${styles.side}`}
    >
      {!isCompleted && !isIssue && (
        <div className="absolute left-[-2px] top-1/2 -translate-y-1/2 text-white/80 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <GripVertical size={14} />
        </div>
      )}

      <div className="pl-4 pr-3 py-3">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3 overflow-hidden">
            <div className="flex flex-col min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${
                  isCompleted ? 'bg-green-100 text-green-600' : 
                  (isIssue ? 'bg-yellow-100 text-yellow-700' : 
                  (delivery.type === DeliveryType.PICKUP ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'))
                }`}>
                  {isIssue ? <AlertTriangle size={10} /> : (delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />)}
                  {isIssue ? 'INCIDENCIA' : (delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA')}
                </span>
              </div>
              <div className="flex items-center gap-1 text-[11px] text-slate-500 mt-0.5">
                <MapPin size={12} className="shrink-0" />
                <p className="truncate opacity-80">{delivery.address}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0 ml-2">
            {!isCompleted && !isIssue && (
              <button 
                type="button"
                title="Priorizar"
                onClick={(e) => { e.stopPropagation(); onMoveToTop(delivery.id); }}
                className="p-1.5 rounded-lg text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-all"
              >
                <ArrowUpToLine size={16} />
              </button>
            )}
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-white transition-all"
            >
              <Trash2 size={16} />
            </button>
            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white transition-all"
            >
              {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-slate-200/50 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-4">
              <div className="flex flex-wrap gap-3">
                {delivery.phone && (
                  <a 
                    href={`tel:${delivery.phone}`}
                    onClick={(e) => e.stopPropagation()}
                    className="flex items-center gap-2 px-3 py-2 bg-blue-50 text-blue-600 rounded-xl text-xs font-bold border border-blue-100 hover:bg-blue-100 transition-colors"
                  >
                    <Phone size={14} /> {delivery.phone}
                  </a>
                )}
                {delivery.sourceUrl && (
                  <a 
                    href={delivery.sourceUrl} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    onClick={(e) => e.stopPropagation()} 
                    className="flex items-center gap-2 px-3 py-2 bg-slate-50 text-slate-600 rounded-xl text-xs font-bold border border-slate-200 hover:bg-slate-100 transition-colors"
                  >
                    <ExternalLink size={14} /> Google Maps
                  </a>
                )}
              </div>

              {delivery.notes && (
                <div className="bg-white/60 p-2.5 rounded-lg text-[11px] text-slate-600 border border-slate-100">
                  <span className="font-bold text-slate-400 uppercase text-[9px] block mb-1">Notas:</span>
                  {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex flex-wrap gap-2">
                  {!isCompleted && !isIssue ? (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-green-600 text-white hover:bg-green-700 text-xs font-bold transition-all shadow-sm shadow-green-100"
                      >
                        <CheckCircle size={14} /> Entregado
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.ISSUE); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-yellow-500 text-white hover:bg-yellow-600 text-xs font-bold transition-all shadow-sm shadow-yellow-100"
                      >
                        <AlertTriangle size={14} /> Incidencia
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                        className={`flex items-center gap-1.5 px-4 py-2 rounded-xl bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-xs font-bold transition-all ${delivery.status === DeliveryStatus.IN_PROGRESS ? 'border-blue-500 text-blue-600' : ''}`}
                      >
                        <Navigation size={14} /> {delivery.status === DeliveryStatus.IN_PROGRESS ? 'En Camino' : 'Ir ahora'}
                      </button>
                    </>
                  ) : (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-xs font-bold text-slate-400 hover:text-slate-600 underline underline-offset-4"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="text-[11px] text-slate-400 flex items-center gap-1 font-medium ml-auto">
                  <Clock size={12} /> {delivery.estimatedTime || '--:--'}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  selectedId: string | null;
  onMarkerClick: (id: string) => void;
  onMoveToTop: (id: string) => void;
  viewMode: string;
}

const MapView: React.FC<MapViewProps> = ({ deliveries, selectedId, onMarkerClick, onMoveToTop, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});
  const polylineRef = useRef<L.Polyline | null>(null);

  useEffect(() => {
    if (!mapRef.current) {
      const mapContainer = document.getElementById('map-container');
      if (!mapContainer) return;

      mapRef.current = L.map('map-container', {
        zoomControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }
  }, []);

  useEffect(() => {
    if (mapRef.current) {
      const timer = setTimeout(() => {
        try {
          mapRef.current?.invalidateSize({ animate: true });
        } catch (e) {
          console.warn("Invalidate size failed", e);
        }
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Remove existing markers
    (Object.values(markersRef.current) as L.Marker[]).forEach(m => {
      try {
        m.remove();
      } catch (e) {
        console.warn("Error removing marker", e);
      }
    });
    markersRef.current = {};

    // Remove existing polyline
    if (polylineRef.current) {
      polylineRef.current.remove();
      polylineRef.current = null;
    }

    const validDeliveries = deliveries.filter(d => 
      Array.isArray(d.coordinates) && 
      d.coordinates.length === 2 && 
      !isNaN(d.coordinates[0]) && 
      !isNaN(d.coordinates[1])
    );

    // Filter pending for the route path
    const pending = validDeliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);

    // Draw route path if there are at least 2 points
    if (pending.length >= 2) {
      const routePoints = pending.map(d => d.coordinates);
      polylineRef.current = L.polyline(routePoints, {
        color: '#3b82f6',
        weight: 4,
        opacity: 0.6,
        dashArray: '10, 10',
        lineJoin: 'round'
      }).addTo(map);
    }

    validDeliveries.forEach((delivery) => {
      // Color logic
      let color = '#3b82f6'; // Blue (delivery)
      if (delivery.status === DeliveryStatus.COMPLETED) {
        color = '#10b981'; // Green
      } else if (delivery.status === DeliveryStatus.ISSUE) {
        color = '#eab308'; // Yellow
      } else if (delivery.type === DeliveryType.PICKUP) {
        color = '#ef4444'; // Red
      }

      const isSelected = selectedId === delivery.id;
      const size = isSelected ? 24 : 18;
      const borderSize = isSelected ? '4px' : '3px';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div style="background-color: ${color}; width: ${size}px; height: ${size}px; border-radius: 50%; border: ${borderSize} solid white; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); transition: all 0.3s ease;"></div>`,
        iconSize: [size, size],
        iconAnchor: [size/2, size/2]
      });

      try {
        const marker = L.marker(delivery.coordinates, { icon, zIndexOffset: isSelected ? 1000 : 0 })
          .addTo(map)
          .on('click', () => onMarkerClick(delivery.id));

        // Add popup with Priority action
        const popupContent = document.createElement('div');
        popupContent.className = 'p-2 min-w-[120px]';
        popupContent.innerHTML = `
          <div class="font-bold text-sm mb-1">${delivery.recipient}</div>
          <div class="text-[10px] text-slate-500 mb-2 truncate max-w-[140px]">${delivery.address}</div>
        `;

        if (delivery.status !== DeliveryStatus.COMPLETED) {
          const btn = document.createElement('button');
          btn.className = 'w-full py-1.5 px-2 bg-blue-600 text-white text-[10px] font-bold rounded-lg shadow-sm hover:bg-blue-700 transition-colors flex items-center justify-center gap-1';
          btn.innerHTML = 'ESTABLECER SIGUIENTE';
          btn.onclick = (e) => {
            e.stopPropagation();
            onMoveToTop(delivery.id);
            map.closePopup();
          };
          popupContent.appendChild(btn);
        }

        marker.bindPopup(popupContent, { offset: [0, -size/2] });
        markersRef.current[delivery.id] = marker;
      } catch (e) {
        console.error("Error creating marker", e);
      }
    });

    if (validDeliveries.length > 0 && viewMode !== 'list') {
      try {
        const bounds = L.latLngBounds(validDeliveries.map(d => d.coordinates));
        map.fitBounds(bounds, { padding: [80, 80], maxZoom: 16 });
      } catch (e) {
        console.warn("Could not fit bounds", e);
      }
    }
  }, [deliveries, onMarkerClick, onMoveToTop, viewMode, selectedId]);

  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      try {
        const marker = markersRef.current[selectedId];
        mapRef.current.flyTo(marker.getLatLng(), 16, {
          duration: 1
        });
        marker.openPopup();
      } catch (e) {
        console.warn("FlyTo failed", e);
      }
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
      style={{ minHeight: '300px' }}
    ></div>
  );
};

export default MapView;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      window.location.reload();
    }
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        const orderMap = new Map();
        result.optimizedOrder.forEach((id: string, index: number) => orderMap.set(id, index));

        const sortedPending = [...pending].sort((a, b) => {
          const indexA = orderMap.get(a.id) ?? 999;
          const indexB = orderMap.get(b.id) ?? 999;
          return indexA - indexB;
        });

        const rest = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED || d.status === DeliveryStatus.ISSUE);
        setDeliveries([...sortedPending, ...rest]);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
      const rest = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED || d.status === DeliveryStatus.ISSUE);

      const newList = [...pending];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setDeliveries([...newList, ...rest]);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const pendingDeliveries = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const asideClasses = viewMode === 'map' ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = viewMode === 'list' ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
              {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
              OPTIMIZAR
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onDragStart={onDragStart} 
                    onDragOver={onDragOver} 
                    onDragEnd={onDragEnd} 
                  />
                ))
              )}
            </div>

            {issueDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-yellow-600 uppercase tracking-widest px-1">
                  <AlertTriangle size={12} />
                  <span>Incidencias ({issueDeliveries.length})</span>
                </div>
                {issueDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={12} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    index={index} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${sectionClasses} relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            selectedId={selectedId} 
            onMarkerClick={(id) => setSelectedId(id)} 
            viewMode={viewMode} 
          />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-28 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all resize-none text-sm" 
                    placeholder="Dirección o datos del paquete (Ej: Calle Mayor 1, Madrid)..." 
                    required 
                  />
                </div>

                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Phone size={18} />
                  </div>
                  <input 
                    type="tel"
                    value={newPhoneInput}
                    onChange={(e) => setNewPhoneInput(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                    placeholder="Teléfono de contacto (opcional)"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
                  <span className="text-sm">Añadir Parada</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, ArrowDownLeft, ArrowUpRight, AlertTriangle, Phone } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index: number;
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;
  const isIssue = delivery.status === DeliveryStatus.ISSUE;

  const getStyles = () => {
    if (isCompleted) {
      return {
        border: 'border-green-200',
        bg: 'bg-green-50/30',
        accent: 'bg-green-600',
        text: 'text-green-700',
        side: 'border-l-green-500'
      };
    }
    if (isIssue) {
      return {
        border: 'border-yellow-200',
        bg: 'bg-yellow-50/40',
        accent: 'bg-yellow-600',
        text: 'text-yellow-700',
        side: 'border-l-yellow-500'
      };
    }
    if (delivery.type === DeliveryType.PICKUP) {
      return {
        border: 'border-red-100',
        bg: 'bg-red-50/40',
        accent: 'bg-red-600',
        text: 'text-red-700',
        side: 'border-l-red-500'
      };
    }
    return {
      border: 'border-blue-100',
      bg: 'bg-blue-50/40',
      accent: 'bg-blue-600',
      text: 'text-blue-700',
      side: 'border-l-blue-500'
    };
  };

  const styles = getStyles();

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  return (
    <div 
      draggable={!isCompleted && !isIssue}
      onDragStart={(e) => !isCompleted && !isIssue && onDragStart(e, index)}
      onDragOver={(e) => !isCompleted && !isIssue && onDragOver(e, index)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 border-l-[6px] transition-all cursor-pointer group shadow-sm hover:shadow-md ${
        isSelected ? 'ring-2 ring-blue-500 ring-offset-1' : ''
      } ${styles.border} ${styles.bg} ${styles.side}`}
    >
      {!isCompleted && !isIssue && (
        <div className="absolute left-[-2px] top-1/2 -translate-y-1/2 text-white/80 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <GripVertical size={14} />
        </div>
      )}

      <div className="pl-4 pr-3 py-3">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3 overflow-hidden">
            <div className="flex flex-col min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${
                  isCompleted ? 'bg-green-100 text-green-600' : 
                  (isIssue ? 'bg-yellow-100 text-yellow-700' : 
                  (delivery.type === DeliveryType.PICKUP ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'))
                }`}>
                  {isIssue ? <AlertTriangle size={10} /> : (delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />)}
                  {isIssue ? 'INCIDENCIA' : (delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA')}
                </span>
              </div>
              <div className="flex items-center gap-1 text-[11px] text-slate-500 mt-0.5">
                <MapPin size={12} className="shrink-0" />
                <p className="truncate opacity-80">{delivery.address}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0 ml-2">
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-white transition-all"
            >
              <Trash2 size={16} />
            </button>
            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white transition-all"
            >
              {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-slate-200/50 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-4">
              <div className="flex flex-wrap gap-3">
                {delivery.phone && (
                  <a 
                    href={`tel:${delivery.phone}`}
                    onClick={(e) => e.stopPropagation()}
                    className="flex items-center gap-2 px-3 py-2 bg-blue-50 text-blue-600 rounded-xl text-xs font-bold border border-blue-100 hover:bg-blue-100 transition-colors"
                  >
                    <Phone size={14} /> {delivery.phone}
                  </a>
                )}
                {delivery.sourceUrl && (
                  <a 
                    href={delivery.sourceUrl} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    onClick={(e) => e.stopPropagation()} 
                    className="flex items-center gap-2 px-3 py-2 bg-slate-50 text-slate-600 rounded-xl text-xs font-bold border border-slate-200 hover:bg-slate-100 transition-colors"
                  >
                    <ExternalLink size={14} /> Google Maps
                  </a>
                )}
              </div>

              {delivery.notes && (
                <div className="bg-white/60 p-2.5 rounded-lg text-[11px] text-slate-600 border border-slate-100">
                  <span className="font-bold text-slate-400 uppercase text-[9px] block mb-1">Notas:</span>
                  {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex flex-wrap gap-2">
                  {!isCompleted && !isIssue ? (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-green-600 text-white hover:bg-green-700 text-xs font-bold transition-all shadow-sm shadow-green-100"
                      >
                        <CheckCircle size={14} /> Entregado
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.ISSUE); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-yellow-500 text-white hover:bg-yellow-600 text-xs font-bold transition-all shadow-sm shadow-yellow-100"
                      >
                        <AlertTriangle size={14} /> Incidencia
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                        className={`flex items-center gap-1.5 px-4 py-2 rounded-xl bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-xs font-bold transition-all ${delivery.status === DeliveryStatus.IN_PROGRESS ? 'border-blue-500 text-blue-600' : ''}`}
                      >
                        <Navigation size={14} /> {delivery.status === DeliveryStatus.IN_PROGRESS ? 'En Camino' : 'Ir ahora'}
                      </button>
                    </>
                  ) : (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-xs font-bold text-slate-400 hover:text-slate-600 underline underline-offset-4"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="text-[11px] text-slate-400 flex items-center gap-1 font-medium ml-auto">
                  <Clock size={12} /> {delivery.estimatedTime || '--:--'}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  selectedId: string | null;
  onMarkerClick: (id: string) => void;
  viewMode: string;
}

const MapView: React.FC<MapViewProps> = ({ deliveries, selectedId, onMarkerClick, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});
  const polylineRef = useRef<L.Polyline | null>(null);

  useEffect(() => {
    if (!mapRef.current) {
      const mapContainer = document.getElementById('map-container');
      if (!mapContainer) return;

      mapRef.current = L.map('map-container', {
        zoomControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }
  }, []);

  useEffect(() => {
    if (mapRef.current) {
      const timer = setTimeout(() => {
        try {
          mapRef.current?.invalidateSize({ animate: true });
        } catch (e) {
          console.warn("Invalidate size failed", e);
        }
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Remove existing markers
    (Object.values(markersRef.current) as L.Marker[]).forEach(m => {
      try {
        m.remove();
      } catch (e) {
        console.warn("Error removing marker", e);
      }
    });
    markersRef.current = {};

    // Remove existing polyline
    if (polylineRef.current) {
      polylineRef.current.remove();
      polylineRef.current = null;
    }

    const validDeliveries = deliveries.filter(d => 
      Array.isArray(d.coordinates) && 
      d.coordinates.length === 2 && 
      !isNaN(d.coordinates[0]) && 
      !isNaN(d.coordinates[1])
    );

    // Filter pending for the route path
    const pending = validDeliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);

    // Draw route path if there are at least 2 points
    if (pending.length >= 2) {
      const routePoints = pending.map(d => d.coordinates);
      polylineRef.current = L.polyline(routePoints, {
        color: '#3b82f6',
        weight: 4,
        opacity: 0.6,
        dashArray: '10, 10',
        lineJoin: 'round'
      }).addTo(map);
    }

    validDeliveries.forEach((delivery) => {
      // Color logic
      let color = '#3b82f6'; // Blue (delivery)
      if (delivery.status === DeliveryStatus.COMPLETED) {
        color = '#10b981'; // Green
      } else if (delivery.status === DeliveryStatus.ISSUE) {
        color = '#eab308'; // Yellow
      } else if (delivery.type === DeliveryType.PICKUP) {
        color = '#ef4444'; // Red
      }

      const isSelected = selectedId === delivery.id;
      const size = isSelected ? 24 : 18;
      const borderSize = isSelected ? '4px' : '3px';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div style="background-color: ${color}; width: ${size}px; height: ${size}px; border-radius: 50%; border: ${borderSize} solid white; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); transition: all 0.3s ease;"></div>`,
        iconSize: [size, size],
        iconAnchor: [size/2, size/2]
      });

      try {
        const marker = L.marker(delivery.coordinates, { icon, zIndexOffset: isSelected ? 1000 : 0 })
          .addTo(map)
          .on('click', () => onMarkerClick(delivery.id));

        // Add popup
        const popupContent = document.createElement('div');
        popupContent.className = 'p-2 min-w-[120px]';
        popupContent.innerHTML = `
          <div class="font-bold text-sm mb-1">${delivery.recipient}</div>
          <div class="text-[10px] text-slate-500 truncate max-w-[140px]">${delivery.address}</div>
        `;

        marker.bindPopup(popupContent, { offset: [0, -size/2] });
        markersRef.current[delivery.id] = marker;
      } catch (e) {
        console.error("Error creating marker", e);
      }
    });

    if (validDeliveries.length > 0 && viewMode !== 'list') {
      try {
        const bounds = L.latLngBounds(validDeliveries.map(d => d.coordinates));
        map.fitBounds(bounds, { padding: [80, 80], maxZoom: 16 });
      } catch (e) {
        console.warn("Could not fit bounds", e);
      }
    }
  }, [deliveries, onMarkerClick, viewMode, selectedId]);

  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      try {
        const marker = markersRef.current[selectedId];
        mapRef.current.flyTo(marker.getLatLng(), 16, {
          duration: 1
        });
        marker.openPopup();
      } catch (e) {
        console.warn("FlyTo failed", e);
      }
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
      style={{ minHeight: '300px' }}
    ></div>
  );
};

export default MapView;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
  }, [manualSequence]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    setManualSequence(prev => prev.filter(sid => sid !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(SEQUENCE_KEY);
      window.location.reload();
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery || delivery.status === DeliveryStatus.COMPLETED) return;

    // Si no está en la secuencia, lo añadimos al final
    if (!manualSequence.includes(id)) {
      setManualSequence(prev => [...prev, id]);
    }
  };

  const resetSequence = () => {
    setManualSequence([]);
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        setManualSequence(result.optimizedOrder);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    // La ordenación manual por drag & drop actualiza la secuencia
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pendingSorted = getSortedPending();
      const newList = [...pendingSorted];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setManualSequence(newList.map(d => d.id));
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);

    // Primero los que tienen orden manual
    const ordered = manualSequence
      .map(id => pending.find(p => p.id === id))
      .filter((p): p is Delivery => !!p);

    // Luego los que no están en la secuencia
    const unordered = pending.filter(p => !manualSequence.includes(p.id));

    return [...ordered, ...unordered];
  };

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const asideClasses = viewMode === 'map' ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = viewMode === 'list' ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <div className="flex items-center gap-2">
              {manualSequence.length > 0 && (
                <button onClick={resetSequence} className="p-1.5 text-slate-400 hover:text-slate-600 transition-colors" title="Reiniciar orden">
                  <RotateCcw size={16} />
                </button>
              )}
              <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
                {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
                AUTO-RUTEAR
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => {
                  const seqIdx = manualSequence.indexOf(delivery.id);
                  return (
                    <DeliveryCard 
                      key={delivery.id} 
                      index={seqIdx !== -1 ? seqIdx : undefined} 
                      delivery={delivery} 
                      isSelected={selectedId === delivery.id} 
                      onClick={() => setSelectedId(delivery.id)} 
                      onStatusChange={handleStatusChange} 
                      onDelete={handleDeleteDelivery} 
                      onDragStart={onDragStart} 
                      onDragOver={onDragOver} 
                      onDragEnd={onDragEnd} 
                    />
                  );
                })
              )}
            </div>

            {issueDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-yellow-600 uppercase tracking-widest px-1">
                  <AlertTriangle size={12} />
                  <span>Incidencias ({issueDeliveries.length})</span>
                </div>
                {issueDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={12} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${sectionClasses} relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            manualSequence={manualSequence}
            selectedId={selectedId} 
            onMarkerClick={handleMarkerClick} 
            viewMode={viewMode} 
          />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-28 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all resize-none text-sm" 
                    placeholder="Dirección o datos del paquete (Ej: Calle Mayor 1, Madrid)..." 
                    required 
                  />
                </div>

                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Phone size={18} />
                  </div>
                  <input 
                    type="tel"
                    value={newPhoneInput}
                    onChange={(e) => setNewPhoneInput(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                    placeholder="Teléfono de contacto (opcional)"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
                  <span className="text-sm">Añadir Parada</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, ArrowDownLeft, ArrowUpRight, AlertTriangle, Phone } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index?: number; // El índice ahora es opcional y representa la secuencia manual
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;
  const isIssue = delivery.status === DeliveryStatus.ISSUE;

  const getStyles = () => {
    if (isCompleted) {
      return {
        border: 'border-green-200',
        bg: 'bg-green-50/30',
        accent: 'bg-green-600',
        text: 'text-green-700',
        side: 'border-l-green-500'
      };
    }
    if (isIssue) {
      return {
        border: 'border-yellow-200',
        bg: 'bg-yellow-50/40',
        accent: 'bg-yellow-600',
        text: 'text-yellow-700',
        side: 'border-l-yellow-500'
      };
    }
    if (delivery.type === DeliveryType.PICKUP) {
      return {
        border: 'border-red-100',
        bg: 'bg-red-50/40',
        accent: 'bg-red-600',
        text: 'text-red-700',
        side: 'border-l-red-500'
      };
    }
    return {
      border: 'border-blue-100',
      bg: 'bg-blue-50/40',
      accent: 'bg-blue-600',
      text: 'text-blue-700',
      side: 'border-l-blue-500'
    };
  };

  const styles = getStyles();

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  const currentDragIndex = typeof index === 'number' ? index : 0;

  return (
    <div 
      draggable={!isCompleted && !isIssue}
      onDragStart={(e) => !isCompleted && !isIssue && onDragStart(e, currentDragIndex)}
      onDragOver={(e) => !isCompleted && !isIssue && onDragOver(e, currentDragIndex)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 border-l-[6px] transition-all cursor-pointer group shadow-sm hover:shadow-md ${
        isSelected ? 'ring-2 ring-blue-500 ring-offset-1' : ''
      } ${styles.border} ${styles.bg} ${styles.side}`}
    >
      {!isCompleted && !isIssue && (
        <div className="absolute left-[-2px] top-1/2 -translate-y-1/2 text-white/80 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <GripVertical size={14} />
        </div>
      )}

      <div className="pl-4 pr-3 py-3">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3 overflow-hidden">
            {typeof index === 'number' && !isCompleted && !isIssue && (
              <span className="shrink-0 w-6 h-6 flex items-center justify-center bg-blue-600 text-white text-[10px] font-bold rounded-full shadow-sm">
                {index + 1}
              </span>
            )}
            <div className="flex flex-col min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${
                  isCompleted ? 'bg-green-100 text-green-600' : 
                  (isIssue ? 'bg-yellow-100 text-yellow-700' : 
                  (delivery.type === DeliveryType.PICKUP ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'))
                }`}>
                  {isIssue ? <AlertTriangle size={10} /> : (delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />)}
                  {isIssue ? 'INCIDENCIA' : (delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA')}
                </span>
              </div>
              <div className="flex items-center gap-1 text-[11px] text-slate-500 mt-0.5">
                <MapPin size={12} className="shrink-0" />
                <p className="truncate opacity-80">{delivery.address}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0 ml-2">
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-white transition-all"
            >
              <Trash2 size={16} />
            </button>
            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white transition-all"
            >
              {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-slate-200/50 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-4">
              <div className="flex flex-wrap gap-3">
                {delivery.phone && (
                  <a 
                    href={`tel:${delivery.phone}`}
                    onClick={(e) => e.stopPropagation()}
                    className="flex items-center gap-2 px-3 py-2 bg-blue-50 text-blue-600 rounded-xl text-xs font-bold border border-blue-100 hover:bg-blue-100 transition-colors"
                  >
                    <Phone size={14} /> {delivery.phone}
                  </a>
                )}
                {delivery.sourceUrl && (
                  <a 
                    href={delivery.sourceUrl} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    onClick={(e) => e.stopPropagation()} 
                    className="flex items-center gap-2 px-3 py-2 bg-slate-50 text-slate-600 rounded-xl text-xs font-bold border border-slate-200 hover:bg-slate-100 transition-colors"
                  >
                    <ExternalLink size={14} /> Google Maps
                  </a>
                )}
              </div>

              {delivery.notes && (
                <div className="bg-white/60 p-2.5 rounded-lg text-[11px] text-slate-600 border border-slate-100">
                  <span className="font-bold text-slate-400 uppercase text-[9px] block mb-1">Notas:</span>
                  {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex flex-wrap gap-2">
                  {!isCompleted && !isIssue ? (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-green-600 text-white hover:bg-green-700 text-xs font-bold transition-all shadow-sm shadow-green-100"
                      >
                        <CheckCircle size={14} /> Entregado
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.ISSUE); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-yellow-500 text-white hover:bg-yellow-600 text-xs font-bold transition-all shadow-sm shadow-yellow-100"
                      >
                        <AlertTriangle size={14} /> Incidencia
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                        className={`flex items-center gap-1.5 px-4 py-2 rounded-xl bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-xs font-bold transition-all ${delivery.status === DeliveryStatus.IN_PROGRESS ? 'border-blue-500 text-blue-600' : ''}`}
                      >
                        <Navigation size={14} /> {delivery.status === DeliveryStatus.IN_PROGRESS ? 'En Camino' : 'Ir ahora'}
                      </button>
                    </>
                  ) : (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-xs font-bold text-slate-400 hover:text-slate-600 underline underline-offset-4"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="text-[11px] text-slate-400 flex items-center gap-1 font-medium ml-auto">
                  <Clock size={12} /> {delivery.estimatedTime || '--:--'}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  manualSequence: string[];
  selectedId: string | null;
  onMarkerClick: (id: string) => void;
  viewMode: string;
}

const MapView: React.FC<MapViewProps> = ({ deliveries, manualSequence, selectedId, onMarkerClick, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});
  const polylineRef = useRef<L.Polyline | null>(null);

  useEffect(() => {
    if (!mapRef.current) {
      const mapContainer = document.getElementById('map-container');
      if (!mapContainer) return;

      mapRef.current = L.map('map-container', {
        zoomControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }
  }, []);

  useEffect(() => {
    if (mapRef.current) {
      const timer = setTimeout(() => {
        try {
          mapRef.current?.invalidateSize({ animate: true });
        } catch (e) {
          console.warn("Invalidate size failed", e);
        }
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Remove existing markers
    (Object.values(markersRef.current) as L.Marker[]).forEach(m => {
      try {
        m.remove();
      } catch (e) {
        console.warn("Error removing marker", e);
      }
    });
    markersRef.current = {};

    // Remove existing polyline
    if (polylineRef.current) {
      polylineRef.current.remove();
      polylineRef.current = null;
    }

    const validDeliveries = deliveries.filter(d => 
      Array.isArray(d.coordinates) && 
      d.coordinates.length === 2 && 
      !isNaN(d.coordinates[0]) && 
      !isNaN(d.coordinates[1])
    );

    // Draw route path based on manualSequence
    if (manualSequence.length >= 2) {
      const routePoints = manualSequence
        .map(id => validDeliveries.find(d => d.id === id)?.coordinates)
        .filter((coords): coords is [number, number] => !!coords);

      if (routePoints.length >= 2) {
        polylineRef.current = L.polyline(routePoints, {
          color: '#3b82f6',
          weight: 4,
          opacity: 0.6,
          dashArray: '10, 10',
          lineJoin: 'round'
        }).addTo(map);
      }
    }

    validDeliveries.forEach((delivery) => {
      // Color logic
      let color = '#3b82f6'; // Blue (delivery)
      if (delivery.status === DeliveryStatus.COMPLETED) {
        color = '#10b981'; // Green
      } else if (delivery.status === DeliveryStatus.ISSUE) {
        color = '#eab308'; // Yellow
      } else if (delivery.type === DeliveryType.PICKUP) {
        color = '#ef4444'; // Red
      }

      const isSelected = selectedId === delivery.id;
      const sequenceIndex = manualSequence.indexOf(delivery.id);
      const isOrdered = sequenceIndex !== -1;

      const size = isSelected ? 30 : (isOrdered ? 26 : 20);
      const borderSize = isSelected ? '4px' : '3px';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div style="
            background-color: ${color}; 
            width: ${size}px; 
            height: ${size}px; 
            border-radius: 50%; 
            border: ${borderSize} solid white; 
            box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); 
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 10px;
            font-weight: 800;
            transition: all 0.3s ease;
          ">
            ${isOrdered && delivery.status !== DeliveryStatus.COMPLETED ? sequenceIndex + 1 : ''}
            ${delivery.status === DeliveryStatus.COMPLETED ? '✓' : ''}
          </div>
        `,
        iconSize: [size, size],
        iconAnchor: [size/2, size/2]
      });

      try {
        const marker = L.marker(delivery.coordinates, { icon, zIndexOffset: isSelected ? 1000 : 0 })
          .addTo(map)
          .on('click', () => onMarkerClick(delivery.id));

        // Add popup
        const popupContent = document.createElement('div');
        popupContent.className = 'p-2 min-w-[120px]';
        popupContent.innerHTML = `
          <div class="font-bold text-sm mb-1">${delivery.recipient}</div>
          <div class="text-[10px] text-slate-500 truncate max-w-[140px]">${delivery.address}</div>
        `;

        marker.bindPopup(popupContent, { offset: [0, -size/2] });
        markersRef.current[delivery.id] = marker;
      } catch (e) {
        console.error("Error creating marker", e);
      }
    });

    if (validDeliveries.length > 0 && viewMode !== 'list') {
      try {
        const bounds = L.latLngBounds(validDeliveries.map(d => d.coordinates));
        map.fitBounds(bounds, { padding: [80, 80], maxZoom: 16 });
      } catch (e) {
        console.warn("Could not fit bounds", e);
      }
    }
  }, [deliveries, manualSequence, onMarkerClick, viewMode, selectedId]);

  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      try {
        const marker = markersRef.current[selectedId];
        mapRef.current.flyTo(marker.getLatLng(), 16, {
          duration: 1
        });
        marker.openPopup();
      } catch (e) {
        console.warn("FlyTo failed", e);
      }
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
      style={{ minHeight: '300px' }}
    ></div>
  );
};

export default MapView;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
  }, [manualSequence]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    setManualSequence(prev => prev.filter(sid => sid !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleRemoveFromSequence = (id: string) => {
    setManualSequence(prev => prev.filter(sid => sid !== id));
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(SEQUENCE_KEY);
      window.location.reload();
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery || delivery.status === DeliveryStatus.COMPLETED) return;

    // Si no está en la secuencia, lo añadimos al final
    if (!manualSequence.includes(id)) {
      setManualSequence(prev => [...prev, id]);
    }
  };

  const resetSequence = () => {
    setManualSequence([]);
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        setManualSequence(result.optimizedOrder);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pendingSorted = getSortedPending();
      const newList = [...pendingSorted];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setManualSequence(newList.map(d => d.id));
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);

    // Primero los que tienen orden manual
    const ordered = manualSequence
      .map(id => pending.find(p => p.id === id))
      .filter((p): p is Delivery => !!p);

    // Luego los que no están en la secuencia
    const unordered = pending.filter(p => !manualSequence.includes(p.id));

    return [...ordered, ...unordered];
  };

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const asideClasses = viewMode === 'map' ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = viewMode === 'list' ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <div className="flex items-center gap-2">
              {manualSequence.length > 0 && (
                <button onClick={resetSequence} className="p-1.5 text-slate-400 hover:text-slate-600 transition-colors" title="Reiniciar orden">
                  <RotateCcw size={16} />
                </button>
              )}
              <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
                {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
                AUTO-RUTEAR
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => {
                  const seqIdx = manualSequence.indexOf(delivery.id);
                  return (
                    <DeliveryCard 
                      key={delivery.id} 
                      index={seqIdx !== -1 ? seqIdx : undefined} 
                      delivery={delivery} 
                      isSelected={selectedId === delivery.id} 
                      onClick={() => setSelectedId(delivery.id)} 
                      onStatusChange={handleStatusChange} 
                      onDelete={handleDeleteDelivery} 
                      onRemoveFromSequence={handleRemoveFromSequence}
                      onDragStart={onDragStart} 
                      onDragOver={onDragOver} 
                      onDragEnd={onDragEnd} 
                    />
                  );
                })
              )}
            </div>

            {issueDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-yellow-600 uppercase tracking-widest px-1">
                  <AlertTriangle size={12} />
                  <span>Incidencias ({issueDeliveries.length})</span>
                </div>
                {issueDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onRemoveFromSequence={handleRemoveFromSequence}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={12} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery, index) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    onClick={() => setSelectedId(delivery.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onRemoveFromSequence={handleRemoveFromSequence}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${sectionClasses} relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            manualSequence={manualSequence}
            selectedId={selectedId} 
            onMarkerClick={handleMarkerClick} 
            viewMode={viewMode} 
          />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-28 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all resize-none text-sm" 
                    placeholder="Dirección o datos del paquete (Ej: Calle Mayor 1, Madrid)..." 
                    required 
                  />
                </div>

                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Phone size={18} />
                  </div>
                  <input 
                    type="tel"
                    value={newPhoneInput}
                    onChange={(e) => setNewPhoneInput(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                    placeholder="Teléfono de contacto (opcional)"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || !newAddressInput.trim()} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
                  <span className="text-sm">Añadir Parada</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';
import { CheckCircle, Clock, MapPin, Navigation, ExternalLink, Trash2, GripVertical, ChevronDown, ChevronUp, ArrowDownLeft, ArrowUpRight, AlertTriangle, Phone, X } from 'lucide-react';

interface DeliveryCardProps {
  delivery: Delivery;
  index?: number; // El índice representa la secuencia manual
  isSelected: boolean;
  onClick: () => void;
  onStatusChange: (id: string, status: DeliveryStatus) => void;
  onDelete: (id: string) => void;
  onRemoveFromSequence: (id: string) => void;
  onDragStart: (e: React.DragEvent, index: number) => void;
  onDragOver: (e: React.DragEvent, index: number) => void;
  onDragEnd: (e: React.DragEvent) => void;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ 
  delivery, 
  index, 
  isSelected, 
  onClick, 
  onStatusChange, 
  onDelete,
  onRemoveFromSequence,
  onDragStart,
  onDragOver,
  onDragEnd
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isCompleted = delivery.status === DeliveryStatus.COMPLETED;
  const isIssue = delivery.status === DeliveryStatus.ISSUE;

  const getStyles = () => {
    if (isCompleted) {
      return {
        border: 'border-green-200',
        bg: 'bg-green-50/30',
        accent: 'bg-green-600',
        text: 'text-green-700',
        side: 'border-l-green-500'
      };
    }
    if (isIssue) {
      return {
        border: 'border-yellow-200',
        bg: 'bg-yellow-50/40',
        accent: 'bg-yellow-600',
        text: 'text-yellow-700',
        side: 'border-l-yellow-500'
      };
    }
    if (delivery.type === DeliveryType.PICKUP) {
      return {
        border: 'border-red-100',
        bg: 'bg-red-50/40',
        accent: 'bg-red-600',
        text: 'text-red-700',
        side: 'border-l-red-500'
      };
    }
    return {
      border: 'border-blue-100',
      bg: 'bg-blue-50/40',
      accent: 'bg-blue-600',
      text: 'text-blue-700',
      side: 'border-l-blue-500'
    };
  };

  const styles = getStyles();

  const toggleExpand = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExpanded(!isExpanded);
  };

  const handleClearSequence = (e: React.MouseEvent) => {
    e.stopPropagation();
    onRemoveFromSequence(delivery.id);
  };

  const currentDragIndex = typeof index === 'number' ? index : 0;

  return (
    <div 
      draggable={!isCompleted && !isIssue}
      onDragStart={(e) => !isCompleted && !isIssue && onDragStart(e, currentDragIndex)}
      onDragOver={(e) => !isCompleted && !isIssue && onDragOver(e, currentDragIndex)}
      onDragEnd={onDragEnd}
      onClick={onClick}
      className={`relative mb-3 rounded-xl border-2 border-l-[6px] transition-all cursor-pointer group shadow-sm hover:shadow-md ${
        isSelected ? 'ring-2 ring-blue-500 ring-offset-1' : ''
      } ${styles.border} ${styles.bg} ${styles.side}`}
    >
      {!isCompleted && !isIssue && (
        <div className="absolute left-[-2px] top-1/2 -translate-y-1/2 text-white/80 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <GripVertical size={14} />
        </div>
      )}

      <div className="pl-4 pr-3 py-3">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3 overflow-hidden">
            {typeof index === 'number' && !isCompleted && !isIssue && (
              <div className="relative group/seq shrink-0">
                <span className="w-6 h-6 flex items-center justify-center bg-blue-600 text-white text-[10px] font-bold rounded-full shadow-sm">
                  {index + 1}
                </span>
                <button 
                  onClick={handleClearSequence}
                  className="absolute -top-1 -right-1 bg-white text-slate-400 border border-slate-200 rounded-full p-0.5 opacity-0 group-hover/seq:opacity-100 transition-opacity shadow-sm hover:text-red-500 hover:border-red-100"
                  title="Quitar de la ruta manual"
                >
                  <X size={8} />
                </button>
              </div>
            )}
            <div className="flex flex-col min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h3 className="font-bold truncate text-sm md:text-base text-slate-800">
                  {delivery.recipient}
                </h3>
                <span className={`text-[9px] font-black px-1.5 py-0.5 rounded flex items-center gap-1 uppercase tracking-tighter ${
                  isCompleted ? 'bg-green-100 text-green-600' : 
                  (isIssue ? 'bg-yellow-100 text-yellow-700' : 
                  (delivery.type === DeliveryType.PICKUP ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'))
                }`}>
                  {isIssue ? <AlertTriangle size={10} /> : (delivery.type === DeliveryType.DELIVERY ? <ArrowDownLeft size={10} /> : <ArrowUpRight size={10} />)}
                  {isIssue ? 'INCIDENCIA' : (delivery.type === DeliveryType.DELIVERY ? 'ENTREGA' : 'RECOGIDA')}
                </span>
              </div>
              <div className="flex items-center gap-1 text-[11px] text-slate-500 mt-0.5">
                <MapPin size={12} className="shrink-0" />
                <p className="truncate opacity-80">{delivery.address}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-1 shrink-0 ml-2">
            <button 
              type="button"
              onMouseDown={(e) => e.stopPropagation()}
              onClick={(e) => { e.stopPropagation(); onDelete(delivery.id); }}
              className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-white transition-all"
            >
              <Trash2 size={16} />
            </button>
            <button 
              type="button"
              onClick={toggleExpand}
              className="p-1.5 rounded-lg text-slate-400 hover:bg-white transition-all"
            >
              {isExpanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-3 pt-3 border-t border-slate-200/50 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-4">
              <div className="flex flex-wrap gap-3">
                {delivery.phone && (
                  <a 
                    href={`tel:${delivery.phone}`}
                    onClick={(e) => e.stopPropagation()}
                    className="flex items-center gap-2 px-3 py-2 bg-blue-50 text-blue-600 rounded-xl text-xs font-bold border border-blue-100 hover:bg-blue-100 transition-colors"
                  >
                    <Phone size={14} /> {delivery.phone}
                  </a>
                )}
                {delivery.sourceUrl && (
                  <a 
                    href={delivery.sourceUrl} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    onClick={(e) => e.stopPropagation()} 
                    className="flex items-center gap-2 px-3 py-2 bg-slate-50 text-slate-600 rounded-xl text-xs font-bold border border-slate-200 hover:bg-slate-100 transition-colors"
                  >
                    <ExternalLink size={14} /> Google Maps
                  </a>
                )}
              </div>

              {delivery.notes && (
                <div className="bg-white/60 p-2.5 rounded-lg text-[11px] text-slate-600 border border-slate-100">
                  <span className="font-bold text-slate-400 uppercase text-[9px] block mb-1">Notas:</span>
                  {delivery.notes}
                </div>
              )}

              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex flex-wrap gap-2">
                  {!isCompleted && !isIssue ? (
                    <>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.COMPLETED); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-green-600 text-white hover:bg-green-700 text-xs font-bold transition-all shadow-sm shadow-green-100"
                      >
                        <CheckCircle size={14} /> Entregado
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.ISSUE); }}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-yellow-500 text-white hover:bg-yellow-600 text-xs font-bold transition-all shadow-sm shadow-yellow-100"
                      >
                        <AlertTriangle size={14} /> Incidencia
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.IN_PROGRESS); }}
                        className={`flex items-center gap-1.5 px-4 py-2 rounded-xl bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 text-xs font-bold transition-all ${delivery.status === DeliveryStatus.IN_PROGRESS ? 'border-blue-500 text-blue-600' : ''}`}
                      >
                        <Navigation size={14} /> {delivery.status === DeliveryStatus.IN_PROGRESS ? 'En Camino' : 'Ir ahora'}
                      </button>
                    </>
                  ) : (
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onStatusChange(delivery.id, DeliveryStatus.PENDING); }}
                      className="text-xs font-bold text-slate-400 hover:text-slate-600 underline underline-offset-4"
                    >
                      Reabrir tarea
                    </button>
                  )}
                </div>

                <div className="text-[11px] text-slate-400 flex items-center gap-1 font-medium ml-auto">
                  <Clock size={12} /> {delivery.estimatedTime || '--:--'}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryCard;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Search, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        recipient: 'Juan Pérez',
        address: 'Calle de la Princesa, 1, 28008 Madrid, Spain',
        coordinates: [40.4241, -3.7126],
        status: DeliveryStatus.PENDING,
        type: DeliveryType.DELIVERY,
        estimatedTime: '09:30 AM'
      }
    ];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
  }, [manualSequence]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation permission denied", err)
      );
    }
  }, []);

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error(error);
      alert("No pudimos ubicar esa dirección. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    setManualSequence(prev => prev.filter(sid => sid !== id));
    if (selectedId === id) setSelectedId(null);
    if (expandedId === id) setExpandedId(null);
  };

  const handleRemoveFromSequence = (id: string) => {
    setManualSequence(prev => prev.filter(sid => sid !== id));
  };

  const handleLogout = () => {
    if (window.confirm("¿Borrar todos los datos de la ruta actual?")) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(SEQUENCE_KEY);
      window.location.reload();
    }
  };

  const handleMarkerClick = (id: string, forceExpand: boolean = false) => {
    setSelectedId(id);
    if (forceExpand) {
      setExpandedId(id);
    }

    const delivery = deliveries.find(d => d.id === id);
    if (!delivery || delivery.status === DeliveryStatus.COMPLETED) return;

    // Si no está en la secuencia, lo añadimos al final
    if (!manualSequence.includes(id)) {
      setManualSequence(prev => [...prev, id]);
    }
  };

  const resetSequence = () => {
    setManualSequence([]);
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        setManualSequence(result.optimizedOrder);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pendingSorted = getSortedPending();
      const newList = [...pendingSorted];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setManualSequence(newList.map(d => d.id));
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);

    // Primero los que tienen orden manual
    const ordered = manualSequence
      .map(id => pending.find(p => p.id === id))
      .filter((p): p is Delivery => !!p);

    // Luego los que no están en la secuencia
    const unordered = pending.filter(p => !manualSequence.includes(p.id));

    return [...ordered, ...unordered];
  };

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const asideClasses = viewMode === 'map' ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = viewMode === 'list' ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
            <LogOut size={20} />
          </button>
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <div className="flex items-center gap-2">
              {manualSequence.length > 0 && (
                <button onClick={resetSequence} className="p-1.5 text-slate-400 hover:text-slate-600 transition-colors" title="Reiniciar orden">
                  <RotateCcw size={16} />
                </button>
              )}
              <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
                {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
                AUTO-RUTEAR
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery, index) => {
                  const seqIdx = manualSequence.indexOf(delivery.id);
                  return (
                    <DeliveryCard 
                      key={delivery.id} 
