import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimize this delivery route. Starting from ${startLocation}, sequence these deliveries logically to minimize travel time and distance. Return the optimized order of IDs.
      Deliveries: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "List of delivery IDs in optimized order"
            },
            reasoning: {
              type: Type.STRING,
              description: "Brief explanation of the optimization logic"
            }
          },
          required: ["optimizedOrder"]
        }
      }
    });

    const text = response.text?.trim() || '{}';
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to optimize route", e);
    return { optimizedOrder: deliveries.map(d => d.id), reasoning: "Fallback order due to API error" };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualCoords?: string) => {
  const coordHint = manualCoords 
    ? `\nCAMPO COORDENADAS/LINK: "${manualCoords}". 
       ATENCIÓN: Si este campo contiene un enlace de Google Maps o coordenadas (ej: 40.41, -3.70), extrae la ubicación exacta. 
       ESTA INFORMACIÓN TIENE PRIORIDAD ABSOLUTA.` 
    : "";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Eres un experto en geolocalización. Procesa estos datos:
      TEXTO: "${input}"
      ${coordHint}

      Instrucciones:
      1. Extrae RECIPIENT, ADDRESS, PHONE, LAT, LNG y NOTES.
      2. Si hay coordenadas manuales o link, úsalos como LAT y LNG definitivos.
      3. Formatea LAT y LNG siempre como números decimales.

      Formato EXACTO:
      RECIPIENT: [Nombre]
      ADDRESS: [Dirección]
      PHONE: [Teléfono]
      LAT: [Número]
      LNG: [Número]
      NOTES: [Notas]`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: userLocation ? {
          retrievalConfig: {
            latLng: {
              latitude: userLocation.latitude,
              longitude: userLocation.longitude
            }
          }
        } : undefined
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    // Regex mejorado para aceptar enteros y decimales
    const recipientMatch = text.match(/RECIPIENT:\s*(.*)/i);
    const addressMatch = text.match(/ADDRESS:\s*(.*)/i);
    const phoneMatch = text.match(/PHONE:\s*(.*)/i);
    const latMatch = text.match(/LAT:\s*(-?\d+(?:\.\d+)?)/i);
    const lngMatch = text.match(/LNG:\s*(-?\d+(?:\.\d+)?)/i);
    const notesMatch = text.match(/NOTES:\s*(.*)/i);

    let sourceUrl = manualCoords?.includes('http') ? manualCoords : "";

    // Validar que sean números y no NaN
    const parsedLat = latMatch ? parseFloat(latMatch[1]) : NaN;
    const parsedLng = lngMatch ? parseFloat(lngMatch[1]) : NaN;

    let finalLat = !isNaN(parsedLat) ? parsedLat : (userLocation?.latitude || 40.4168);
    let finalLng = !isNaN(parsedLng) ? parsedLng : (userLocation?.longitude || -3.7038);

    if (groundingChunks && !sourceUrl) {
      const mapChunk = groundingChunks.find((chunk: any) => chunk.maps?.uri);
      if (mapChunk) sourceUrl = mapChunk.maps.uri;
    }

    return {
      recipient: recipientMatch ? recipientMatch[1].trim() : "Cliente",
      address: addressMatch ? addressMatch[1].trim() : (input || "Dirección desconocida"),
      phone: phoneMatch ? phoneMatch[1].trim() : "",
      lat: finalLat,
      lng: finalLng,
      notes: notesMatch ? notesMatch[1].trim() : "",
      sourceUrl
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback seguro para evitar fallos de la app
    return {
      recipient: "Cliente",
      address: input || "Dirección manual",
      phone: "",
      lat: userLocation?.latitude || 40.4168,
      lng: userLocation?.longitude || -3.7038,
      notes: "Error en procesamiento automático",
      sourceUrl: ""
    };
  }
};

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { Delivery, DeliveryStatus, DeliveryType } from '../types';

interface MapViewProps {
  deliveries: Delivery[];
  manualSequence: string[];
  selectedId: string | null;
  onMarkerClick: (id: string, forceExpand?: boolean) => void;
  viewMode: string;
}

const MapView: React.FC<MapViewProps> = ({ deliveries, manualSequence, selectedId, onMarkerClick, viewMode }) => {
  const mapRef = useRef<L.Map | null>(null);
  const markersRef = useRef<{ [key: string]: L.Marker }>({});
  const polylineRef = useRef<L.Polyline | null>(null);
  const pressTimerRef = useRef<number | null>(null);

  useEffect(() => {
    if (!mapRef.current) {
      const mapContainer = document.getElementById('map-container');
      if (!mapContainer) return;

      mapRef.current = L.map('map-container', {
        zoomControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([40.4168, -3.7126], 13);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }
  }, []);

  useEffect(() => {
    if (mapRef.current) {
      const timer = setTimeout(() => {
        try {
          mapRef.current?.invalidateSize({ animate: true });
        } catch (e) {
          console.warn("Invalidate size failed", e);
        }
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // Limpieza de marcadores existentes
    Object.values(markersRef.current).forEach(m => {
      try {
        if (m) m.remove();
      } catch (e) {
        console.warn("Error removing marker", e);
      }
    });
    markersRef.current = {};

    if (polylineRef.current) {
      polylineRef.current.remove();
      polylineRef.current = null;
    }

    // Validación estricta de coordenadas para evitar LatLng(NaN, NaN)
    const validDeliveries = deliveries.filter(d => 
      Array.isArray(d.coordinates) && 
      d.coordinates.length === 2 && 
      typeof d.coordinates[0] === 'number' && 
      typeof d.coordinates[1] === 'number' &&
      !isNaN(d.coordinates[0]) && 
      !isNaN(d.coordinates[1])
    );

    if (manualSequence.length >= 2) {
      const routePoints = manualSequence
        .map(id => validDeliveries.find(d => d.id === id)?.coordinates)
        .filter((coords): coords is [number, number] => !!coords);

      if (routePoints.length >= 2) {
        polylineRef.current = L.polyline(routePoints, {
          color: '#3b82f6',
          weight: 4,
          opacity: 0.6,
          dashArray: '10, 10',
          lineJoin: 'round'
        }).addTo(map);
      }
    }

    validDeliveries.forEach((delivery) => {
      let color = '#3b82f6';
      if (delivery.status === DeliveryStatus.COMPLETED) color = '#10b981';
      else if (delivery.status === DeliveryStatus.ISSUE) color = '#eab308';
      else if (delivery.type === DeliveryType.PICKUP) color = '#ef4444';

      const isSelected = selectedId === delivery.id;
      const sequenceIndex = manualSequence.indexOf(delivery.id);
      const isOrdered = sequenceIndex !== -1;

      const size = isSelected ? 30 : (isOrdered ? 26 : 20);
      const borderSize = isSelected ? '4px' : '3px';

      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div style="
            background-color: ${color}; 
            width: ${size}px; 
            height: ${size}px; 
            border-radius: 50%; 
            border: ${borderSize} solid white; 
            box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); 
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 10px;
            font-weight: 800;
            transition: all 0.3s ease;
          ">
            ${isOrdered && delivery.status !== DeliveryStatus.COMPLETED ? sequenceIndex + 1 : ''}
            ${delivery.status === DeliveryStatus.COMPLETED ? '✓' : ''}
          </div>
        `,
        iconSize: [size, size],
        iconAnchor: [size/2, size/2]
      });

      try {
        const marker = L.marker(delivery.coordinates, { icon, zIndexOffset: isSelected ? 1000 : 0 })
          .addTo(map);

        const handleDown = () => {
          pressTimerRef.current = window.setTimeout(() => {
            pressTimerRef.current = -1;
          }, 500);
        };

        const handleUp = () => {
          if (pressTimerRef.current === -1) {
            onMarkerClick(delivery.id, true);
          } else if (pressTimerRef.current !== null) {
            onMarkerClick(delivery.id, false);
          }
          if (pressTimerRef.current && pressTimerRef.current !== -1) clearTimeout(pressTimerRef.current);
          pressTimerRef.current = null;
        };

        marker.on('mousedown', handleDown);
        marker.on('mouseup', handleUp);
        marker.on('touchstart', handleDown);
        marker.on('touchend', (e: any) => {
          if (e.originalEvent) e.originalEvent.preventDefault();
          handleUp();
        });

        const popupContent = document.createElement('div');
        popupContent.className = 'p-2 min-w-[120px]';
        popupContent.innerHTML = `
          <div class="font-bold text-sm mb-1">${delivery.recipient}</div>
          <div class="text-[10px] text-slate-500 truncate max-w-[140px]">${delivery.address}</div>
        `;

        marker.bindPopup(popupContent, { offset: [0, -size/2] });
        markersRef.current[delivery.id] = marker;
      } catch (e) {
        console.error("Error creating marker", e);
      }
    });

    if (validDeliveries.length > 0 && viewMode !== 'list') {
      try {
        const bounds = L.latLngBounds(validDeliveries.map(d => d.coordinates));
        map.fitBounds(bounds, { padding: [80, 80], maxZoom: 16 });
      } catch (e) {
        console.warn("Could not fit bounds", e);
      }
    }
  }, [deliveries, manualSequence, onMarkerClick, viewMode, selectedId]);

  useEffect(() => {
    if (selectedId && markersRef.current[selectedId] && mapRef.current) {
      try {
        const marker = markersRef.current[selectedId];
        mapRef.current.flyTo(marker.getLatLng(), 16, {
          duration: 1
        });
        marker.openPopup();
      } catch (e) {
        console.warn("FlyTo failed", e);
      }
    }
  }, [selectedId]);

  return (
    <div 
      id="map-container" 
      className="h-full w-full bg-slate-100"
      style={{ minHeight: '300px' }}
    ></div>
  );
};

