import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Link as LinkIcon } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved && ['split', 'map', 'list', 'control'].includes(saved)) return saved as any;
    return window.innerWidth < 768 ? 'split' : 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
  }, [manualSequence]);

  useEffect(() => {
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          if (!isNaN(pos.coords.latitude) && !isNaN(pos.coords.longitude)) {
            setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude });
          }
        },
        (err) => console.warn("Geolocation permission denied", err)
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'es-ES';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => (prev ? `${prev} ${transcript}` : transcript));
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc, newCoordsInput);

      const finalLat = (typeof parsed.lat === 'number' && !isNaN(parsed.lat)) ? parsed.lat : 40.4168;
      const finalLng = (typeof parsed.lng === 'number' && !isNaN(parsed.lng)) ? parsed.lng : -3.7038;
      const fallbackUrl = `https://maps.google.com/?q=${finalLat},${finalLng}`;

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [finalLat, finalLng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl || fallbackUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error("Add delivery error:", error);
      alert("Hubo un problema al procesar la parada. Inténtalo de nuevo.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleDeleteDelivery = (id: string) => {
    setDeliveries(prev => prev.filter(d => d.id !== id));
    setManualSequence(prev => prev.filter(sid => sid !== id));
    if (selectedId === id) setSelectedId(null);
    if (expandedId === id) setExpandedId(null);
  };

  const handleRemoveFromSequence = (id: string) => {
    setManualSequence(prev => prev.filter(sid => sid !== id));
  };

  const handleLogout = () => {
    if (window.confirm("¿Deseas cerrar la sesión? Se borrarán todos los datos.")) {
      localStorage.clear();
      setDeliveries([]);
      setManualSequence([]);
      window.location.reload();
    }
  };

  const handleMarkerClick = (id: string, forceExpand: boolean = false) => {
    setSelectedId(id);
    if (forceExpand) {
      setExpandedId(id);
    }

    const delivery = deliveries.find(d => d.id === id);
    if (!delivery || delivery.status === DeliveryStatus.COMPLETED) return;

    if (!manualSequence.includes(id)) {
      setManualSequence(prev => [...prev, id]);
    }
  };

  const resetSequence = () => {
    setManualSequence([]);
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Current Location";
      const result = await optimizeRoute(pending, startLoc);

      if (result && Array.isArray(result.optimizedOrder)) {
        setManualSequence(result.optimizedOrder);
      }
    } catch (error) {
      console.error("Optimization failed", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pendingSorted = getSortedPending();
      const newList = [...pendingSorted];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setManualSequence(newList.map(d => d.id));
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const ordered = manualSequence
      .map(id => pending.find(p => p.id === id))
      .filter((p): p is Delivery => !!p);
    const unordered = pending.filter(p => !manualSequence.includes(p.id));
    return [...ordered, ...unordered];
  };

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const countEntregas = completedDeliveries.filter(d => d.type === DeliveryType.DELIVERY).length;
  const countRecogidas = completedDeliveries.filter(d => d.type === DeliveryType.PICKUP).length;
  const countIncidencias = issueDeliveries.length;

  const asideClasses = (viewMode === 'map' || viewMode === 'control') ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = (viewMode === 'list' || viewMode === 'control') ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
          <button onClick={() => setViewMode('control')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'control' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <Settings2 size={16} />
            <span className="hidden sm:inline">CONTROL</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        {viewMode === 'control' && (
          <div className="flex-1 overflow-y-auto bg-slate-50 p-6 md:p-10 animate-in fade-in slide-in-from-bottom-4 duration-300">
            <div className="max-w-4xl mx-auto space-y-8">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-black text-slate-800 tracking-tight">PANEL DE CONTROL</h2>
                  <p className="text-slate-500 text-sm">Resumen de actividad y gestión de sesión</p>
                </div>
                <button 
                  onClick={handleLogout} 
                  className="flex items-center gap-2 px-6 py-3 bg-white border-2 border-red-100 text-red-600 rounded-2xl font-bold text-sm hover:bg-red-50 hover:border-red-200 transition-all shadow-sm active:scale-95"
                >
                  <LogOut size={18} />
                  CERRAR SESIÓN
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-green-50 text-green-600 flex items-center justify-center">
                    <Package size={24} />
                  </div>
                  <div>
                    <span className="text-4xl font-black text-slate-800">{countEntregas}</span>
                    <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Entregas Realizadas</h3>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center">
                    <Archive size={24} />
                  </div>
                  <div>
                    <span className="text-4xl font-black text-slate-800">{countRecogidas}</span>
                    <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Recogidas Realizadas</h3>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-yellow-50 text-yellow-600 flex items-center justify-center">
                    <AlertTriangle size={24} />
                  </div>
                  <div>
                    <span className="text-4xl font-black text-slate-800">{countIncidencias}</span>
                    <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Incidencias</h3>
                  </div>
                </div>
              </div>

              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                  <BarChart3 className="text-blue-600" size={20} />
                  <h3 className="font-bold text-slate-800">Eficiencia de Ruta</h3>
                </div>

                <div className="space-y-6">
                  <div>
                    <div className="flex justify-between text-xs font-bold mb-2">
                      <span className="text-slate-500 uppercase tracking-tighter">Progreso Total</span>
                      <span className="text-blue-600">{Math.round(((countEntregas + countRecogidas) / (deliveries.length || 1)) * 100)}%</span>
                    </div>
                    <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-blue-600 transition-all duration-500" 
                        style={{ width: `${((countEntregas + countRecogidas) / (deliveries.length || 1)) * 100}%` }}
                      />
                    </div>
                  </div>

                  <div className="pt-4 border-t border-slate-100 flex justify-between items-center text-sm">
                    <span className="text-slate-500">Paradas totales en sistema</span>
                    <span className="font-bold text-slate-800">{deliveries.length}</span>
                  </div>
                  <div className="flex justify-between items-center text-sm">
                    <span className="text-slate-500">Pendientes de procesar</span>
                    <span className="font-bold text-slate-800">{pendingDeliveries.length}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <aside className={`${asideClasses} flex flex-col bg-white border-r border-slate-200 overflow-hidden`}>
          <div className="p-4 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between">
            <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm">
              <Navigation size={16} className="text-blue-600" />
              Ruta Actual
            </h2>
            <div className="flex items-center gap-2">
              {manualSequence.length > 0 && (
                <button onClick={resetSequence} className="p-1.5 text-slate-400 hover:text-slate-600 transition-colors" title="Reiniciar orden">
                  <RotateCcw size={16} />
                </button>
              )}
              <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="text-[10px] flex items-center gap-1.5 font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 bg-blue-50 px-3 py-1.5 rounded-full transition-colors border border-blue-100">
                {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={12} />}
                AUTO-RUTEAR
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-6">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <Clock size={12} />
                <span>Ruta Pendiente ({pendingDeliveries.length})</span>
              </div>
              {pendingDeliveries.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-slate-200 rounded-2xl">
                  <p className="text-[10px] text-slate-400">Sin tareas pendientes</p>
                </div>
              ) : (
                pendingDeliveries.map((delivery) => {
                  const seqIdx = manualSequence.indexOf(delivery.id);
                  return (
                    <DeliveryCard 
                      key={delivery.id} 
                      index={seqIdx !== -1 ? seqIdx : undefined} 
                      delivery={delivery} 
                      isSelected={selectedId === delivery.id} 
                      forceExpanded={expandedId === delivery.id}
                      onToggleExpand={(expanded) => setExpandedId(expanded ? delivery.id : null)}
                      onClick={() => { setSelectedId(delivery.id); setExpandedId(null); }} 
                      onStatusChange={handleStatusChange} 
                      onDelete={handleDeleteDelivery} 
                      onRemoveFromSequence={handleRemoveFromSequence}
                      onDragStart={onDragStart} 
                      onDragOver={onDragOver} 
                      onDragEnd={onDragEnd} 
                    />
                  );
                })
              )}
            </div>

            {issueDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-yellow-600 uppercase tracking-widest px-1">
                  <AlertTriangle size={12} />
                  <span>Incidencias ({issueDeliveries.length})</span>
                </div>
                {issueDeliveries.map((delivery) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    forceExpanded={expandedId === delivery.id}
                    onToggleExpand={(expanded) => setExpandedId(expanded ? delivery.id : null)}
                    onClick={() => { setSelectedId(delivery.id); setExpandedId(null); }} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onRemoveFromSequence={handleRemoveFromSequence}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}

            {completedDeliveries.length > 0 && (
              <div className="space-y-3 pt-4 border-t border-slate-200">
                <div className="flex items-center gap-2 text-[10px] font-black text-green-500 uppercase tracking-widest px-1">
                  <CheckCircle2 size={12} />
                  <span>Realizadas ({completedDeliveries.length})</span>
                </div>
                {completedDeliveries.map((delivery) => (
                  <DeliveryCard 
                    key={delivery.id} 
                    delivery={delivery} 
                    isSelected={selectedId === delivery.id} 
                    forceExpanded={expandedId === delivery.id}
                    onToggleExpand={(expanded) => setExpandedId(expanded ? delivery.id : null)}
                    onClick={() => { setSelectedId(delivery.id); setExpandedId(null); }} 
                    onStatusChange={handleStatusChange} 
                    onDelete={handleDeleteDelivery} 
                    onRemoveFromSequence={handleRemoveFromSequence}
                    onDragStart={() => {}} 
                    onDragOver={() => {}} 
                    onDragEnd={() => {}} 
                  />
                ))}
              </div>
            )}
          </div>
        </aside>

        <section className={`${sectionClasses} relative z-10 overflow-hidden`}>
          <MapView 
            deliveries={deliveries} 
            manualSequence={manualSequence}
            selectedId={selectedId} 
            onMarkerClick={handleMarkerClick} 
            viewMode={viewMode} 
          />
        </section>
      </main>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h3 className="text-xl font-bold text-slate-900">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 text-slate-400 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3 p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowDownLeft size={18} /> Entrega
                </button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200'}`}>
                  <ArrowUpRight size={18} /> Recogida
                </button>
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-24 p-4 pr-14 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all resize-none text-sm" 
                    placeholder="Escribe o dicta la dirección (Ej: Calle Mayor 1, Madrid)..." 
                  />
                  <button 
                    type="button"
                    onClick={toggleListening}
                    className={`absolute right-4 top-4 p-3 rounded-xl transition-all shadow-md ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-400 hover:text-blue-600 border border-slate-200'}`}
                    title="Dictar dirección"
                  >
                    <Mic size={20} />
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                      <Phone size={18} />
                    </div>
                    <input 
                      type="tel"
                      value={newPhoneInput}
                      onChange={(e) => setNewPhoneInput(e.target.value)}
                      className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                      placeholder="Teléfono"
                    />
                  </div>
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                      <MapPin size={18} />
                    </div>
                    <input 
                      type="text"
                      value={newCoordsInput}
                      onChange={(e) => setNewCoordsInput(e.target.value)}
                      className="w-full pl-11 pr-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/5 outline-none transition-all text-sm"
                      placeholder="Coords o Link Maps"
                    />
                    {newCoordsInput.includes('http') && (
                      <div className="absolute right-3 top-1/2 -translate-y-1/2 text-blue-500">
                        <LinkIcon size={14} />
                      </div>
                    )}
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 px-1">
                  * Pega un enlace de Maps o escribe coordenadas para máxima precisión.
                </p>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 px-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-slate-50">Cancelar</button>
                <button type="submit" disabled={isParsing || (!newAddressInput.trim() && !newCoordsInput.trim())} className={`flex-1 py-4 px-4 text-white rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95 ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                  {isParsing ? <Loader2 size={20} className="animate-spin" /> : <Plus size={20} />} 
                  <span className="text-sm">Importar Parada</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es un número finito válido.
 */
const isValidCoordValue = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && isFinite(num);
};

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimize this delivery route. Starting from ${startLocation}, sequence these deliveries logically to minimize travel time and distance. Return the optimized order of IDs.
      Deliveries: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "List of delivery IDs in optimized order"
            },
            reasoning: {
              type: Type.STRING,
              description: "Brief explanation of the optimization logic"
            }
          },
          required: ["optimizedOrder"]
        }
      }
    });

    const text = response.text?.trim() || '{}';
    return JSON.parse(text);
  } catch (e: any) {
    console.warn("Optimización AI fallida (posible cuota):", e.message);
    // Fallback: mantener el orden actual si la IA falla
    return { optimizedOrder: deliveries.map(d => d.id), reasoning: "Orden manual (IA no disponible)" };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualCoords?: string) => {
  const coordHint = manualCoords 
    ? `\nCAMPO COORDENADAS/LINK: "${manualCoords}". 
       ATENCIÓN: Si este campo contiene un enlace de Google Maps o coordenadas (ej: 40.41, -3.70), extrae la ubicación exacta. 
       ESTA INFORMACIÓN TIENE PRIORIDAD ABSOLUTA.` 
    : "";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Eres un experto en geolocalización. Procesa estos datos:
      TEXTO: "${input}"
      ${coordHint}

      Instrucciones:
      1. Extrae RECIPIENT, ADDRESS, PHONE, LAT, LNG y NOTES.
      2. Si hay coordenadas manuales o link, úsalos como LAT y LNG definitivos.
      3. Formatea LAT y LNG siempre como números decimales.

      Formato EXACTO:
      RECIPIENT: [Nombre]
      ADDRESS: [Dirección]
      PHONE: [Teléfono]
      LAT: [Número]
