import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es un número finito válido.
 */
const isValidCoordValue = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && isFinite(num);
};

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Actúa como un despachador logístico de élite. Optimiza esta ruta de reparto. 
      Punto de inicio: ${startLocation}.
      Paradas: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}.
      Tu objetivo es minimizar la distancia total recorrida y optimizar el tiempo de llegada.
      Devuelve el resultado estrictamente en formato JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de IDs de entrega en el orden secuencial sugerido"
            },
            reasoning: {
              type: Type.STRING,
              description: "Explicación técnica de la optimización lograda"
            }
          },
          required: ["optimizedOrder"]
        }
      }
    });

    const text = response.text?.trim() || '{}';
    return JSON.parse(text);
  } catch (e: any) {
    console.warn("Optimización AI fallida:", e.message);
    return { optimizedOrder: deliveries.map(d => d.id), reasoning: "Orden manual (AI no disponible)" };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualCoords?: string) => {
  const userLocStr = userLocation ? `Cerca de: ${userLocation.latitude}, ${userLocation.longitude}` : "Desconocida";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Actúa como un experto en geocodificación logística profesional.
      Entrada del usuario: "${input}"
      Referencia manual (si existe): "${manualCoords || ''}"
      Ubicación del dispositivo: ${userLocStr}

      INSTRUCCIONES CRÍTICAS:
      1. Usa OBLIGATORIAMENTE la herramienta Google Maps para verificar la dirección.
      2. Si hay un enlace o coordenadas manuales, dales prioridad absoluta.
      3. Normaliza la dirección al formato oficial (Calle, Número, Ciudad, Código Postal).
      4. Si la entrada es un nombre de negocio, obtén su dirección exacta.
      5. Genera coordenadas LAT y LNG de alta precisión.

      FORMATO DE SALIDA:
      RECIPIENT: [Nombre del cliente o negocio]
      ADDRESS: [Dirección completa normalizada]
      PHONE: [Número si se detecta]
      LAT: [Decimal]
      LNG: [Decimal]
      NOTES: [Instrucciones especiales o de acceso]`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: userLocation ? {
          retrievalConfig: {
            latLng: {
              latitude: userLocation.latitude,
              longitude: userLocation.longitude
            }
          }
        } : undefined
      },
    });

    const text = response.text || "";

    const recipientMatch = text.match(/RECIPIENT:\s*(.*)/i);
    const addressMatch = text.match(/ADDRESS:\s*(.*)/i);
    const phoneMatch = text.match(/PHONE:\s*(.*)/i);
    const latMatch = text.match(/LAT:\s*(-?\d+(?:\.\d+)?)/i);
    const lngMatch = text.match(/LNG:\s*(-?\d+(?:\.\d+)?)/i);
    const notesMatch = text.match(/NOTES:\s*(.*)/i);

    const parsedLat = latMatch ? parseFloat(latMatch[1]) : NaN;
    const parsedLng = lngMatch ? parseFloat(lngMatch[1]) : NaN;

    // Fallback inteligente basado en la última ubicación conocida
    let finalLat = isValidCoordValue(parsedLat) ? parsedLat : (userLocation?.latitude || 40.4168);
    let finalLng = isValidCoordValue(parsedLng) ? parsedLng : (userLocation?.longitude || -3.7038);

    return {
      recipient: recipientMatch ? recipientMatch[1].trim() : "Cliente",
      address: addressMatch ? addressMatch[1].trim() : (input || "Ubicación manual"),
      phone: phoneMatch ? phoneMatch[1].trim() : "",
      lat: finalLat,
      lng: finalLng,
      notes: notesMatch ? notesMatch[1].trim() : "",
      sourceUrl: manualCoords?.includes('http') ? manualCoords : `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`
    };
  } catch (error: any) {
    console.error("Error en geocodificación:", error);
    const fallbackLat = userLocation?.latitude || 40.4168;
    const fallbackLng = userLocation?.longitude || -3.7038;

    return {
      recipient: "Manual",
      address: input || "Entrada directa",
      phone: "",
      lat: fallbackLat,
      lng: fallbackLng,
      notes: "Añadido sin procesamiento de IA",
      sourceUrl: manualCoords?.includes('http') ? manualCoords : ""
    };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    if (saved && ['split', 'map', 'list', 'control'].includes(saved)) return saved as any;
    return 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
  }, [deliveries, isAppClosed]);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
  }, [manualSequence, isAppClosed]);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      const geoOptions = {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      };

      const success = (pos: GeolocationPosition) => {
        setCurrentUserLoc({ 
          latitude: pos.coords.latitude, 
          longitude: pos.coords.longitude 
        });
      };

      const error = (err: GeolocationPositionError) => {
        console.warn("GPS Warning:", err.message);
      };

      // Watch position for continuous refinement
      const watchId = navigator.geolocation.watchPosition(success, error, geoOptions);
      return () => navigator.geolocation.clearWatch(watchId);
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.lang = 'es-ES';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => (prev ? `${prev} ${transcript}` : transcript));
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc, newCoordsInput);

      const finalLat = (typeof parsed.lat === 'number' && !isNaN(parsed.lat)) ? parsed.lat : (currentUserLoc?.latitude || 40.4168);
      const finalLng = (typeof parsed.lng === 'number' && !isNaN(parsed.lng)) ? parsed.lng : (currentUserLoc?.longitude || -3.7038);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient,
        address: parsed.address,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [finalLat, finalLng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes,
        sourceUrl: parsed.sourceUrl,
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error) {
      console.error("Error AI:", error);
    } finally {
      setIsParsing(false);
    }
  };

  const handleLogout = () => {
    if (window.confirm("¿FINALIZAR SESIÓN? Se borrarán todos los datos de la ruta actual y se cerrará la aplicación.")) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem(SEQUENCE_KEY);
      localStorage.removeItem(VIEW_MODE_KEY);
      setDeliveries([]);
      setManualSequence([]);
      setIsAppClosed(true);
    }
  };

  const handleRestart = () => {
    setIsAppClosed(false);
    window.location.reload();
  };

  const resetSequence = () => {
    if (window.confirm("¿Reiniciar orden de ruta?")) {
      setManualSequence([]);
    }
  };

  const handleMarkerClick = (id: string, forceExpand: boolean = false) => {
    setSelectedId(id);
    if (forceExpand) setExpandedId(id);

    const delivery = deliveries.find(d => d.id === id);
    if (!delivery || delivery.status === DeliveryStatus.COMPLETED) return;

    if (!manualSequence.includes(id)) {
      setManualSequence(prev => [...prev, id]);
    }
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const startLoc = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Ubicación actual";
      const result = await optimizeRoute(pending, startLoc);
      if (result && Array.isArray(result.optimizedOrder)) {
        setManualSequence(result.optimizedOrder);
      }
    } catch (error) {
      console.error("Optimización fallida", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    dragOverItem.current = index;
  };

  const onDragEnd = (e: React.DragEvent) => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const pendingSorted = getSortedPending();
      const newList = [...pendingSorted];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      setManualSequence(newList.map(d => d.id));
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const ordered = manualSequence
      .map(id => pending.find(p => p.id === id))
      .filter((p): p is Delivery => !!p);
    const unordered = pending.filter(p => !manualSequence.includes(p.id));
    return [...ordered, ...unordered];
  };

  const handleRemoveFromSequence = (id: string) => {
    setManualSequence(prev => prev.filter(sid => sid !== id));
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <div className="bg-white/10 p-6 rounded-full mb-8 animate-pulse">
          <Power size={64} className="text-white" />
        </div>
        <h1 className="text-4xl font-black text-white mb-4">SESIÓN FINALIZADA</h1>
        <p className="text-slate-400 max-w-md mb-10 text-lg">
          Todos los datos de la ruta han sido eliminados de forma segura. La aplicación se ha detenido correctamente.
        </p>
        <button 
          onClick={handleRestart}
          className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-4 rounded-2xl font-black text-lg flex items-center gap-3 shadow-2xl transition-all active:scale-95"
        >
          <RefreshCcw size={24} />
          REINICIAR APLICACIÓN
        </button>
      </div>
    );
  }

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const countEntregas = completedDeliveries.filter(d => d.type === DeliveryType.DELIVERY).length;
  const countRecogidas = completedDeliveries.filter(d => d.type === DeliveryType.PICKUP).length;
  const countIncidencias = issueDeliveries.length;

  const asideClasses = (viewMode === 'map' || viewMode === 'control') ? 'hidden' : 
                      viewMode === 'list' ? 'flex-1 h-full' : 
                      'flex-[0.6] md:flex-none md:w-[380px] lg:w-[420px] h-full order-2 md:order-1';

  const sectionClasses = (viewMode === 'list' || viewMode === 'control') ? 'hidden' : 
                        viewMode === 'map' ? 'flex-1 h-full' : 
                        'flex-[0.4] md:flex-1 h-full order-1 md:order-2';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 px-4 md:px-6 py-3 flex items-center justify-between shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="bg-blue-600 p-1.5 md:p-2 rounded-lg text-white shadow-md">
            <Truck size={20} />
          </div>
          <h1 className="text-lg md:text-xl font-bold text-slate-900">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200">
          <button onClick={() => setViewMode('list')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <List size={16} />
            <span className="hidden sm:inline">Lista</span>
          </button>
          <button onClick={() => setViewMode('map')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <MapIcon size={16} />
            <span className="hidden sm:inline">Mapa</span>
          </button>
          <button onClick={() => setViewMode('split')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'split' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <LayoutGrid size={16} />
            <span className="hidden sm:inline">Dividida</span>
          </button>
          <button onClick={() => setViewMode('control')} className={`p-2 md:px-4 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'control' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>
            <Settings2 size={16} />
            <span className="hidden sm:inline">CONTROL</span>
          </button>
        </div>

        <div className="flex items-center gap-1 md:gap-2">
          <button onClick={() => setIsAdding(true)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 md:px-4 md:py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg active:scale-95 transition-all">
            <Plus size={20} />
            <span className="hidden md:inline text-sm">Nueva</span>
          </button>
        </div>
      </header>

      <main className={`flex-1 flex overflow-hidden relative ${viewMode === 'split' ? 'flex-col md:flex-row' : ''}`}>
        {viewMode === 'control' && (
          <div className="flex-1 overflow-y-auto bg-slate-50 p-6 md:p-10 animate-in fade-in slide-in-from-bottom-4 duration-300">
            <div className="max-w-4xl mx-auto space-y-8">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-black text-slate-800 tracking-tight uppercase">Panel Operativo</h2>
                  <p className="text-slate-500 text-sm">Resumen de actividad diaria y gestión de la sesión</p>
                </div>
                <button 
                  onClick={handleLogout} 
                  className="flex items-center gap-2 px-6 py-3 bg-red-600 text-white rounded-2xl font-bold text-sm hover:bg-red-700 transition-all shadow-lg active:scale-95"
                >
                  <LogOut size={18} />
                  BORRAR Y CERRAR
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-green-50 text-green-600 flex items-center justify-center">
                    <Package size={24} />
                  </div>
                  <div>
                    <span className="text-4xl font-black text-slate-800">{countEntregas}</span>
                    <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Entregas</h3>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center">
                    <Archive size={24} />
                  </div>
                  <div>
                    <span className="text-4xl font-black text-slate-800">{countRecogidas}</span>
                    <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Recogidas</h3>
