import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es un número finito válido.
 */
const isValidCoordValue = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && isFinite(num);
};

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Actúa como un despachador logístico de élite. Optimiza esta ruta de reparto. 
      Punto de inicio: ${startLocation}.
      Paradas: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}.
      Tu objetivo es minimizar la distancia total recorrida y optimizar el tiempo de llegada.
      Devuelve el resultado estrictamente en formato JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de IDs de entrega en el orden secuencial sugerido"
            },
            reasoning: {
              type: Type.STRING,
              description: "Explicación técnica de la optimización lograda"
            }
          },
          required: ["optimizedOrder"]
        }
      }
    });

    const text = response.text?.trim() || '{}';
    return JSON.parse(text);
  } catch (e: any) {
    console.warn("Optimización AI fallida:", e.message);
    return { optimizedOrder: deliveries.map(d => d.id), reasoning: "Orden manual (AI no disponible)" };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualCoords?: string) => {
  // Coordenadas de Elche, Comunidad Valenciana, España como anclaje por defecto si no hay GPS
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchorLoc = userLocation || elcheCoords;
  const anchorStr = `${anchorLoc.latitude}, ${anchorLoc.longitude}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Eres un experto en geocodificación logística para la zona de Elche y alrededores.
      ENTRADA DE TEXTO: "${input}"
      ENTRADA DE COORDENADAS/LINK: "${manualCoords || 'ninguna'}"
      UBICACIÓN DE REFERENCIA (ANCLAJE): ${anchorStr}

      INSTRUCCIONES DE PRIORIDAD:
      1. Si 'ENTRADA DE COORDENADAS/LINK' contiene coordenadas numéricas (ej: 38.123, -0.456) o un link de Google Maps, extrae y usa esas coordenadas EXACTAS.
      2. Si no hay coordenadas exactas, busca la dirección en 'ENTRADA DE TEXTO'.
      3. Usa OBLIGATORIAMENTE la herramienta Google Maps con sesgo hacia Elche, España.
      4. Si la dirección es ambigua, elige siempre la más cercana a Elche/Alicante.

      FORMATO DE SALIDA ESTRICTO:
      RECIPIENT: [Nombre]
      ADDRESS: [Dirección normalizada]
      PHONE: [Teléfono si existe]
      LAT: [Número decimal]
      LNG: [Número decimal]
      NOTES: [Notas relevantes]`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: anchorLoc.latitude,
              longitude: anchorLoc.longitude
            }
          }
        }
      },
    });

    const text = response.text || "";

    const recipientMatch = text.match(/RECIPIENT:\s*(.*)/i);
    const addressMatch = text.match(/ADDRESS:\s*(.*)/i);
    const phoneMatch = text.match(/PHONE:\s*(.*)/i);
    const latMatch = text.match(/LAT:\s*(-?\d+(?:\.\d+)?)/i);
    const lngMatch = text.match(/LNG:\s*(-?\d+(?:\.\d+)?)/i);
    const notesMatch = text.match(/NOTES:\s*(.*)/i);

    const parsedLat = latMatch ? parseFloat(latMatch[1]) : NaN;
    const parsedLng = lngMatch ? parseFloat(lngMatch[1]) : NaN;

    // VALIDACIÓN ESTRICTA: No permitimos NaN
    if (!isValidCoordValue(parsedLat) || !isValidCoordValue(parsedLng)) {
      throw new Error("No se pudieron obtener coordenadas válidas de la entrada.");
    }

    // Extraer URL de grounding si está disponible
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    let mapUrl = `https://www.google.com/maps/search/?api=1&query=${parsedLat},${parsedLng}`;
    if (groundingChunks) {
      const mapsChunk = groundingChunks.find(c => c.maps?.uri);
      if (mapsChunk) mapUrl = mapsChunk.maps.uri;
    }

    return {
      recipient: recipientMatch ? recipientMatch[1].trim() : "Cliente",
      address: addressMatch ? addressMatch[1].trim() : (input || "Dirección manual"),
      phone: phoneMatch ? phoneMatch[1].trim() : "",
      lat: parsedLat,
      lng: parsedLng,
      notes: notesMatch ? notesMatch[1].trim() : "",
      sourceUrl: manualCoords?.includes('http') ? manualCoords : mapUrl
    };
  } catch (error: any) {
    console.error("Error en parseAddress:", error.message);
    // Lanzamos el error para que App.tsx no cree una entrada vacía o con NaN
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw } from 'lucide-react';
