 */
export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualCoords?: string, attempt: number = 1): Promise<any> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchorLoc = userLocation || elcheCoords;
  const anchorStr = `${anchorLoc.latitude}, ${anchorLoc.longitude}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Actúa como un geocodificador experto para Elche (España).
      ENTRADA: "${input}"
      REF MANUAL: "${manualCoords || 'ninguna'}"
      UBICACIÓN ANCLA: ${anchorStr} (Elche, Alicante).

      INSTRUCCIONES:
      1. Usa la herramienta Google Maps para encontrar la ubicación exacta.
      2. Prioriza el anclaje en Elche para evitar resultados en otras provincias.
      3. Extrae obligatoriamente la Latitud y Longitud.

      FORMATO DE SALIDA (ESTRICTO):
      RECIPIENT: [Nombre/Negocio]
      ADDRESS: [Calle, Número, Elche]
      LAT: [Número]
      LNG: [Número]
      PHONE: [Teléfono o vacío]
      NOTES: [Notas]`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: anchorLoc.latitude,
              longitude: anchorLoc.longitude
            }
          }
        }
      },
    });

    const text = response.text || "";

    // Intentar extraer de la respuesta de texto
    const latMatch = text.match(/LAT:\s*(-?\d+(?:\.\d+)?)/i);
    const lngMatch = text.match(/LNG:\s*(-?\d+(?:\.\d+)?)/i);
    const recipientMatch = text.match(/RECIPIENT:\s*(.*)/i);
    const addressMatch = text.match(/ADDRESS:\s*(.*)/i);

    let finalLat = latMatch ? parseFloat(latMatch[1]) : NaN;
    let finalLng = lngMatch ? parseFloat(lngMatch[1]) : NaN;

    // REFUERZO: Si el texto no tiene coordenadas, intentamos extraerlas de los metadatos de la herramienta (Grounding)
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    let mapUrl = `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`;

    if (groundingChunks && groundingChunks.length > 0) {
      // Si la IA usó Maps, a menudo el link está en los chunks
      const mapsChunk = groundingChunks.find(c => c.maps?.uri);
      if (mapsChunk) {
        mapUrl = mapsChunk.maps.uri;
        // Si no tenemos lat/lng por texto, intentamos extraerlas de la URL de maps si es posible (formato /@lat,lng)
        if (isNaN(finalLat) || isNaN(finalLng)) {
          const urlCoords = mapUrl.match(/query=(-?\d+\.\d+),(-?\d+\.\d+)/);
          if (urlCoords) {
            finalLat = parseFloat(urlCoords[1]);
            finalLng = parseFloat(urlCoords[2]);
          }
        }
      }
    }

    // Si aún así no tenemos coordenadas válidas y es el primer intento, reintentamos
    if ((!isValidCoordValue(finalLat) || !isValidCoordValue(finalLng)) && attempt < 2) {
      console.warn(`Intento ${attempt} fallido para "${input}". Reintentando...`);
      return await parseAddress(input, userLocation, manualCoords, attempt + 1);
    }

    // Validación final estricta
    if (!isValidCoordValue(finalLat) || !isValidCoordValue(finalLng)) {
      throw new Error(`No se encontró una ubicación precisa para "${input}" en la zona de Elche.`);
    }

    return {
      recipient: recipientMatch ? recipientMatch[1].trim() : "Cliente",
      address: addressMatch ? addressMatch[1].trim() : (input || "Dirección detectada"),
      phone: (text.match(/PHONE:\s*(.*)/i)?.[1] || "").trim(),
      lat: finalLat,
      lng: finalLng,
      notes: (text.match(/NOTES:\s*(.*)/i)?.[1] || "").trim(),
      sourceUrl: manualCoords?.includes('http') ? manualCoords : mapUrl
    };
  } catch (error: any) {
    // Si es un error de tiempo de espera o red y tenemos reintentos, lo usamos
    if (attempt < 2 && (error.message.includes('fetch') || error.message.includes('timeout'))) {
      return await parseAddress(input, userLocation, manualCoords, attempt + 1);
    }
    throw error;
  }
};

