              latitude: anchorLoc.latitude,
              longitude: anchorLoc.longitude
            }
          }
        }
      },
    });

    const text = response.text || "";

    // 1. Extraer del texto de la respuesta (Gemini suele escribir los datos del tool)
    const latMatch = text.match(/(?:LAT|latitud):\s*(-?\d+(?:\.\d+)?)/i);
    const lngMatch = text.match(/(?:LNG|longitud|lng|lon):\s*(-?\d+(?:\.\d+)?)/i);
    const nameMatch = text.match(/(?:NOMBRE|NAME):\s*(.*)/i);
    const addressMatch = text.match(/(?:DIRECCION|ADDRESS):\s*(.*)/i);

    let finalLat = latMatch ? parseFloat(latMatch[1]) : NaN;
    let finalLng = lngMatch ? parseFloat(lngMatch[1]) : NaN;
    let finalAddress = addressMatch ? addressMatch[1].trim() : "";
    let finalName = nameMatch ? nameMatch[1].trim() : "";

    // 2. REFUERZO: Extraer directamente de los metadatos de la herramienta (Grounding)
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    let mapUrl = "";

    if (groundingChunks && groundingChunks.length > 0) {
      const mapsChunk = groundingChunks.find(c => c.maps && c.maps.uri);
      if (mapsChunk) {
        mapUrl = mapsChunk.maps.uri;

        // Si no hay coordenadas en el texto, las sacamos de la URL de Maps del tool
        if (!isValidCoordValue(finalLat) || !isValidCoordValue(finalLng)) {
          const urlCoords = mapUrl.match(/query=(-?\d+\.\d+),(-?\d+\.\d+)/) || 
                           mapUrl.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/) ||
                           mapUrl.match(/ll=(-?\d+\.\d+),(-?\d+\.\d+)/);

          if (urlCoords) {
            finalLat = parseFloat(urlCoords[1]);
            finalLng = parseFloat(urlCoords[2]);
          }
        }

        if ((!finalAddress || finalAddress === "N/A") && mapsChunk.maps.title) {
          finalAddress = mapsChunk.maps.title;
        }
      }
    }

    // VALIDACIÓN CRÍTICA: Si tras el tool y el texto seguimos sin lat/lng válidos...
    if (!isValidCoordValue(finalLat) || !isValidCoordValue(finalLng)) {
      if (attempt < 2) {
        console.warn(`[Geocoding] No se detectaron coordenadas en intento ${attempt}. Reintentando con prompt forzado...`);
        return await parseAddress(`${input} Elche`, userLocation, manualCoords, attempt + 1);
      }
      // Fallo definitivo: No asignamos N/A ni permitimos NaN
      throw new Error(`Google Maps no devolvió una ubicación procesable para "${input}".`);
    }

    // A partir de aquí tenemos coordenadas VÁLIDAS y FINITAS
    console.log(`[Geocoding] RESULTADO VÁLIDO:`);
    console.log(` - Dirección: ${finalAddress || input}`);
    console.log(` - Coordenadas: [${finalLat}, ${finalLng}]`);

    const distance = getDistanceInKm(finalLat, finalLng, elcheCoords.latitude, elcheCoords.longitude);

    // Si la ubicación es válida pero está fuera del radio (ej: El Corte Inglés de otra ciudad)
    if (distance > 10 && attempt < 2) {
      console.warn(`[Geocoding] Ubicación encontrada fuera de Elche (${distance.toFixed(2)}km). Reintentando...`);
      return await parseAddress(`${input} Elche Alicante`, userLocation, manualCoords, attempt + 1);
    }

    return {
      recipient: finalName || (finalAddress.split(',')[0] || "Cliente"),
      address: finalAddress || input,
      phone: (text.match(/(?:TEL|TELEFONO|tel):\s*(.*)/i)?.[1] || "").trim(),
      lat: finalLat,
      lng: finalLng,
      notes: (text.match(/(?:NOTAS|notas):\s*(.*)/i)?.[1] || "").trim(),
      sourceUrl: manualCoords?.includes('http') ? manualCoords : (mapUrl || `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`)
    };

  } catch (error: any) {
    // Manejo de errores de red o reintentos
    if (attempt < 2 && (error.message.includes('fetch') || error.message.includes('timeout'))) {
      return await parseAddress(input, userLocation, manualCoords, attempt + 1);
    }
    console.error(`[Geocoding] Error final: ${error.message}`);
    throw error;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es un número finito válido.
 */
const isValidCoordValue = (val: any): boolean => {
  const num = parseFloat(val);
  return typeof num === 'number' && Number.isFinite(num);
};

/**
 * Calcula la distancia en KM entre dos puntos (Haversine).
 */
const getDistanceInKm = (lat1: number, lon1: number, lat2: number, lon2: number) => {
  const R = 6371; 
  const dLat = (lat2 - lat1) * (Math.PI / 180);
  const dLon = (lon2 - lon1) * (Math.PI / 180);
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * (Math.PI / 180)) * Math.cos(lat2 * (Math.PI / 180)) * 
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

/**
 * Intenta extraer coordenadas de una cadena de texto (formato "lat, lng" o similar).
 */
const extractCoordsFromManual = (input: string) => {
  const coordsRegex = /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/;
  const match = input.match(coordsRegex);
  if (match) {
    return { lat: parseFloat(match[1]), lng: parseFloat(match[2]) };
  }
  return null;
};

