  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

/**
 * Intenta extraer coordenadas de una URL de Google Maps o una cadena lat,lng.
 */
const extractCoordsFromInput = (input: string) => {
  if (!input) return null;

  // Caso 1: Formato "lat, lng" (ej: 38.26, -0.69)
  const coordsRegex = /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/;
  const matchCoords = input.match(coordsRegex);
  if (matchCoords) {
    return { lat: parseFloat(matchCoords[1]), lng: parseFloat(matchCoords[2]) };
  }

  // Caso 2: URL de Google Maps (query=lat,lng o @lat,lng)
  const urlRegex = /query=(-?\d+\.\d+),(-?\d+\.\d+)|@(-?\d+\.\d+),(-?\d+\.\d+)|ll=(-?\d+\.\d+),(-?\d+\.\d+)/;
  const matchUrl = input.match(urlRegex);
  if (matchUrl) {
    // El match puede estar en diferentes grupos según el formato
    const lat = parseFloat(matchUrl[1] || matchUrl[3] || matchUrl[5]);
    const lng = parseFloat(matchUrl[2] || matchUrl[4] || matchUrl[6]);
    if (isValidCoordValue(lat) && isValidCoordValue(lng)) {
      return { lat, lng };
    }
  }

  return null;
};

