          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-5 border-b flex justify-between items-center bg-slate-50">
              <h3 className="font-bold text-slate-800">Nueva Parada</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleAddDelivery} className="p-5 space-y-4">
              <div className="flex bg-slate-100 p-1 rounded-xl">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex-1 py-2.5 rounded-lg text-xs font-bold transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-500'}`}>ENTREGA</button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex-1 py-2.5 rounded-lg text-xs font-bold transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-sm' : 'text-slate-500'}`}>RECOGIDA</button>
