                  <textarea 
                    required
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-24 p-3 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 text-sm resize-none transition-colors" 
                    placeholder="Ej: C. Mayor 10, Elche o El Corte Inglés..." 
                  />
                  <button type="button" onClick={toggleListening} className={`absolute right-2 bottom-2 p-2 rounded-lg transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}>
                    <Mic size={18} />
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Teléfono</label>
                  <input 
                    type="tel" 
                    value={newPhoneInput} 
                    onChange={(e) => setNewPhoneInput(e.target.value)} 
                    className="w-full p-3 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 text-sm transition-colors" 
                    placeholder="Opcional" 
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">URL Google Maps</label>
                  <input 
                    type="text" 
                    value={newCoordsInput} 
                    onChange={(e) => setNewCoordsInput(e.target.value)} 
                    className="w-full p-3 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 text-sm transition-colors" 
                    placeholder="Enlace o Coords" 
                  />
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isParsing || !newAddressInput.trim()} 
                className="w-full py-4 bg-blue-600 text-white rounded-xl font-bold flex justify-center items-center gap-2 shadow-lg active:scale-95 transition-all disabled:opacity-50 mt-2"
              >
                {isParsing ? <Loader2 className="animate-spin" size={20} /> : <Plus size={20} />} 
                BUSCAR Y AÑADIR
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

