      const data = await response.json();
      const newDeliveries = data.waypoints.map((waypoint, index) => {
        const correspondingDelivery = pendingDeliveries.find(
          (delivery) =>
            delivery.latitude === waypoint.latitude &&
            delivery.longitude === waypoint.longitude
        );

        return correspondingDelivery || {
          id: index,
          latitude: waypoint.latitude,
          longitude: waypoint.longitude,
          status: DeliveryStatus.PENDING,
          recipient: "Optimized Location",
          address: "Optimized Address",
        };
      });

      return newDeliveries;

    } catch (error) {
      console.error("Error optimizing route:", error);
      // Handle the error appropriately, e.g., show an error message or fallback to a default route.
      // Fallback: return the original pending order.
      return pendingDeliveries;
    }
  };
