import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

const extractFromUrl = (url: string) => {
  if (!url) return null;
  const match = url.match(/query=(-?\d+\.\d+),(-?\d+\.\d+)|@(-?\d+\.\d+),(-?\d+\.\d+)|ll=(-?\d+\.\d+),(-?\d+\.\d+)/);
  if (match) {
    const lat = parseFloat(match[1] || match[3] || match[5]);
    const lng = parseFloat(match[2] || match[4] || match[6]);
    return isValidCoord(lat) && isValidCoord(lng) ? { lat, lng } : null;
  }
  return null;
};

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimiza esta ruta de reparto iniciando en ${startLocation}. Entregas: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}. Devuelve JSON con 'optimizedOrder' (lista de IDs en orden lógico).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: { type: Type.ARRAY, items: { type: Type.STRING } },
            reasoning: { type: Type.STRING }
          },
          required: ["optimizedOrder"]
        }
      }
    });
    const result = JSON.parse(response.text || '{}');
    return result;
  } catch (e) {
    console.error("Optimización fallida:", e);
    return { optimizedOrder: deliveries.map(d => d.id) };
  }
};

export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualInput?: string): Promise<any> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Entrada manual o URL
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación Directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes('http') ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`
    };
  }

  // 2. Geocodificación inteligente con Google Maps Tool
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Localiza y geocodifica exactamente esta dirección o lugar en España: "${input}". 
      Es OBLIGATORIO usar la herramienta Google Maps para obtener coordenadas exactas.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        }
      },
    });

    const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const mapsData = grounding?.find(c => c.maps)?.maps;

    if (mapsData) {
      const coords = extractFromUrl(mapsData.uri);
      if (coords) {
        return {
          recipient: mapsData.title || input,
          address: mapsData.title || input,
          lat: coords.lat,
          lng: coords.lng,
          sourceUrl: mapsData.uri,
          notes: ""
        };
      }
    }

    // Fallback simple por si el grounding no devuelve URI pero el modelo sí texto
    const text = response.text || "";
    const latMatch = text.match(/latitud[:\s]+(-?\d+\.\d+)/i) || text.match(/lat[:\s]+(-?\d+\.\d+)/i);
    const lngMatch = text.match(/longitud[:\s]+(-?\d+\.\d+)/i) || text.match(/lng[:\s]+(-?\d+\.\d+)/i);

    if (latMatch && lngMatch) {
      return {
        recipient: input,
        address: input,
        lat: parseFloat(latMatch[1]),
        lng: parseFloat(lngMatch[1]),
        sourceUrl: ""
      };
    }

    throw new Error("No pudimos encontrar una ubicación precisa. Por favor, intenta ser más específico.");
  } catch (e: any) {
    console.error("[Geocoding Error]", e);
    throw new Error(e.message || "Error al localizar la dirección.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  // Sincronización con LocalStorage
  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  // Geolocalización y Speech API
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn(err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) return;
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) return;

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc, newCoordsInput);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substr(2, 9),
        recipient: parsed.recipient || newAddressInput,
        address: parsed.address || newAddressInput,
        phone: newPhoneInput.trim() || parsed.phone,
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`
      };

      setDeliveries(prev => [...prev, newDelivery]);

      // Limpiar campos y cerrar modal
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      alert("Error al localizar: " + error.message);
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const start = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Centro Ciudad";
      const result = await optimizeRoute(pending, start);
      if (result?.optimizedOrder) setManualSequence(result.optimizedOrder);
    } catch (e) {
      console.error(e);
    } finally {
      setIsOptimizing(false);
    }
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const ordered = manualSequence.map(id => pending.find(p => p.id === id)).filter((p): p is Delivery => !!p);
    const unordered = pending.filter(p => !manualSequence.includes(p.id));
    return [...ordered, ...unordered];
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <Power size={80} className="text-white mb-8 animate-pulse" />
        <h1 className="text-4xl font-black text-white mb-4">SISTEMA REINICIADO</h1>
        <p className="text-slate-400 mb-8 max-w-sm">La sesión ha sido finalizada y los datos borrados correctamente.</p>
        <button onClick={() => window.location.reload()} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-3">
          <RefreshCcw size={20} /> EMPEZAR NUEVA RUTA
        </button>
      </div>
    );
  }

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 relative">
      <header className="bg-white border-b px-6 py-3 flex items-center justify-between z-30 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg text-white">
            <Truck size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tight">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex bg-slate-100 rounded-xl p-1">
          {['list', 'map', 'split', 'control'].map((mode) => (
            <button 
              key={mode} 
              onClick={() => setViewMode(mode as any)} 
              className={`px-4 py-2 rounded-lg text-[10px] font-black tracking-widest transition-all ${viewMode === mode ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {mode.toUpperCase()}
            </button>
          ))}
        </div>

        <button onClick={() => setIsAdding(true)} className="bg-blue-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 font-bold shadow-lg hover:bg-blue-700 active:scale-95 transition-all">
          <Plus size={18} /> <span className="hidden sm:inline">Nueva Parada</span>
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {viewMode === 'control' ? (
          <div className="flex-1 p-6 md:p-10 overflow-y-auto bg-slate-50">
            <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex justify-between items-center">
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tighter">CENTRO DE CONTROL</h2>
                  <p className="text-slate-500 font-medium">Gestión total de la jornada de reparto</p>
                </div>
                <button 
                  onClick={handleClearAll} 
                  className="bg-red-600 text-white px-8 py-4 rounded-2xl font-black flex items-center gap-3 shadow-2xl hover:bg-red-700 active:scale-95 transition-all"
                >
                  <LogOut size={20} /> BORRAR Y CERRAR
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-sm flex flex-col items-center text-center">
                  <div className="bg-green-50 p-4 rounded-2xl text-green-600 mb-4">
                    <Package size={32} />
                  </div>
                  <span className="text-5xl font-black text-slate-800 tracking-tighter">{completedDeliveries.length}</span>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-2">Completados</p>
                </div>
                <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-sm flex flex-col items-center text-center">
                  <div className="bg-yellow-50 p-4 rounded-2xl text-yellow-600 mb-4">
                    <AlertTriangle size={32} />
                  </div>
                  <span className="text-5xl font-black text-slate-800 tracking-tighter">{issueDeliveries.length}</span>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-2">Incidencias</p>
