import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Extrae coordenadas de una URL de Google Maps (formatos comunes: query=lat,lng o @lat,lng)
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;
  const match = url.match(/query=(-?\d+\.\d+),(-?\d+\.\d+)|@(-?\d+\.\d+),(-?\d+\.\d+)|ll=(-?\d+\.\d+),(-?\d+\.\d+)/);
  if (match) {
    const lat = parseFloat(match[1] || match[3] || match[5]);
    const lng = parseFloat(match[2] || match[4] || match[6]);
    return isValidCoord(lat) && isValidCoord(lng) ? { lat, lng } : null;
  }
  return null;
};

export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimiza esta ruta de reparto iniciando en ${startLocation}. Entregas: ${JSON.stringify(deliveries.map(d => ({ id: d.id, address: d.address })))}. Devuelve JSON con 'optimizedOrder' (lista de IDs en orden lógico).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: { type: Type.ARRAY, items: { type: Type.STRING } },
            reasoning: { type: Type.STRING }
          },
          required: ["optimizedOrder"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Error en optimización AI:", e);
    return { optimizedOrder: deliveries.map(d => d.id) };
  }
};

/**
 * Geocodifica una dirección usando la herramienta Google Maps de Gemini.
 * Devuelve un objeto con recipient, address, lat, lng y sourceUrl.
 */
export const parseAddress = async (input: string, userLocation?: { latitude: number, longitude: number }, manualInput?: string): Promise<any> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Si el usuario pegó directamente una URL o coordenadas manuales
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación Directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes('http') ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`
    };
  }

  // 2. Uso de Google Maps Grounding para geocodificación precisa
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", // Requerido para herramientas de Maps
      contents: `Encuentra las coordenadas exactas y la dirección de este lugar: "${input}". 
      Responde indicando el nombre del lugar y su dirección. 
      ES CRÍTICO usar la herramienta Google Maps para geocodificar.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        }
      },
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    // Buscamos el primer chunk que contenga metadatos de mapas con una URI de la cual extraer coordenadas
    if (groundingChunks) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            return {
              recipient: chunk.maps.title || input,
              address: chunk.maps.title || input,
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.maps.uri,
              notes: ""
            };
          }
        }
      }
    }

    // Fallback: búsqueda en el texto por si el grounding no devolvió la URI pero sí texto parseable
    const text = response.text || "";
    const latMatch = text.match(/(?:lat|latitud)[:\s]+(-?\d+\.\d+)/i);
    const lngMatch = text.match(/(?:lng|longitud)[:\s]+(-?\d+\.\d+)/i);

    if (latMatch && lngMatch) {
      return {
        recipient: input,
        address: input,
        lat: parseFloat(latMatch[1]),
        lng: parseFloat(lngMatch[1]),
        sourceUrl: ""
      };
    }

    throw new Error("No se pudo obtener una ubicación precisa para: " + input);
  } catch (error: any) {
    console.error("Error en parseAddress:", error);
    throw new Error(error.message || "Error al localizar la dirección.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw } from 'lucide-react';
