            <Truck size={22} />
          </div>
          <h1 className="text-2xl font-black tracking-tighter text-slate-800">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex bg-slate-100 rounded-2xl p-1.5 shadow-inner">
          {['list', 'map', 'split', 'control'].map((mode) => (
            <button 
              key={mode} 
              onClick={() => setViewMode(mode as any)} 
              className={`px-5 py-2.5 rounded-xl text-[10px] font-black tracking-widest transition-all ${viewMode === mode ? 'bg-white shadow-md text-blue-600 scale-105' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {mode.toUpperCase()}
            </button>
          ))}
        </div>

        <button onClick={() => setIsAdding(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl flex items-center gap-2 font-black shadow-[0_10px_30px_rgba(37,99,235,0.3)] hover:bg-blue-700 active:scale-95 transition-all text-sm">
          <Plus size={20} /> <span className="hidden sm:inline">NUEVA PARADA</span>
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {viewMode === 'control' ? (
          <div className="flex-1 p-6 md:p-12 overflow-y-auto bg-slate-50">
            <div className="max-w-5xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tighter">CENTRO DE CONTROL</h2>
                  <p className="text-slate-500 font-bold text-lg">Métricas y gestión operativa en tiempo real</p>
                </div>
                {/* BOTÓN ROJO BORRAR Y CERRAR */}
                <button 
                  onClick={handleClearAll} 
                  className="bg-red-600 text-white px-10 py-5 rounded-[24px] font-black flex items-center gap-4 shadow-[0_15px_40px_rgba(220,38,38,0.3)] hover:bg-red-700 active:scale-95 transition-all text-lg"
