import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Extrae coordenadas de una URL de Google Maps o formato query
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;
  const match = url.match(
    /query=(-?\d+\.\d+),(-?\d+\.\d+)|@(-?\d+\.\d+),(-?\d+\.\d+)|ll=(-?\d+\.\d+),(-?\d+\.\d+)/
  );
  if (match) {
    const lat = parseFloat(match[1] || match[3] || match[5]);
    const lng = parseFloat(match[2] || match[4] || match[6]);
    return isValidCoord(lat) && isValidCoord(lng) ? { lat, lng } : null;
  }
  return null;
};

export const optimizeRoute = async (
  deliveries: Delivery[],
  startLocation: string
) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimiza esta ruta de reparto iniciando en ${startLocation}. Entregas: ${JSON.stringify(
        deliveries.map((d) => ({ id: d.id, address: d.address }))
      )}. Devuelve JSON con 'optimizedOrder' (lista de IDs en orden lógico).`,
      config: {
        responseMimeType: "application/json",
        // Using Type enum from @google/genai as per guidelines
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
            },
            reasoning: { type: Type.STRING },
          },
          required: ["optimizedOrder"],
        },
      },
    });

    const text = response.text;
    if (text) return JSON.parse(text);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  } catch (e) {
    console.error("Error en optimización AI:", e);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  }
};

/**
 * Geocodifica una dirección usando Google Maps Grounding de forma nativa.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  notes: string;
}> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Entrada manual o URL
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes("http") ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`,
      notes: "",
    };
  }

  // 2. Búsqueda con Google Maps Tool (Sin responseMimeType para evitar errores de compatibilidad)
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca y geolocaliza exactamente el siguiente lugar o dirección en España: "${input}". 
      Es obligatorio usar la herramienta Google Maps para encontrar la ubicación precisa.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude },
          },
        },
      },
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (groundingChunks && groundingChunks.length > 0) {
      // Buscamos el primer chunk que tenga datos de mapas
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            return {
              recipient: chunk.maps.title || input,
              address: chunk.maps.title || input,
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.maps.uri,
              notes: ""
            };
          }
        }
      }
    }

    // Fallback: Si no hay grounding pero hay texto con coordenadas (raro pero posible)
    const text = response.text || "";
    const latLngMatch = text.match(/(-?\d+\.\d+),\s*(-?\d+\.\d+)/);
    // Fix: correct typo 'latLngLngMatch' to 'latLngMatch'
    if (latLngMatch) {
      return {
        recipient: input,
        address: input,
        lat: parseFloat(latLngMatch[1]),
        lng: parseFloat(latLngMatch[2]),
        sourceUrl: "",
        notes: ""
      };
    }

    throw new Error("No pudimos encontrar una ubicación exacta. Intenta ser más específico (ej: añade ciudad o calle).");
  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error(error.message || "Error al buscar la dirección.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("GPS no disponible:", err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) {
      alert("Escribe una dirección o busca un sitio.");
      return;
    }

    setIsParsing(true);
    try {
      const parsed = await parseAddress(newAddressInput, currentUserLoc, newCoordsInput);
      const newDelivery: Delivery = {
        id: Math.random().toString(36).substring(2, 9),
        recipient: parsed.recipient || newAddressInput,
        address: parsed.address || newAddressInput,
        phone: newPhoneInput.trim(),
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`,
      };
      setDeliveries(prev => [...prev, newDelivery]);
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      console.error("Error en geocodificación:", error);
      alert(error.message || "No se pudo localizar el sitio. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación por completo.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const start = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Ubicación inicial";
      const result = await optimizeRoute(pending, start);
      if (result?.optimizedOrder) setManualSequence(result.optimizedOrder);
    } catch (e) {
      console.error(e);
    } finally {
      setIsOptimizing(false);
    }
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const ordered = manualSequence.map(id => pending.find(p => p.id === id)).filter((p): p is Delivery => !!p);
    const unordered = pending.filter(p => !manualSequence.includes(p.id));
    return [...ordered, ...unordered];
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <Power size={80} className="text-white mb-8 animate-pulse" />
