        <p className="text-slate-400 mb-10 max-w-sm font-medium">Todos los datos de ruta han sido eliminados del dispositivo.</p>
        <button onClick={() => window.location.reload()} className="bg-blue-600 text-white px-10 py-5 rounded-3xl font-black shadow-[0_20px_50px_rgba(37,99,235,0.3)] hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-4">
          <RefreshCcw size={24} /> NUEVA JORNADA
        </button>
      </div>
    );
  }

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const viewLabels: { [key: string]: string } = {
    list: 'LISTA',
    map: 'MAPA',
    split: 'DIVIDIDO',
    control: 'CONTROL'
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 relative">
      <header className="bg-white border-b px-4 py-3 sm:px-6 sm:py-4 flex items-center justify-between z-30 shadow-sm gap-2">
        <div className="flex items-center gap-2 sm:gap-3 shrink-0">
          <div className="bg-blue-600 p-1.5 sm:p-2 rounded-lg sm:rounded-xl text-white shadow-md">
            <Truck size={18} className="sm:w-5 sm:h-5" />
          </div>
          <h1 className="text-lg sm:text-2xl font-black tracking-tighter text-slate-800">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex bg-slate-100 rounded-xl sm:rounded-2xl p-1 shadow-inner overflow-x-auto no-scrollbar">
          {['list', 'map', 'split', 'control'].map((mode) => (
            <button 
              key={mode} 
              onClick={() => setViewMode(mode as any)} 
              className={`px-3 sm:px-6 py-2 sm:py-2.5 rounded-lg sm:rounded-xl text-[9px] sm:text-[10px] font-black tracking-tighter sm:tracking-widest transition-all whitespace-nowrap ${viewMode === mode ? 'bg-white shadow-md text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {viewLabels[mode]}
            </button>
          ))}
        </div>

        <button onClick={() => setIsAdding(true)} className="bg-blue-600 text-white p-2 sm:px-5 sm:py-3 rounded-xl flex items-center gap-2 font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all text-[10px] shrink-0 uppercase">
          <Plus size={16} /> <span className="hidden md:inline">Nueva Parada</span>
        </button>
      </header>

      <main className={`flex-1 flex overflow-hidden ${viewMode === 'split' ? 'flex-col md:flex-row' : 'flex-row'}`}>
        {viewMode === 'control' ? (
          <div className="flex-1 p-6 md:p-12 overflow-y-auto bg-slate-50">
            <div className="max-w-5xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tighter uppercase">Panel Operativo</h2>
                  <p className="text-slate-500 font-bold text-lg">Métricas de la jornada actual</p>
                </div>
                <button 
                  onClick={handleClearAll} 
                  className="bg-red-600 text-white w-full md:w-auto px-10 py-5 rounded-[24px] font-black flex items-center justify-center gap-4 shadow-[0_15px_40px_rgba(220,38,38,0.3)] hover:bg-red-700 active:scale-95 transition-all text-lg uppercase"
                >
                  <LogOut size={24} /> Borrar y Cerrar
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-green-50 p-6 rounded-3xl text-green-600 mb-6">
                    <Package size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{completedDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Completados</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-yellow-50 p-6 rounded-3xl text-yellow-600 mb-6">
                    <AlertTriangle size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{issueDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Incidencias</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-blue-50 p-6 rounded-3xl text-blue-600 mb-6">
                    <Clock size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{pendingDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Pendientes</p>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <>
            <aside className={`
              ${viewMode === 'map' ? 'hidden' : ''} 
              ${viewMode === 'list' ? 'w-full' : ''} 
              ${viewMode === 'split' ? 'w-full md:w-[440px] h-1/2 md:h-full' : ''}
              border-r bg-white flex flex-col overflow-hidden shadow-2xl z-20 transition-all
            `}>
              <div className="p-5 bg-slate-50/80 border-b flex justify-between items-center backdrop-blur-sm">
                <h2 className="font-black text-[11px] uppercase tracking-[0.2em] text-slate-400">Ruta de Reparto</h2>
                <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black border-none flex items-center gap-2 hover:bg-blue-700 disabled:opacity-30 transition-all shadow-lg active:scale-95">
                  {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={14} />} OPTIMIZAR
                </button>
