              <div className="flex-1 overflow-y-auto p-5 space-y-4">
                {pendingDeliveries.length === 0 && (
                  <div className="text-center py-12 md:py-24 opacity-20 flex flex-col items-center">
                    <Navigation size={64} className="mb-6" />
                    <p className="text-lg font-black tracking-widest">SIN PARADAS</p>
                  </div>
                )}
                {pendingDeliveries.map((d) => (
                  <DeliveryCard 
                    key={d.id} 
                    index={manualSequence.indexOf(d.id)} 
                    delivery={d} 
                    isSelected={selectedId === d.id} 
                    onClick={() => setSelectedId(d.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={(id) => setDeliveries(prev => prev.filter(x => x.id !== id))} 
                    onRemoveFromSequence={(id) => setManualSequence(prev => prev.filter(x => x !== id))}
                    onDragStart={() => {}} onDragOver={() => {}} onDragEnd={() => {}}
                  />
