                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="tel" value={newPhoneInput} onChange={(e) => setNewPhoneInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Teléfono (opc)" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Link o Coords</label>
                  <div className="relative">
                    <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="text" value={newCoordsInput} onChange={(e) => setNewCoordsInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Link Google Maps" />
                  </div>
                </div>
              </div>
              <button type="submit" disabled={isParsing || !newAddressInput.trim()} className="w-full py-5 bg-blue-600 text-white rounded-[30px] font-black text-lg flex justify-center items-center gap-4 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 mt-4 shrink-0 uppercase">
                {isParsing ? <Loader2 className="animate-spin" size={24} /> : <Plus size={24} />} 
                Buscar y Añadir
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

