import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Extrae coordenadas de una URL de Google Maps con soporte para múltiples formatos
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;
  // Regex mejorada para capturar @lat,lng o query=lat,lng o place/.../@lat,lng
  const match = url.match(
    /(?:query=|@|ll=)(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  );
  if (match) {
    const lat = parseFloat(match[1]);
    const lng = parseFloat(match[2]);
    return isValidCoord(lat) && isValidCoord(lng) ? { lat, lng } : null;
  }
  return null;
};

