/**
 * Geocodifica una dirección usando Google Maps Grounding de forma nativa.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  notes: string;
}> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Entrada manual o URL directa
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes("http") ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`,
      notes: "",
    };
  }

  // 2. Búsqueda con Google Maps Tool
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca la ubicación EXACTA en España para esta dirección: "${input}". 
      Es CRÍTICO que encuentres el número de calle específico si se proporciona.
      Si es en Elche, Alicante, prioriza esa zona.
      Usa la herramienta Google Maps y devuelve el resultado más preciso.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude },
          },
        },
      },
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            return {
              recipient: chunk.maps.title || input,
              address: chunk.maps.title || input,
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.maps.uri,
              notes: ""
            };
          }
        }
      }
    }

    // Fallback: Si no hay grounding pero hay texto con coordenadas
    const text = response.text || "";
    const latLngMatch = text.match(/(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/);
    if (latLngMatch) {
      return {
        recipient: input,
        address: input,
        lat: parseFloat(latLngMatch[1]),
        lng: parseFloat(latLngMatch[2]),
        sourceUrl: `https://www.google.com/maps/search/?api=1&query=${latLngMatch[1]},${latLngMatch[2]}`,
        notes: ""
      };
    }

    throw new Error("No pudimos encontrar una ubicación exacta para esa calle y número. Asegúrate de incluir la ciudad (ej: 'Calle Capitán Antonio Mena 11 Elche').");
  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error(error.message || "Error al buscar la dirección.");
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es una coordenada numérica finita
 */
const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Extrae coordenadas de una URL de Google Maps o enlaces similares
 * Soporta formatos: @lat,lng | query=lat,lng | ll=lat,lng | q=lat,lng
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;

  // Intentar varios patrones comunes de coordenadas en URLs
  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,           // Formato @38.26,-0.69
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,     // Formato query=38.26,-0.69
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,        // Formato ll=38.26,-0.69
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,         // Formato q=38.26,-0.69
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/            // Cualquier par lat,lng
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (isValidCoord(lat) && isValidCoord(lng)) {
        return { lat, lng };
      }
    }
  }
  return null;
};

