/**
 * Geocodifica una dirección usando Google Maps y Search Grounding simultáneamente.
 * Esto aumenta drásticamente la precisión para calles específicas con número.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  notes: string;
}> => {
  // Coordenadas por defecto (Elche) si no hay GPS del usuario
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Entrada manual o URL directa de Google Maps pegada por el usuario
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes("http") ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`,
      notes: "",
    };
  }

  // 2. Búsqueda con Herramientas de Grounding (Maps + Search)
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca la ubicación EXACTA en España para la dirección: "${input}". 
      Es CRÍTICO encontrar el número de calle específico.
      Si no se especifica ciudad, asume que está en Elche (Alicante) o alrededores.
      Verifica con Google Maps y Google Search para obtener las coordenadas precisas.`,
      config: {
        // Usamos ambas herramientas para máxima fiabilidad
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude },
          },
        },
      },
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        // Revisar si viene de Maps
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            return {
              recipient: chunk.maps.title || input,
              address: chunk.maps.title || input,
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.maps.uri,
              notes: ""
            };
          }
        }
        // Revisar si viene de Search (Web)
        if (chunk.web && chunk.web.uri) {
          const coords = extractFromUrl(chunk.web.uri);
          if (coords) {
            return {
              recipient: chunk.web.title || input,
              address: chunk.web.title || input,
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.web.uri,
              notes: ""
            };
          }
        }
      }
    }

    // Fallback Final: Si no hay grounding chunks con URI pero el modelo puso coords en el texto
    const textResponse = response.text || "";
    const textCoords = extractFromUrl(textResponse);
    if (textCoords) {
      return {
        recipient: input,
        address: input,
        lat: textCoords.lat,
        lng: textCoords.lng,
        sourceUrl: `https://www.google.com/maps/search/?api=1&query=${textCoords.lat},${textCoords.lng}`,
        notes: ""
      };
    }

    throw new Error("No se pudo localizar la dirección exacta. Prueba a añadir la ciudad o código postal (ej: 'Calle Capitán Antonio Mena 11 Elche').");
  } catch (error: any) {
    console.error("[Geocoding Detailed Error]", error);
    throw new Error(error.message || "Error al conectar con el servicio de mapas.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw, User } from 'lucide-react';
import MapView from './components/MapView';
