import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es una coordenada numérica finita
 */
const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Detecta si un string tiene formato de Plus Code (ej: 8C7X+H3 o 8C7X+H3 Elche)
 */
const isPlusCode = (input: string): boolean => {
  const plusCodeRegex = /[23456789CFGHJMPQRVWX]{4,8}\+[23456789CFGHJMPQRVWX]{2,}/i;
  return plusCodeRegex.test(input);
};

/**
 * Extrae coordenadas de una URL de Google Maps o enlaces similares
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;

  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (isValidCoord(lat) && isValidCoord(lng)) {
        return { lat, lng };
      }
    }
  }
  return null;
};

/**
 * Optimiza la ruta utilizando Gemini 3 Pro
 */
export const optimizeRoute = async (
  deliveries: Delivery[],
  startLocation: string
) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimiza esta ruta de reparto iniciando en ${startLocation}. Entregas: ${JSON.stringify(
        deliveries.map((d) => ({ id: d.id, address: d.address }))
      )}. Devuelve JSON con 'optimizedOrder' (lista de IDs en orden lógico para minimizar tiempo y distancia).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
            },
            reasoning: { type: Type.STRING },
          },
          required: ["optimizedOrder"],
        },
      },
    });

    const text = response.text;
    if (text) return JSON.parse(text);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  } catch (e) {
    console.error("Error en optimización AI:", e);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  }
};

/**
 * Geocodifica una dirección usando Google Maps y Search Grounding simultáneamente.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  notes: string;
}> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Coordenadas manuales en el input de link
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes("http") ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`,
      notes: "",
    };
  }

  // 2. Búsqueda con Herramientas de Grounding
  try {
    const isPlus = manualInput ? isPlusCode(manualInput) : false;
    const finalSearchQuery = isPlus ? manualInput! : (input || manualInput || "");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca la ubicación para: "${finalSearchQuery}". 
      ${isPlus ? "Esto es un PLUS CODE de Google Maps, resuélvelo prioritariamente." : "Busca la dirección exacta en España."}
      Si no hay ciudad especificada, asume que está en Elche (Alicante).
      Usa Google Maps para obtener las coordenadas exactas.`,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude },
          },
        },
      },
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            return {
              recipient: input || chunk.maps.title || "Ubicación encontrada",
              address: chunk.maps.title || input || "Dirección encontrada",
              lat: coords.lat,
              lng: coords.lng,
              sourceUrl: chunk.maps.uri,
              notes: ""
            };
          }
        }
      }
    }

    const textResponse = response.text || "";
    const textCoords = extractFromUrl(textResponse);
    if (textCoords) {
      return {
        recipient: input || "Ubicación",
        address: input || "Ubicación por texto",
        lat: textCoords.lat,
        lng: textCoords.lng,
        sourceUrl: `https://www.google.com/maps/search/?api=1&query=${textCoords.lat},${textCoords.lng}`,
        notes: ""
      };
    }

    throw new Error("No se pudo localizar el sitio. Revisa el Plus Code o la dirección.");
  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error(error.message || "Error al buscar la ubicación.");
  }
};

