    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newNameInput, setNewNameInput] = useState('');
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("GPS no disponible:", err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    // Validamos que haya al menos una forma de localizar la parada
    if (!newAddressInput.trim() && !newCoordsInput.trim()) {
      alert("Escribe una dirección o un Plus Code / Link.");
      return;
    }

    setIsParsing(true);
    try {
      const searchQuery = newNameInput ? `${newNameInput}, ${newAddressInput}` : newAddressInput;
      const parsed = await parseAddress(searchQuery, currentUserLoc, newCoordsInput);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substring(2, 9),
        recipient: newNameInput.trim() || parsed.recipient || newAddressInput || "Nueva Parada",
        address: parsed.address || newAddressInput || "Localización por código",
        phone: newPhoneInput.trim(),
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`,
      };
      setDeliveries(prev => [...prev, newDelivery]);
      setNewNameInput('');
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      console.error("Error en geocodificación:", error);
      alert(error.message || "No se pudo localizar el sitio. Intenta ser más específico o usa un Plus Code exacto.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación por completo.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    if (status === DeliveryStatus.COMPLETED) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    setManualSequence(prev => {
      if (prev.includes(id)) return prev;
      return [...prev, id];
    });
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const start = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Ubicación inicial";
      const result = await optimizeRoute(pending, start);
      if (result?.optimizedOrder) setManualSequence(result.optimizedOrder);
    } catch (e) {
      console.error(e);
    } finally {
      setIsOptimizing(false);
    }
  };

  const getSortedPending = () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const ordered = manualSequence.map(id => pending.find(p => p.id === id)).filter((p): p is Delivery => !!p);
    const unordered = pending.filter(p => !manualSequence.includes(p.id));
    return [...ordered, ...unordered];
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <Power size={80} className="text-white mb-8 animate-pulse" />
        <h1 className="text-4xl font-black text-white mb-4 tracking-tighter uppercase">Sesión Finalizada</h1>
        <p className="text-slate-400 mb-10 max-w-sm font-medium">Todos los datos de ruta han sido eliminados del dispositivo.</p>
        <button onClick={() => window.location.reload()} className="bg-blue-600 text-white px-10 py-5 rounded-3xl font-black shadow-[0_20px_50px_rgba(37,99,235,0.3)] hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-4">
          <RefreshCcw size={24} /> NUEVA JORNADA
        </button>
      </div>
    );
  }

  const pendingDeliveries = getSortedPending();
  const issueDeliveries = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);
  const completedDeliveries = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

  const viewLabels: { [key: string]: string } = {
    list: 'LISTA',
    map: 'MAPA',
    split: 'DIVIDIDO',
    control: 'CONTROL'
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 relative">
      <header className="bg-white border-b px-4 py-3 sm:px-6 sm:py-4 flex items-center justify-between z-30 shadow-sm gap-2">
        <div className="flex items-center gap-2 sm:gap-3 shrink-0">
          <div className="bg-blue-600 p-1.5 sm:p-2 rounded-lg sm:rounded-xl text-white shadow-md">
            <Truck size={18} className="sm:w-5 sm:h-5" />
          </div>
          <h1 className="text-lg sm:text-2xl font-black tracking-tighter text-slate-800">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex bg-slate-100 rounded-xl sm:rounded-2xl p-1 shadow-inner overflow-x-auto no-scrollbar">
          {['list', 'map', 'split', 'control'].map((mode) => (
            <button 
              key={mode} 
              onClick={() => setViewMode(mode as any)} 
              className={`px-3 sm:px-6 py-2 sm:py-2.5 rounded-lg sm:rounded-xl text-[9px] sm:text-[10px] font-black tracking-tighter sm:tracking-widest transition-all whitespace-nowrap ${viewMode === mode ? 'bg-white shadow-md text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {viewLabels[mode]}
            </button>
          ))}
        </div>

        <button onClick={() => setIsAdding(true)} className="bg-blue-600 text-white p-2 sm:px-5 sm:py-3 rounded-xl flex items-center gap-2 font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all text-[10px] shrink-0 uppercase">
          <Plus size={16} /> <span className="hidden md:inline">Nueva Parada</span>
        </button>
      </header>

      <main className={`flex-1 flex overflow-hidden ${viewMode === 'split' ? 'flex-col md:flex-row' : 'flex-row'}`}>
        {viewMode === 'control' ? (
          <div className="flex-1 p-6 md:p-12 overflow-y-auto bg-slate-50">
            <div className="max-w-5xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tighter uppercase">Panel Operativo</h2>
                  <p className="text-slate-500 font-bold text-lg">Métricas de la jornada actual</p>
                </div>
                <button 
                  onClick={handleClearAll} 
                  className="bg-red-600 text-white w-full md:w-auto px-10 py-5 rounded-[24px] font-black flex items-center justify-center gap-4 shadow-[0_15px_40px_rgba(220,38,38,0.3)] hover:bg-red-700 active:scale-95 transition-all text-lg uppercase"
                >
                  <LogOut size={24} /> Borrar y Cerrar
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-green-50 p-6 rounded-3xl text-green-600 mb-6">
                    <Package size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{completedDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Completados</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-yellow-50 p-6 rounded-3xl text-yellow-600 mb-6">
                    <AlertTriangle size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{issueDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Incidencias</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-blue-50 p-6 rounded-3xl text-blue-600 mb-6">
                    <Clock size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{pendingDeliveries.length}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Pendientes</p>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <>
            <aside className={`
              ${viewMode === 'map' ? 'hidden' : ''} 
              ${viewMode === 'list' ? 'w-full' : ''} 
              ${viewMode === 'split' ? 'w-full md:w-[440px] h-1/2 md:h-full' : ''}
              border-r bg-white flex flex-col overflow-hidden shadow-2xl z-20 transition-all
            `}>
              <div className="p-5 bg-slate-50/80 border-b flex justify-between items-center backdrop-blur-sm">
                <div className="flex flex-col">
                  <h2 className="font-black text-[11px] uppercase tracking-[0.2em] text-slate-400">Ruta de Reparto</h2>
                  <span className="text-[9px] text-blue-500 font-bold uppercase mt-0.5">Toca el mapa para ordenar</span>
                </div>
                <button onClick={handleOptimize} disabled={isOptimizing || pendingDeliveries.length < 2} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black border-none flex items-center gap-2 hover:bg-blue-700 disabled:opacity-30 transition-all shadow-lg active:scale-95">
                  {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={14} />} OPTIMIZAR
                </button>
              </div>
              <div className="flex-1 overflow-y-auto p-5 space-y-4">
                {pendingDeliveries.length === 0 && (
                  <div className="text-center py-12 md:py-24 opacity-20 flex flex-col items-center">
                    <Navigation size={64} className="mb-6" />
                    <p className="text-lg font-black tracking-widest">SIN PARADAS</p>
                  </div>
                )}
                {pendingDeliveries.map((d) => (
                  <DeliveryCard 
                    key={d.id} 
                    index={manualSequence.indexOf(d.id)} 
                    delivery={d} 
                    isSelected={selectedId === d.id} 
                    onClick={() => setSelectedId(d.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={(id) => setDeliveries(prev => prev.filter(x => x.id !== id))} 
                    onRemoveFromSequence={(id) => setManualSequence(prev => prev.filter(x => x !== id))}
                    onDragStart={() => {}} onDragOver={() => {}} onDragEnd={() => {}}
                  />
                ))}
              </div>
            </aside>
            <section className={`
              ${viewMode === 'list' ? 'hidden' : ''} 
              ${viewMode === 'map' ? 'flex-1' : ''} 
              ${viewMode === 'split' ? 'flex-1 h-1/2 md:h-full' : ''}
              relative transition-all
            `}>
              <MapView 
                deliveries={deliveries} 
                manualSequence={manualSequence} 
                selectedId={selectedId} 
                onMarkerClick={handleMarkerClick} 
                viewMode={viewMode} 
              />
            </section>
          </>
        )}
      </main>

      <button 
        onClick={() => setIsAdding(true)}
        className="fixed bottom-6 right-6 sm:bottom-10 sm:right-10 w-16 h-16 sm:w-20 sm:h-20 bg-blue-600 text-white rounded-2xl sm:rounded-[28px] shadow-2xl flex items-center justify-center hover:bg-blue-700 hover:scale-110 active:scale-90 transition-all z-40"
      >
        <Plus size={32} />
      </button>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[40px] w-full max-w-xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50/40 shrink-0">
              <div>
                <h3 className="text-2xl font-black text-slate-800 tracking-tighter uppercase">Añadir Parada</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Introduce los datos del reparto</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-3 hover:bg-slate-200 rounded-2xl transition-all">
                <X size={24} className="text-slate-400" />
              </button>
            </div>
            <form onSubmit={handleAddDelivery} className="p-8 space-y-6 overflow-y-auto">
              <div className="flex bg-slate-100 p-1.5 rounded-3xl shrink-0">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex-1 py-4 rounded-2xl text-[10px] font-black tracking-widest transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>ENTREGA</button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex-1 py-4 rounded-2xl text-[10px] font-black tracking-widest transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>RECOGIDA</button>
              </div>

              {/* CAMPO NOMBRE */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nombre / Comercio</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                  <input 
                    type="text"
                    value={newNameInput}
                    onChange={(e) => setNewNameInput(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-base font-bold transition-all placeholder:text-slate-300"
                    placeholder="Ej: El Corte Inglés Elche"
                  />
                </div>
              </div>

              {/* CAMPO DIRECCIÓN */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Dirección Exacta</label>
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-24 p-6 border-2 border-slate-100 rounded-[30px] outline-none focus:border-blue-500 text-lg font-medium resize-none transition-all placeholder:text-slate-200" 
                    placeholder="Ej: Alcalde Ramón Pastor 2 Elche..." 
                  />
                  <button type="button" onClick={toggleListening} className={`absolute right-4 bottom-4 p-4 rounded-2xl transition-all shadow-sm ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}>
                    <Mic size={20} />
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Teléfono</label>
                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="tel" value={newPhoneInput} onChange={(e) => setNewPhoneInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Teléfono (opc)" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Plus Code o Link</label>
                  <div className="relative">
                    <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="text" value={newCoordsInput} onChange={(e) => setNewCoordsInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Ej: 8C7X+H3 Elche" />
                  </div>
                </div>
              </div>
              <button type="submit" disabled={isParsing || (!newAddressInput.trim() && !newCoordsInput.trim())} className="w-full py-5 bg-blue-600 text-white rounded-[30px] font-black text-lg flex justify-center items-center gap-4 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 mt-4 shrink-0 uppercase">
                {isParsing ? <Loader2 className="animate-spin" size={24} /> : <Plus size={24} />} 
                Añadir a la Ruta
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw, User } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newNameInput, setNewNameInput] = useState('');
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("GPS no disponible:", err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) {
      alert("Escribe una dirección o un Plus Code / Link.");
      return;
    }

    setIsParsing(true);
    try {
      const searchQuery = newNameInput ? `${newNameInput}, ${newAddressInput}` : newAddressInput;
      const parsed = await parseAddress(searchQuery, currentUserLoc, newCoordsInput);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substring(2, 9),
        recipient: newNameInput.trim() || parsed.recipient || newAddressInput || "Nueva Parada",
        address: parsed.address || newAddressInput || "Localización por código",
        phone: newPhoneInput.trim(),
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`,
      };
      setDeliveries(prev => [...prev, newDelivery]);
      setNewNameInput('');
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      console.error("Error en geocodificación:", error);
      alert(error.message || "No se pudo localizar el sitio. Intenta ser más específico o usa un Plus Code exacto.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación por completo.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    // Si se completa o es incidencia, lo quitamos de la secuencia de ruta activa para que se mueva al final
    if (status === DeliveryStatus.COMPLETED || status === DeliveryStatus.ISSUE) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    setManualSequence(prev => {
      if (prev.includes(id)) return prev;
      return [...prev, id];
    });
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const start = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Ubicación inicial";
      const result = await optimizeRoute(pending, start);
      if (result?.optimizedOrder) setManualSequence(result.optimizedOrder);
    } catch (e) {
      console.error(e);
    } finally {
      setIsOptimizing(false);
    }
  };

  const getSortedDeliveries = () => {
    // 1. Activas (Pendientes / En Progreso)
    const active = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const orderedActive = manualSequence.map(id => active.find(p => p.id === id)).filter((p): p is Delivery => !!p);
    const unorderedActive = active.filter(p => !manualSequence.includes(p.id));

    // 2. Incidencias
    const issues = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);

    // 3. Completados
    const completed = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

    return [...orderedActive, ...unorderedActive, ...issues, ...completed];
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <Power size={80} className="text-white mb-8 animate-pulse" />
        <h1 className="text-4xl font-black text-white mb-4 tracking-tighter uppercase">Sesión Finalizada</h1>
        <p className="text-slate-400 mb-10 max-w-sm font-medium">Todos los datos de ruta han sido eliminados del dispositivo.</p>
        <button onClick={() => window.location.reload()} className="bg-blue-600 text-white px-10 py-5 rounded-3xl font-black shadow-[0_20px_50px_rgba(37,99,235,0.3)] hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-4">
          <RefreshCcw size={24} /> NUEVA JORNADA
        </button>
      </div>
    );
  }

  const allSortedDeliveries = getSortedDeliveries();
  const pendingCount = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS).length;
  const issueCount = deliveries.filter(d => d.status === DeliveryStatus.ISSUE).length;
  const completedCount = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED).length;

  const viewLabels: { [key: string]: string } = {
    list: 'LISTA',
    map: 'MAPA',
    split: 'DIVIDIDO',
    control: 'CONTROL'
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 relative">
      <header className="bg-white border-b px-4 py-3 sm:px-6 sm:py-4 flex items-center justify-between z-30 shadow-sm gap-2">
        <div className="flex items-center gap-2 sm:gap-3 shrink-0">
          <div className="bg-blue-600 p-1.5 sm:p-2 rounded-lg sm:rounded-xl text-white shadow-md">
            <Truck size={18} className="sm:w-5 sm:h-5" />
          </div>
          <h1 className="text-lg sm:text-2xl font-black tracking-tighter text-slate-800">LogiRoute <span className="text-blue-600">AI</span></h1>
        </div>

        <div className="flex bg-slate-100 rounded-xl sm:rounded-2xl p-1 shadow-inner overflow-x-auto no-scrollbar">
          {['list', 'map', 'split', 'control'].map((mode) => (
            <button 
              key={mode} 
              onClick={() => setViewMode(mode as any)} 
              className={`px-3 sm:px-6 py-2 sm:py-2.5 rounded-lg sm:rounded-xl text-[9px] sm:text-[10px] font-black tracking-tighter sm:tracking-widest transition-all whitespace-nowrap ${viewMode === mode ? 'bg-white shadow-md text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {viewLabels[mode]}
            </button>
          ))}
        </div>

        <button onClick={() => setIsAdding(true)} className="bg-blue-600 text-white p-2 sm:px-5 sm:py-3 rounded-xl flex items-center gap-2 font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all text-[10px] shrink-0 uppercase">
          <Plus size={16} /> <span className="hidden md:inline">Nueva Parada</span>
        </button>
      </header>

      <main className={`flex-1 flex overflow-hidden ${viewMode === 'split' ? 'flex-col md:flex-row' : 'flex-row'}`}>
        {viewMode === 'control' ? (
          <div className="flex-1 p-6 md:p-12 overflow-y-auto bg-slate-50">
            <div className="max-w-5xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tighter uppercase">Panel Operativo</h2>
                  <p className="text-slate-500 font-bold text-lg">Métricas de la jornada actual</p>
                </div>
                <button 
                  onClick={handleClearAll} 
                  className="bg-red-600 text-white w-full md:w-auto px-10 py-5 rounded-[24px] font-black flex items-center justify-center gap-4 shadow-[0_15px_40px_rgba(220,38,38,0.3)] hover:bg-red-700 active:scale-95 transition-all text-lg uppercase"
                >
                  <LogOut size={24} /> Borrar y Cerrar
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-green-50 p-6 rounded-3xl text-green-600 mb-6">
                    <Package size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{completedCount}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Completados</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-yellow-50 p-6 rounded-3xl text-yellow-600 mb-6">
                    <AlertTriangle size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{issueCount}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Incidencias</p>
                </div>
                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-xl flex flex-col items-center text-center">
                  <div className="bg-blue-50 p-6 rounded-3xl text-blue-600 mb-6">
                    <Clock size={40} />
                  </div>
                  <span className="text-6xl font-black text-slate-800 tracking-tighter">{pendingCount}</span>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-widest mt-3">Pendientes</p>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <>
            <aside className={`
              ${viewMode === 'map' ? 'hidden' : ''} 
              ${viewMode === 'list' ? 'w-full' : ''} 
              ${viewMode === 'split' ? 'w-full md:w-[440px] h-1/2 md:h-full' : ''}
              border-r bg-white flex flex-col overflow-hidden shadow-2xl z-20 transition-all
            `}>
              <div className="p-5 bg-slate-50/80 border-b flex justify-between items-center backdrop-blur-sm">
                <div className="flex flex-col">
                  <h2 className="font-black text-[11px] uppercase tracking-[0.2em] text-slate-400">Ruta de Reparto</h2>
                  <span className="text-[9px] text-blue-500 font-bold uppercase mt-0.5">{pendingCount} tareas pendientes</span>
                </div>
                <button onClick={handleOptimize} disabled={isOptimizing || pendingCount < 2} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black border-none flex items-center gap-2 hover:bg-blue-700 disabled:opacity-30 transition-all shadow-lg active:scale-95">
                  {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <BrainCircuit size={14} />} OPTIMIZAR
                </button>
              </div>
              <div className="flex-1 overflow-y-auto p-5 space-y-4">
                {allSortedDeliveries.length === 0 && (
                  <div className="text-center py-12 md:py-24 opacity-20 flex flex-col items-center">
                    <Navigation size={64} className="mb-6" />
                    <p className="text-lg font-black tracking-widest">SIN PARADAS</p>
                  </div>
                )}
                {allSortedDeliveries.map((d) => (
                  <DeliveryCard 
                    key={d.id} 
                    index={manualSequence.indexOf(d.id)} 
                    delivery={d} 
                    isSelected={selectedId === d.id} 
                    onClick={() => setSelectedId(d.id)} 
                    onStatusChange={handleStatusChange} 
                    onDelete={(id) => setDeliveries(prev => prev.filter(x => x.id !== id))} 
                    onRemoveFromSequence={(id) => setManualSequence(prev => prev.filter(x => x !== id))}
                    onDragStart={() => {}} onDragOver={() => {}} onDragEnd={() => {}}
                  />
                ))}
              </div>
            </aside>
            <section className={`
              ${viewMode === 'list' ? 'hidden' : ''} 
              ${viewMode === 'map' ? 'flex-1' : ''} 
              ${viewMode === 'split' ? 'flex-1 h-1/2 md:h-full' : ''}
              relative transition-all
            `}>
              <MapView 
                deliveries={deliveries} 
                manualSequence={manualSequence} 
                selectedId={selectedId} 
                onMarkerClick={handleMarkerClick} 
                viewMode={viewMode} 
              />
            </section>
          </>
        )}
      </main>

      <button 
        onClick={() => setIsAdding(true)}
        className="fixed bottom-6 right-6 sm:bottom-10 sm:right-10 w-16 h-16 sm:w-20 sm:h-20 bg-blue-600 text-white rounded-2xl sm:rounded-[28px] shadow-2xl flex items-center justify-center hover:bg-blue-700 hover:scale-110 active:scale-90 transition-all z-40"
      >
        <Plus size={32} />
      </button>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[40px] w-full max-w-xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50/40 shrink-0">
              <div>
                <h3 className="text-2xl font-black text-slate-800 tracking-tighter uppercase">Añadir Parada</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Introduce los datos del reparto</p>
              </div>
              <button onClick={() => setIsAdding(false)} className="p-3 hover:bg-slate-200 rounded-2xl transition-all">
                <X size={24} className="text-slate-400" />
              </button>
            </div>
            <form onSubmit={handleAddDelivery} className="p-8 space-y-6 overflow-y-auto">
              <div className="flex bg-slate-100 p-1.5 rounded-3xl shrink-0">
                <button type="button" onClick={() => setNewType(DeliveryType.DELIVERY)} className={`flex-1 py-4 rounded-2xl text-[10px] font-black tracking-widest transition-all ${newType === DeliveryType.DELIVERY ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>ENTREGA</button>
                <button type="button" onClick={() => setNewType(DeliveryType.PICKUP)} className={`flex-1 py-4 rounded-2xl text-[10px] font-black tracking-widest transition-all ${newType === DeliveryType.PICKUP ? 'bg-red-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>RECOGIDA</button>
              </div>

              {/* CAMPO NOMBRE */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nombre / Comercio</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                  <input 
                    type="text"
                    value={newNameInput}
                    onChange={(e) => setNewNameInput(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-base font-bold transition-all placeholder:text-slate-300"
                    placeholder="Ej: El Corte Inglés Elche"
                  />
                </div>
              </div>

              {/* CAMPO DIRECCIÓN */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Dirección Exacta</label>
                <div className="relative">
                  <textarea 
                    value={newAddressInput} 
                    onChange={(e) => setNewAddressInput(e.target.value)} 
                    className="w-full h-24 p-6 border-2 border-slate-100 rounded-[30px] outline-none focus:border-blue-500 text-lg font-medium resize-none transition-all placeholder:text-slate-200" 
                    placeholder="Ej: Alcalde Ramón Pastor 2 Elche..." 
                  />
                  <button type="button" onClick={toggleListening} className={`absolute right-4 bottom-4 p-4 rounded-2xl transition-all shadow-sm ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}>
                    <Mic size={20} />
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Teléfono</label>
                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="tel" value={newPhoneInput} onChange={(e) => setNewPhoneInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Teléfono (opc)" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Plus Code o Link</label>
                  <div className="relative">
                    <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                    <input type="text" value={newCoordsInput} onChange={(e) => setNewCoordsInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium transition-all" placeholder="Ej: 8C7X+H3 Elche" />
                  </div>
                </div>
              </div>
              <button type="submit" disabled={isParsing || (!newAddressInput.trim() && !newCoordsInput.trim())} className="w-full py-5 bg-blue-600 text-white rounded-[30px] font-black text-lg flex justify-center items-center gap-4 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 mt-4 shrink-0 uppercase">
                {isParsing ? <Loader2 className="animate-spin" size={24} /> : <Plus size={24} />} 
                Añadir a la Ruta
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw, User } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newNameInput, setNewNameInput] = useState('');
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("GPS no disponible:", err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAddressInput.trim() && !newCoordsInput.trim()) {
      alert("Escribe una dirección o un Plus Code / Link.");
      return;
    }

    setIsParsing(true);
    try {
      const searchQuery = newNameInput ? `${newNameInput}, ${newAddressInput}` : newAddressInput;
      const parsed = await parseAddress(searchQuery, currentUserLoc, newCoordsInput);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substring(2, 9),
        recipient: newNameInput.trim() || parsed.recipient || newAddressInput || "Nueva Parada",
        address: parsed.address || newAddressInput || "Localización por código",
        phone: newPhoneInput.trim(),
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`,
      };
      setDeliveries(prev => [...prev, newDelivery]);
      setNewNameInput('');
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      console.error("Error en geocodificación:", error);
      alert(error.message || "No se pudo localizar el sitio. Intenta ser más específico o usa un Plus Code exacto.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación por completo.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    // Si se completa o es incidencia, lo quitamos de la secuencia de ruta activa para que se mueva al final
    if (status === DeliveryStatus.COMPLETED || status === DeliveryStatus.ISSUE) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    setManualSequence(prev => {
      // Si la parada ya está en la secuencia, la quitamos (Deseleccionar)
      if (prev.includes(id)) {
        return prev.filter(sid => sid !== id);
      }
      // Si no está, la añadimos al final (Seleccionar)
      return [...prev, id];
    });
  };

  const handleOptimize = async () => {
    const pending = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    if (pending.length < 2) return;
    setIsOptimizing(true);
    try {
      const start = currentUserLoc ? `${currentUserLoc.latitude},${currentUserLoc.longitude}` : "Ubicación inicial";
      const result = await optimizeRoute(pending, start);
      if (result?.optimizedOrder) setManualSequence(result.optimizedOrder);
    } catch (e) {
      console.error(e);
    } finally {
      setIsOptimizing(false);
    }
  };

  const getSortedDeliveries = () => {
    // 1. Activas (Pendientes / En Progreso)
    const active = deliveries.filter(d => d.status === DeliveryStatus.PENDING || d.status === DeliveryStatus.IN_PROGRESS);
    const orderedActive = manualSequence.map(id => active.find(p => p.id === id)).filter((p): p is Delivery => !!p);
    const unorderedActive = active.filter(p => !manualSequence.includes(p.id));

    // 2. Incidencias
    const issues = deliveries.filter(d => d.status === DeliveryStatus.ISSUE);

    // 3. Completados
    const completed = deliveries.filter(d => d.status === DeliveryStatus.COMPLETED);

    return [...orderedActive, ...unorderedActive, ...issues, ...completed];
  };

  if (isAppClosed) {
    return (
      <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center text-center p-6 z-[200]">
        <Power size={80} className="text-white mb-8 animate-pulse" />
        <h1 className="text-4xl font-black text-white mb-4 tracking-tighter uppercase">Sesión Finalizada</h1>
        <p className="text-slate-400 mb-10 max-w-sm font-medium">Todos los datos de ruta han sido eliminados del dispositivo.</p>
