import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Valida si un valor es una coordenada numérica finita
 */
const isValidCoord = (val: any): boolean => {
  const num = parseFloat(val);
  return !isNaN(num) && Number.isFinite(num);
};

/**
 * Detecta si un string tiene formato de Plus Code (ej: 8C7X+H3 o 8C7X+H3 Elche)
 */
const isPlusCode = (input: string): boolean => {
  const plusCodeRegex = /[23456789CFGHJMPQRVWX]{4,8}\+[23456789CFGHJMPQRVWX]{2,}/i;
  return plusCodeRegex.test(input);
};

/**
 * Extrae coordenadas de una URL de Google Maps o enlaces similares
 */
const extractFromUrl = (url: string) => {
  if (!url) return null;

  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (isValidCoord(lat) && isValidCoord(lng)) {
        return { lat, lng };
      }
    }
  }
  return null;
};

/**
 * Optimiza la ruta utilizando Gemini 3 Pro
 */
export const optimizeRoute = async (
  deliveries: Delivery[],
  startLocation: string
) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Optimiza esta ruta de reparto iniciando en ${startLocation}. Entregas: ${JSON.stringify(
        deliveries.map((d) => ({ id: d.id, address: d.address }))
      )}. Devuelve JSON con 'optimizedOrder' (lista de IDs en orden lógico para minimizar tiempo y distancia).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimizedOrder: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
            },
            reasoning: { type: Type.STRING },
          },
          required: ["optimizedOrder"],
        },
      },
    });

    const text = response.text;
    if (text) return JSON.parse(text);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  } catch (e) {
    console.error("Error en optimización AI:", e);
    return { optimizedOrder: deliveries.map((d) => d.id) };
  }
};

/**
 * Geocodifica una dirección usando Google Maps y Search Grounding simultáneamente.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  notes: string;
}> => {
  const elcheCoords = { latitude: 38.2622, longitude: -0.6993 };
  const anchor = userLocation || elcheCoords;

  // 1. Prioridad: Coordenadas manuales en el input de link
  const manual = extractFromUrl(manualInput || "");
  if (manual) {
    return {
      recipient: input || "Ubicación directa",
      address: input || "Coordenadas manuales",
      lat: manual.lat,
      lng: manual.lng,
      sourceUrl: manualInput?.includes("http") ? manualInput : `https://www.google.com/maps/search/?api=1&query=${manual.lat},${manual.lng}`,
      notes: "",
    };
  }

  // 2. Búsqueda con Herramientas de Grounding
  try {
    const isPlus = manualInput ? isPlusCode(manualInput) : false;
    const finalSearchQuery = isPlus ? manualInput! : (input || manualInput || "");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Identifica la ubicación para: "${finalSearchQuery}". 
      Instrucciones críticas:
      1. Si es un Plus Code, resuélvelo.
      2. Extrae el nombre oficial del establecimiento.
      3. Extrae la DIRECCIÓN FÍSICA REAL (calle, número, ciudad).
      4. Responde siguiendo estrictamente este formato al principio de tu respuesta:
         NAME: [Nombre del Sitio] | ADDRESS: [Calle, Número, Ciudad]
      5. Si no se especifica ciudad, asume que está en la zona de Elche/Alicante.`,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude },
          },
        },
      },
    });

    const textResponse = response.text || "";
    let extractedName = "";
    let extractedAddress = "";

    // Intentar extraer del formato solicitado "NAME: ... | ADDRESS: ..."
    const nameMatch = textResponse.match(/NAME:\s*(.*?)\s*\|/);
    const addressMatch = textResponse.match(/ADDRESS:\s*(.*)/);

    if (nameMatch) extractedName = nameMatch[1].trim();
    if (addressMatch) {
        // Limpiar posibles restos de markdown o texto extra
        extractedAddress = addressMatch[1].split('\n')[0].trim();
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    let finalCoords: { lat: number, lng: number } | null = null;
    let mapsUri = "";

    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromUrl(chunk.maps.uri);
          if (coords) {
            finalCoords = coords;
            mapsUri = chunk.maps.uri;
            // Si no pudimos extraer nombre/dirección del texto, usamos los de Maps
            if (!extractedName) extractedName = chunk.maps.title || "";
            if (!extractedAddress) extractedAddress = chunk.maps.title || "";
            break;
          }
        }
      }
    }

    // Si aún no tenemos coordenadas pero sí texto, intentamos extraer del texto
    if (!finalCoords) {
        finalCoords = extractFromUrl(textResponse);
    }

    if (finalCoords) {
      return {
        recipient: extractedName || input || "Ubicación encontrada",
        address: extractedAddress || input || "Dirección encontrada",
        lat: finalCoords.lat,
        lng: finalCoords.lng,
        sourceUrl: mapsUri || `https://www.google.com/maps/search/?api=1&query=${finalCoords.lat},${finalCoords.lng}`,
        notes: ""
      };
    }

    throw new Error("No se pudo localizar el sitio. Revisa el Plus Code o el nombre del sitio.");
  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error(error.message || "Error al buscar la ubicación.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw, User } from 'lucide-react';
import MapView from './components/MapView';
import DeliveryCard from './components/DeliveryCard';
import { Delivery, DeliveryStatus, DeliveryType } from './types';
import { parseAddress, optimizeRoute } from './services/geminiService';

const STORAGE_KEY = 'logiroute_deliveries_v3';
const VIEW_MODE_KEY = 'logiroute_viewmode_v1';
const SEQUENCE_KEY = 'logiroute_sequence_v1';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [manualSequence, setManualSequence] = useState<string[]>(() => {
    const saved = localStorage.getItem(SEQUENCE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [viewMode, setViewMode] = useState<'split' | 'map' | 'list' | 'control'>(() => {
    const saved = localStorage.getItem(VIEW_MODE_KEY);
    return (saved as any) || 'split';
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newNameInput, setNewNameInput] = useState('');
  const [newAddressInput, setNewAddressInput] = useState('');
  const [newPhoneInput, setNewPhoneInput] = useState('');
  const [newCoordsInput, setNewCoordsInput] = useState('');
  const [newType, setNewType] = useState<DeliveryType>(DeliveryType.DELIVERY);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isParsing, setIsParsing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isAppClosed, setIsAppClosed] = useState(false);
  const [currentUserLoc, setCurrentUserLoc] = useState<{latitude: number, longitude: number} | undefined>(undefined);

  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (isAppClosed) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(deliveries));
    localStorage.setItem(SEQUENCE_KEY, JSON.stringify(manualSequence));
    localStorage.setItem(VIEW_MODE_KEY, viewMode);
  }, [deliveries, manualSequence, viewMode, isAppClosed]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setCurrentUserLoc({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("GPS no disponible:", err.message),
        { enableHighAccuracy: true }
      );
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'es-ES';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setNewAddressInput(prev => prev ? `${prev} ${transcript}` : transcript);
        setIsListening(false);
      };

      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }
    if (isListening) recognitionRef.current.stop();
    else { setIsListening(true); recognitionRef.current.start(); }
  };

  const handleAddDelivery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNameInput.trim() && !newAddressInput.trim() && !newCoordsInput.trim()) {
      alert("Escribe un nombre de sitio, dirección o Plus Code.");
      return;
    }

    setIsParsing(true);
    try {
      // Priorizamos el nombre si existe para la búsqueda
      const searchQuery = newNameInput.trim() || newAddressInput.trim();
      const parsed = await parseAddress(searchQuery, currentUserLoc, newCoordsInput);

      const newDelivery: Delivery = {
        id: Math.random().toString(36).substring(2, 9),
        // Si el usuario puso un nombre manual, lo respetamos, si no usamos el encontrado por la IA
        recipient: newNameInput.trim() || parsed.recipient,
        // La dirección siempre intentamos que sea la oficial encontrada
        address: parsed.address || newAddressInput || "Dirección no disponible",
        phone: newPhoneInput.trim(),
        coordinates: [parsed.lat, parsed.lng],
        status: DeliveryStatus.PENDING,
        type: newType,
        notes: parsed.notes || "",
        sourceUrl: parsed.sourceUrl || "",
        estimatedTime: `${Math.floor(Math.random() * 4) + 1} h aprox.`,
      };
      setDeliveries(prev => [...prev, newDelivery]);
      setNewNameInput('');
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
    } catch (error: any) {
      console.error("Error en geocodificación:", error);
      alert(error.message || "No se pudo localizar el sitio. Intenta ser más específico.");
    } finally {
      setIsParsing(false);
    }
  };

  const handleClearAll = () => {
    if (window.confirm("¿BORRAR Y CERRAR? Se eliminarán todas las paradas y se reiniciará la aplicación por completo.")) {
      setIsAppClosed(true);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleStatusChange = (id: string, status: DeliveryStatus) => {
    setDeliveries(prev => prev.map(d => d.id === id ? { ...d, status } : d));
    // Si se completa o es incidencia, lo quitamos de la secuencia de ruta activa para que se mueva al final
    if (status === DeliveryStatus.COMPLETED || status === DeliveryStatus.ISSUE) {
      setManualSequence(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleMarkerClick = (id: string) => {
    setSelectedId(id);
    setManualSequence(prev => {
      // Si la parada ya está en la secuencia, la quitamos (Deseleccionar)
      if (prev.includes(id)) {
