import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Detecta si un string tiene formato de Plus Code o es una URL de Maps
 */
const extractFromText = (text: string) => {
  if (!text) return null;
  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (!isNaN(lat) && !isNaN(lng)) return { lat, lng };
    }
  }
  return null;
};

/**
 * Busca un lugar real usando Grounding de Google Maps y Search
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoordsInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
}> => {
  // Coordenadas de Elche como ancla por defecto
  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  // 1. Si hay coordenadas manuales (Plus Code o Link)
  if (manualCoordsInput) {
    const coords = extractFromText(manualCoordsInput);
    if (coords) {
      return {
        recipient: input || "Ubicación directa",
        address: input || "Coordenadas manuales",
        lat: coords.lat,
        lng: coords.lng,
        sourceUrl: manualCoordsInput.includes('http') ? manualCoordsInput : `https://www.google.com/maps/search/?api=1&query=${coords.lat},${coords.lng}`
      };
    }
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca el lugar: "${input}" en Elche, España. 
      Instrucción Crítica: Necesito el NOMBRE OFICIAL del sitio y su DIRECCIÓN POSTAL EXACTA (calle y número).
      Responde con este formato: [NOMBRE] | [DIRECCIÓN COMPLETA]`,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        }
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    let lat = anchor.latitude;
    let lng = anchor.longitude;
    let recipient = input;
    let address = input;
    let sourceUrl = "";

    // Intentar sacar info de grounding chunks (Google Maps Tool)
    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractFromText(chunk.maps.uri);
          if (coords) {
            lat = coords.lat;
            lng = coords.lng;
            recipient = chunk.maps.title || recipient;
            address = chunk.maps.title || address;
            sourceUrl = chunk.maps.uri;
            break;
          }
        }
      }
    }

    // Si el texto tiene el formato [NOMBRE] | [DIRECCIÓN], lo usamos para limpiar la UI
    if (text.includes('|')) {
      const parts = text.split('|');
      recipient = parts[0].replace(/\[|\]/g, '').trim();
      address = parts[1].replace(/\[|\]/g, '').trim();
    }

    return {
      recipient,
      address,
      lat,
      lng,
      sourceUrl: sourceUrl || `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`
    };

  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error("No se pudo localizar el sitio. Intenta ser más específico.");
  }
};

/**
 * Optimiza la ruta utilizando razonamiento de Gemini 3
 */
export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Optimiza esta ruta de reparto. Inicio: ${startLocation}. Paradas: ${JSON.stringify(deliveries.map(d => ({id: d.id, addr: d.address})))}. Devuelve solo JSON con 'order' (lista de IDs).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            order: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["order"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result.order as string[];
  } catch (e) {
    return deliveries.map(d => d.id);
  }
};

