import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Extrae coordenadas (Latitud y Longitud) de un texto o URL de Google Maps.
 */
const extractCoordsFromText = (text: string) => {
  if (!text) return null;

  // Patrones comunes en URLs de Google Maps y respuestas de texto
  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,                 // Formato @38.123,-0.456
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,           // Formato query=38.123,-0.456
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,              // Formato ll=38.123,-0.456
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,               // Formato q=38.123,-0.456
    /!3d(-?\d+\.\d+)!4d(-?\d+\.\d+)/,                  // Formato interno de Maps !3d...!4d...
    /\[\s*(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)\s*\]/,       // Formato [38.123, -0.456]
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/                  // Formato simple 38.123, -0.456
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (!isNaN(lat) && !isNaN(lng) && Math.abs(lat) <= 90 && Math.abs(lng) <= 180) {
        return { lat, lng };
      }
    }
  }
  return null;
};

/**
 * Busca un lugar real usando Grounding de Google Maps y Search.
 * Se asegura de que las coordenadas correspondan al sitio y no al usuario.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoordsInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
}> => {
  // Ancla para la búsqueda (preferiblemente donde está el repartidor)
  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  // 1. Prioridad: Entrada manual de Plus Code o enlace directo
  if (manualCoordsInput) {
    const coords = extractCoordsFromText(manualCoordsInput);
    if (coords) {
      return {
        recipient: input || "Ubicación directa",
        address: input || "Coordenadas manuales",
        lat: coords.lat,
        lng: coords.lng,
        sourceUrl: manualCoordsInput.includes('http') ? manualCoordsInput : `https://www.google.com/maps/search/?api=1&query=${coords.lat},${coords.lng}`
      };
    }
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Busca el lugar exacto: "${input}". 
      Instrucciones Críticas: 
      1. Obtén el NOMBRE OFICIAL del establecimiento.
      2. Obtén la DIRECCIÓN POSTAL REAL (calle, número, ciudad).
      3. Obtén las coordenadas GEOGRÁFICAS (Latitud y Longitud) exactas del sitio.
      Responde siguiendo estrictamente este formato: [NOMBRE] | [DIRECCIÓN COMPLETA] | [LATITUD, LONGITUD]`,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        }
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    let finalLat: number | null = null;
    let finalLng: number | null = null;
    let recipient = "";
    let address = "";
    let sourceUrl = "";

    // 2. Extraer info de Grounding (Google Maps Tool) - Es lo más preciso
    if (groundingChunks && groundingChunks.length > 0) {
      for (const chunk of groundingChunks) {
        if (chunk.maps && chunk.maps.uri) {
          const coords = extractCoordsFromText(chunk.maps.uri);
          if (coords) {
            finalLat = coords.lat;
            finalLng = coords.lng;
            recipient = chunk.maps.title || recipient;
            address = chunk.maps.title || address;
            sourceUrl = chunk.maps.uri;
            break;
          }
        }
      }
    }

    // 3. Si no hay grounding exitoso, intentar parsear el formato [NOMBRE] | [DIRECCIÓN] | [LAT, LNG]
    if (text.includes('|')) {
      const parts = text.split('|').map(p => p.trim());
      if (parts.length >= 2) {
        recipient = parts[0].replace(/\[|\]/g, '');
        address = parts[1].replace(/\[|\]/g, '');

        // Si aún no tenemos coordenadas, las buscamos en la tercera parte del texto
        if (!finalLat && parts.length >= 3) {
          const coords = extractCoordsFromText(parts[2]);
          if (coords) {
            finalLat = coords.lat;
            finalLng = coords.lng;
          }
        }
      }
    }

    // 4. Último recurso: buscar cualquier coordenada en el texto completo de la respuesta
    if (!finalLat) {
      const coords = extractCoordsFromText(text);
      if (coords) {
        finalLat = coords.lat;
        finalLng = coords.lng;
      }
    }

    // Validación final: Si no encontramos coordenadas del sitio, no podemos guardarlo mal.
    if (!finalLat || !finalLng) {
      throw new Error("No se pudo obtener la ubicación exacta en el mapa. Por favor, sé más específico con el nombre o dirección.");
    }

    return {
      recipient: recipient || input,
      address: address || input,
      lat: finalLat,
      lng: finalLng,
      sourceUrl: sourceUrl || `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`
    };

  } catch (error: any) {
    console.error("[Geocoding Error]", error);
    throw new Error(error.message || "Error al localizar el sitio.");
  }
};

/**
 * Optimiza la ruta utilizando razonamiento de Gemini.
 */
export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Optimiza esta ruta de reparto. Inicio: ${startLocation}. Paradas: ${JSON.stringify(deliveries.map(d => ({id: d.id, addr: d.address})))}. Devuelve solo JSON con 'order' (lista de IDs).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            order: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["order"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result.order as string[];
  } catch (e) {
    return deliveries.map(d => d.id);
  }
};

