                  <button type="button" onClick={toggleListening} className={`absolute right-4 bottom-4 p-4 rounded-2xl transition-all shadow-sm ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-400 hover:text-blue-500'}`}><Mic size={20} /></button>
                </div>
