                  <div className="relative"><Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} /><input type="tel" value={newPhoneInput} onChange={(e) => setNewPhoneInput(e.target.value)} className="w-full pl-10 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium" placeholder="Teléfono" /></div>
                </div>
