                  <div className="relative"><MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} /><input type="text" value={newCoordsInput} onChange={(e) => setNewCoordsInput(e.target.value)} className="w-full pl-10 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium" placeholder="Ej: 8C7X+H3" /></div>
                </div>
              </div>
              <button type="submit" disabled={isParsing || (!newNameInput.trim() && !newAddressInput.trim() && !newCoordsInput.trim())} className="w-full py-5 bg-blue-600 text-white rounded-[30px] font-black text-lg flex justify-center items-center gap-4 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 uppercase">
                {isParsing ? <Loader2 className="animate-spin" size={24} /> : <Plus size={24} />} 
                Añadir a la Ruta
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

