 */
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Envoltorio para peticiones a la API con lógica de reintento (Exponential Backoff).
 * Maneja específicamente el error 429 (Resource Exhausted).
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorMsg = error.message || "";
      const isQuotaError = errorMsg.includes("429") || errorMsg.includes("RESOURCE_EXHAUSTED") || (error.status === 429);

      if (isQuotaError && i < maxRetries - 1) {
        // Espera incremental: 2s, 4s, 8s...
        const waitTime = Math.pow(2, i + 1) * 1000;
        console.warn(`Cuota excedida. Reintentando en ${waitTime / 1000}s... (Intento ${i + 1}/${maxRetries})`);
        await sleep(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

/**
 * Extrae coordenadas (Latitud y Longitud) de un texto o URL de Google Maps.
 */
const extractCoordsFromText = (text: string) => {
  if (!text) return null;

  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /!3d(-?\d+\.\d+)!4d(-?\d+\.\d+)/,
    /\[\s*(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)\s*\]/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (!isNaN(lat) && !isNaN(lng) && Math.abs(lat) <= 90 && Math.abs(lng) <= 180) {
        return { lat, lng };
      }
    }
  }
  return null;
};

/**
 * Busca un lugar real usando Grounding de Google Maps y Search.
 * Extrae Nombre, Dirección, Coordenadas y Teléfono.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoordsInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  phone?: string;
}> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  if (manualCoordsInput) {
    const coords = extractCoordsFromText(manualCoordsInput);
    if (coords) {
      return {
        recipient: input || "Ubicación directa",
        address: input || "Coordenadas manuales",
        lat: coords.lat,
        lng: coords.lng,
        sourceUrl: manualCoordsInput.includes('http') ? manualCoordsInput : `https://www.google.com/maps/search/?api=1&query=${coords.lat},${coords.lng}`
      };
    }
  }

  return withRetry(async () => {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Busca el lugar exacto y sus datos de contacto: "${input}". 
        Instrucciones Críticas: 
        1. Obtén el NOMBRE OFICIAL del establecimiento.
        2. Obtén la DIRECCIÓN POSTAL REAL (calle, número, ciudad).
        3. Obtén las coordenadas GEOGRÁFICAS (Latitud y Longitud) exactas.
        4. Obtén el TELÉFONO de contacto si está disponible.
        Responde siguiendo estrictamente este formato: [NOMBRE] | [DIRECCIÓN COMPLETA] | [LATITUD, LONGITUD] | [TELÉFONO]`,
        config: {
          tools: [{ googleMaps: {} }, { googleSearch: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
            }
          }
        },
      });

      const text = response.text || "";
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      let finalLat: number | null = null;
      let finalLng: number | null = null;
      let recipient = "";
      let address = "";
      let sourceUrl = "";
      let phone = "";

      // 1. Extraer del texto estructurado [NOMBRE] | [DIRECCIÓN] | [LAT, LNG] | [TEL]
      if (text.includes('|')) {
        const parts = text.split('|').map(p => p.trim());
        if (parts.length >= 2) {
          recipient = parts[0].replace(/\[|\]/g, '');
          address = parts[1].replace(/\[|\]/g, '');

          if (parts.length >= 3) {
            const coords = extractCoordsFromText(parts[2]);
            if (coords) {
              finalLat = coords.lat;
              finalLng = coords.lng;
            }
          }
          if (parts.length >= 4) {
            phone = parts[3].replace(/\[|\]/g, '').replace(/No disponible|N\/A|None/i, '').trim();
          }
        }
      }

      // 2. Refinar con Grounding si no hay coordenadas o faltan datos
      if (groundingChunks && groundingChunks.length > 0) {
        for (const chunk of groundingChunks) {
          if (chunk.maps && chunk.maps.uri) {
            const coords = extractCoordsFromText(chunk.maps.uri);
            if (coords && !finalLat) {
              finalLat = coords.lat;
              finalLng = coords.lng;
              sourceUrl = chunk.maps.uri;
            }
            if (!recipient) recipient = chunk.maps.title || recipient;
            if (!address) address = chunk.maps.title || address;
          }
        }
      }

      // 3. Fallback: buscar cualquier número de teléfono en el texto si no se extrajo bien
      if (!phone) {
        const phoneMatch = text.match(/(?:\+34|0034|34)?[6789]\d{8}/);
        if (phoneMatch) phone = phoneMatch[0];
      }

      if (!finalLat || !finalLng) {
        const coords = extractCoordsFromText(text);
        if (coords) {
          finalLat = coords.lat;
          finalLng = coords.lng;
        }
      }

      if (!finalLat || !finalLng) {
        throw new Error("No se pudo obtener la ubicación exacta en el mapa.");
      }

      return {
        recipient: recipient || input,
        address: address || input,
        lat: finalLat,
        lng: finalLng,
        sourceUrl: sourceUrl || `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`,
        phone: phone || undefined
      };
    } catch (err: any) {
      // Si el error es un objeto JSON en string, lo parseamos para un mensaje más limpio
      let message = err.message || "Error desconocido";
      try {
        const parsed = JSON.parse(message);
        if (parsed.error?.message) message = parsed.error.message;
      } catch (e) {}
      throw new Error(message);
    }
  });
};

/**
 * Optimiza la ruta utilizando razonamiento de Gemini.
 */
export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return withRetry(async () => {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Optimiza esta ruta de reparto. Inicio: ${startLocation}. Paradas: ${JSON.stringify(deliveries.map(d => ({id: d.id, addr: d.address})))}. Devuelve solo JSON con 'order' (lista de IDs).`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              order: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["order"]
          }
        }
      });

      const result = JSON.parse(response.text);
      return result.order as string[];
    } catch (e) {
      console.error("Error en optimización:", e);
      return deliveries.map(d => d.id);
    }
  });
};

