      setDeliveries(prev => [...prev, newDelivery]);
      setNewNameInput('');
      setNewAddressInput('');
      setNewPhoneInput('');
      setNewCoordsInput('');
      setIsAdding(false);
      setSelectedId(newDelivery.id);
