import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

/**
 * Función de utilidad para esperar un tiempo determinado.
 */
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Envoltorio para peticiones a la API con lógica de reintento mejorada.
 * Maneja específicamente el error 429 (Resource Exhausted).
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 5): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorMsg = typeof error === 'string' ? error : (error.message || "");

      // Detección robusta de error de cuota (429)
      const isQuotaError = 
        errorMsg.includes("429") || 
        errorMsg.includes("RESOURCE_EXHAUSTED") || 
        errorMsg.includes("quota") ||
        (error.status === 429) ||
        (typeof error === 'object' && error?.error?.code === 429);

      if (isQuotaError && i < maxRetries - 1) {
        // Espera incremental más larga para el free tier: 3s, 6s, 12s, 24s...
        const waitTime = Math.pow(2, i) * 3000;
        console.warn(`Límite de cuota detectado. Reintentando en ${waitTime / 1000}s... (Intento ${i + 1}/${maxRetries})`);
        await sleep(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

/**
 * Extrae coordenadas (Latitud y Longitud) de un texto o URL de Google Maps.
 */
const extractCoordsFromText = (text: string) => {
  if (!text) return null;

  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /ll=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /q=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /!3d(-?\d+\.\d+)!4d(-?\d+\.\d+)/,
    /\[\s*(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)\s*\]/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (!isNaN(lat) && !isNaN(lng) && Math.abs(lat) <= 90 && Math.abs(lng) <= 180) {
        return { lat, lng };
      }
    }
  }
  return null;
};

/**
 * Busca un lugar real usando Grounding de Google Maps y Search.
 * Extrae Nombre, Dirección, Coordenadas y Teléfono.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoordsInput?: string
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  phone?: string;
}> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  if (manualCoordsInput) {
    const coords = extractCoordsFromText(manualCoordsInput);
    if (coords) {
      return {
        recipient: input || "Ubicación directa",
        address: input || "Coordenadas manuales",
        lat: coords.lat,
        lng: coords.lng,
        sourceUrl: manualCoordsInput.includes('http') ? manualCoordsInput : `https://www.google.com/maps/search/?api=1&query=${coords.lat},${coords.lng}`
      };
    }
  }

  return withRetry(async () => {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Busca el lugar exacto: "${input}". 
        Formato requerido: [NOMBRE] | [DIRECCIÓN] | [LATITUD, LONGITUD] | [TELÉFONO]`,
        config: {
          tools: [{ googleMaps: {} }, { googleSearch: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
            }
          },
          temperature: 0.1, // Menor temperatura para respuestas más consistentes
        },
      });

      const text = response.text || "";
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      let finalLat: number | null = null;
      let finalLng: number | null = null;
      let recipient = "";
      let address = "";
      let sourceUrl = "";
      let phone = "";

      // 1. Extraer del texto estructurado
      if (text.includes('|')) {
        const parts = text.split('|').map(p => p.trim());
        if (parts.length >= 2) {
          recipient = parts[0].replace(/\[|\]/g, '');
          address = parts[1].replace(/\[|\]/g, '');

          if (parts.length >= 3) {
            const coords = extractCoordsFromText(parts[2]);
            if (coords) {
              finalLat = coords.lat;
              finalLng = coords.lng;
            }
          }
          if (parts.length >= 4) {
            phone = parts[3].replace(/\[|\]/g, '').replace(/No disponible|N\/A|None|null/i, '').trim();
          }
        }
      }

      // 2. Refinar con Grounding
      if (groundingChunks && groundingChunks.length > 0) {
        for (const chunk of groundingChunks) {
          if (chunk.maps && chunk.maps.uri) {
            const coords = extractCoordsFromText(chunk.maps.uri);
            if (coords && !finalLat) {
              finalLat = coords.lat;
              finalLng = coords.lng;
              sourceUrl = chunk.maps.uri;
            }
            if (!recipient) recipient = chunk.maps.title || recipient;
            if (!address) address = chunk.maps.title || address;
          }
        }
      }

      // 3. Fallback de teléfono
      if (!phone) {
        const phoneMatch = text.match(/(?:\+34|0034|34)?[6789]\d{8}/);
        if (phoneMatch) phone = phoneMatch[0];
      }

      if (!finalLat || !finalLng) {
        const coords = extractCoordsFromText(text);
        if (coords) {
          finalLat = coords.lat;
          finalLng = coords.lng;
        }
      }

      if (!finalLat || !finalLng) {
        throw new Error("No se pudo obtener la ubicación exacta en el mapa. Por favor, intenta ser más específico con el nombre.");
      }

      return {
        recipient: recipient || input,
        address: address || input,
        lat: finalLat,
        lng: finalLng,
        sourceUrl: sourceUrl || `https://www.google.com/maps/search/?api=1&query=${finalLat},${finalLng}`,
        phone: phone || undefined
      };
    } catch (err: any) {
      let rawMsg = err.message || "";
      let cleanMsg = "Error en la conexión con la IA.";

      // Si el error es un JSON escapado en un string
      try {
        if (rawMsg.includes('{')) {
          const start = rawMsg.indexOf('{');
          const end = rawMsg.lastIndexOf('}') + 1;
          const jsonPart = rawMsg.substring(start, end);
          const parsed = JSON.parse(jsonPart);
          if (parsed.error?.message) cleanMsg = parsed.error.message;
          if (parsed.error?.code === 429) cleanMsg = "Límite de cuota excedido. Por favor, espera 60 segundos.";
        } else {
          cleanMsg = rawMsg;
        }
      } catch (e) {
        cleanMsg = rawMsg;
      }

      throw new Error(cleanMsg);
    }
  });
};

/**
 * Optimiza la ruta utilizando razonamiento de Gemini.
 */
export const optimizeRoute = async (deliveries: Delivery[], startLocation: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return withRetry(async () => {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Optimiza esta ruta. Inicio: ${startLocation}. Paradas: ${JSON.stringify(deliveries.map(d => ({id: d.id, addr: d.address})))}. Devuelve solo JSON: {"order": ["id1", "id2"]}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              order: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["order"]
          }
        }
      });

      const result = JSON.parse(response.text);
      return result.order as string[];
    } catch (e) {
      console.error("Error en optimización:", e);
      return deliveries.map(d => d.id);
    }
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, Map as MapIcon, List, BrainCircuit, Loader2, X, Navigation, LayoutGrid, LogOut, CheckCircle2, ArrowDownLeft, ArrowUpRight, Clock, AlertTriangle, Truck, Phone, RotateCcw, Settings2, BarChart3, Package, Archive, Mic, MapPin, Power, RefreshCcw, User } from 'lucide-react';
