                  <div className="flex flex-col items-center">
                    <Loader2 className="animate-spin" size={24} />
                    <span className="text-[10px] mt-1 font-bold whitespace-nowrap overflow-hidden text-ellipsis max-w-full">{parsingMessage}</span>
